const lazyEngines = {}; // مخزن المحركات المؤجلة

function loadEngineOnDemand(engineFile) {
    if (!lazyEngines[engineFile]) {
        console.log(`⚡ [LAZY LOAD] تحميل ${engineFile}...`);
        try {
            lazyEngines[engineFile] = require(`./lib/${engineFile}`);
            console.log(`✅ [LAZY] ${engineFile} — محمّل بنجاح`);
        } catch (e) {
            console.log(`⚠️ [LAZY] ${engineFile} — فشل التحميل:`, e.message);
            lazyEngines[engineFile] = null;
        }
    }
    return lazyEngines[engineFile];
}

function isEngineCritical(engineFile) {
    return CRITICAL_ENGINES_L0.includes(engineFile);
}

