// ═══════════════════════════════════════════════════════════════════════════════
// 📅 نظام التاريخ الهجري - Hijri Date System (الأساس)
// ═══════════════════════════════════════════════════════════════════════════════

const HIJRI_MONTHS = [
    { name: 'محرم', nameEn: 'Muharram', days: 30 },
    { name: 'صفر', nameEn: 'Safar', days: 29 },
    { name: 'ربيع الأول', nameEn: 'Rabi al-Awwal', days: 30 },
    { name: 'ربيع الثاني', nameEn: 'Rabi al-Thani', days: 29 },
    { name: 'جمادى الأولى', nameEn: 'Jumada al-Awwal', days: 30 },
    { name: 'جمادى الآخرة', nameEn: 'Jumada al-Thani', days: 29 },
    { name: 'رجب', nameEn: 'Rajab', days: 30 },
    { name: 'شعبان', nameEn: 'Shaban', days: 29 },
    { name: 'رمضان', nameEn: 'Ramadan', days: 30 },
    { name: 'شوال', nameEn: 'Shawwal', days: 29 },
    { name: 'ذو القعدة', nameEn: 'Dhu al-Qadah', days: 30 },
    { name: 'ذو الحجة', nameEn: 'Dhu al-Hijjah', days: 29 } // 30 في السنة الكبيسة
];

const HIJRI_DAYS = [
    { name: 'الأحد', nameEn: 'Sunday', shortName: 'أحد' },
    { name: 'الاثنين', nameEn: 'Monday', shortName: 'اثنين' },
    { name: 'الثلاثاء', nameEn: 'Tuesday', shortName: 'ثلاثاء' },
    { name: 'الأربعاء', nameEn: 'Wednesday', shortName: 'أربعاء' },
    { name: 'الخميس', nameEn: 'Thursday', shortName: 'خميس' },
    { name: 'الجمعة', nameEn: 'Friday', shortName: 'جمعة', blessed: true },
    { name: 'السبت', nameEn: 'Saturday', shortName: 'سبت' }
];

// تحويل من ميلادي إلى هجري (خوارزمية أم القرى)
function gregorianToHijri(gYear, gMonth, gDay) {
    const jd = gregorianToJulian(gYear, gMonth, gDay);
    return julianToHijri(jd);
}

function gregorianToJulian(year, month, day) {
    if (month <= 2) {
        year -= 1;
        month += 12;
    }
    const A = Math.floor(year / 100);
    const B = 2 - A + Math.floor(A / 4);
    return (
        Math.floor(365.25 * (year + 4716)) + Math.floor(30.6001 * (month + 1)) + day + B - 1524.5
    );
}

function julianToHijri(jd) {
    const l = Math.floor(jd) - 1948440 + 10632;
    const n = Math.floor((l - 1) / 10631);
    const l2 = l - 10631 * n + 354;
    const j =
        Math.floor((10985 - l2) / 5316) * Math.floor((50 * l2) / 17719) +
        Math.floor(l2 / 5670) * Math.floor((43 * l2) / 15238);
    const l3 =
        l2 -
        Math.floor((30 - j) / 15) * Math.floor((17719 * j) / 50) -
        Math.floor(j / 16) * Math.floor((15238 * j) / 43) +
        29;
    const month = Math.floor((24 * l3) / 709);
    const day = l3 - Math.floor((709 * month) / 24);
    const year = 30 * n + j - 30;

    return { year, month, day };
}

// تحويل من هجري إلى ميلادي
function hijriToGregorian(hYear, hMonth, hDay) {
    const jd = hijriToJulian(hYear, hMonth, hDay);
    return julianToGregorian(jd);
}

function hijriToJulian(year, month, day) {
    return (
        Math.floor((11 * year + 3) / 30) +
        354 * year +
        30 * month -
        Math.floor((month - 1) / 2) +
        day +
        1948440 -
        385
    );
}

function julianToGregorian(jd) {
    const z = Math.floor(jd + 0.5);
    const a = Math.floor((z - 1867216.25) / 36524.25);
    const aa = z + 1 + a - Math.floor(a / 4);
    const b = aa + 1524;
    const c = Math.floor((b - 122.1) / 365.25);
    const d = Math.floor(365.25 * c);
    const e = Math.floor((b - d) / 30.6001);
    const day = b - d - Math.floor(30.6001 * e);
    const month = e < 14 ? e - 1 : e - 13;
    const year = month > 2 ? c - 4716 : c - 4715;

    return { year, month, day };
}

// الحصول على التاريخ الهجري الحالي
function getCurrentHijriDate() {
    const now = new Date();
    const hijri = gregorianToHijri(now.getFullYear(), now.getMonth() + 1, now.getDate());
    const dayOfWeek = now.getDay();

    return {
        year: hijri.year,
        month: hijri.month,
        day: hijri.day,
        monthName: HIJRI_MONTHS[hijri.month - 1].name,
        monthNameEn: HIJRI_MONTHS[hijri.month - 1].nameEn,
        dayName: HIJRI_DAYS[dayOfWeek].name,
        dayNameEn: HIJRI_DAYS[dayOfWeek].nameEn,
        dayShort: HIJRI_DAYS[dayOfWeek].shortName,
        isBlessed: HIJRI_DAYS[dayOfWeek].blessed || false,
        formatted: `${hijri.day} ${HIJRI_MONTHS[hijri.month - 1].name} ${hijri.year} هـ`,
        formattedEn: `${hijri.day} ${HIJRI_MONTHS[hijri.month - 1].nameEn} ${hijri.year} AH`,
        gregorian: {
            year: now.getFullYear(),
            month: now.getMonth() + 1,
            day: now.getDate(),
            formatted: now.toLocaleDateString('ar-SA-u-ca-gregory')
        }
    };
}

// تنسيق التاريخ الهجري
function formatHijriDate(hijriYear, hijriMonth, hijriDay, format = 'full') {
    const monthInfo = HIJRI_MONTHS[hijriMonth - 1];

    switch (format) {
        case 'full':
            return `${hijriDay} ${monthInfo.name} ${hijriYear} هـ`;
        case 'short':
            return `${hijriDay}/${hijriMonth}/${hijriYear} هـ`;
        case 'numeric':
            return `${hijriYear}-${String(hijriMonth).padStart(2, '0')}-${String(hijriDay).padStart(2, '0')}`;
        case 'withDay':
            const greg = hijriToGregorian(hijriYear, hijriMonth, hijriDay);
            const date = new Date(greg.year, greg.month - 1, greg.day);
            const dayOfWeek = date.getDay();
            return `${HIJRI_DAYS[dayOfWeek].name} ${hijriDay} ${monthInfo.name} ${hijriYear} هـ`;
        default:
            return `${hijriDay} ${monthInfo.name} ${hijriYear} هـ`;
    }
}

// التحقق من الأيام المباركة والمناسبات الإسلامية
function getIslamicOccasions(hijriMonth, hijriDay) {
    const occasions = [];

    // محرم
    if (hijriMonth === 1) {
        if (hijriDay === 1) occasions.push({ name: 'رأس السنة الهجرية', type: 'new_year' });
        if (hijriDay === 10)
            occasions.push({ name: 'يوم عاشوراء', type: 'blessed', fasting: true });
    }

    // ربيع الأول
    if (hijriMonth === 3 && hijriDay === 12) {
        occasions.push({ name: 'المولد النبوي الشريف', type: 'blessed' });
    }

    // رجب
    if (hijriMonth === 7 && hijriDay === 27) {
        occasions.push({ name: 'ليلة الإسراء والمعراج', type: 'blessed' });
    }

    // شعبان
    if (hijriMonth === 8 && hijriDay === 15) {
        occasions.push({ name: 'ليلة النصف من شعبان', type: 'blessed' });
    }

    // رمضان
    if (hijriMonth === 9) {
        occasions.push({ name: 'شهر رمضان المبارك', type: 'ramadan', fasting: true });
        if (hijriDay >= 21 && hijriDay <= 29 && hijriDay % 2 === 1) {
            occasions.push({ name: 'ليالي القدر المحتملة', type: 'laylat_qadr' });
        }
    }

    // شوال
    if (hijriMonth === 10 && hijriDay === 1) {
        occasions.push({ name: 'عيد الفطر المبارك', type: 'eid', holiday: true });
    }

    // ذو الحجة
    if (hijriMonth === 12) {
        if (hijriDay >= 1 && hijriDay <= 9)
            occasions.push({ name: 'أيام العشر المباركة', type: 'blessed' });
        if (hijriDay === 9) occasions.push({ name: 'يوم عرفة', type: 'arafah', fasting: true });
        if (hijriDay === 10)
            occasions.push({ name: 'عيد الأضحى المبارك', type: 'eid', holiday: true });
        if (hijriDay >= 11 && hijriDay <= 13)
            occasions.push({ name: 'أيام التشريق', type: 'tashreeq' });
    }

    return occasions;
}

