// 🕌 أوقات الصلاة والتوقف عن المعاملات - Prayer Times & Trading Pause
// ═══════════════════════════════════════════════════════════════════════════════

const PRAYER_TIMES_SETTINGS = {
    enabled: true,
    pauseDuringJumuah: true,
    jumuahPauseStart: '12:00', // قبل صلاة الجمعة
    jumuahPauseEnd: '14:00', // بعد صلاة الجمعة
    reminderBeforePrayer: 15, // تذكير قبل الصلاة بـ 15 دقيقة
    location: {
        city: 'الخبر',
        country: 'المملكة العربية السعودية',
        timezone: 'Asia/Riyadh',
        latitude: 26.2172,
        longitude: 50.1971
    }
};

// تقريب أوقات الصلاة (سيتم استخدام API حقيقي في الإنتاج)
function getApproximatePrayerTimes() {
    const now = new Date();
    const month = now.getMonth() + 1;

    // أوقات تقريبية للخبر (تختلف حسب الموسم)
    const times = {
        fajr: month >= 4 && month <= 9 ? '03:45' : '05:00',
        sunrise: month >= 4 && month <= 9 ? '05:15' : '06:30',
        dhuhr: '12:00',
        asr: month >= 4 && month <= 9 ? '15:30' : '15:00',
        maghrib: month >= 4 && month <= 9 ? '18:30' : '17:30',
        isha: month >= 4 && month <= 9 ? '20:00' : '19:00'
    };

    return {
        ...times,
        date: getCurrentHijriDate(),
        location: PRAYER_TIMES_SETTINGS.location.city
    };
}

// التحقق من وقت صلاة الجمعة
function isJumuahTime() {
    const now = new Date();
    if (now.getDay() !== 5) return false; // ليس يوم الجمعة

    const hours = now.getHours();
    const minutes = now.getMinutes();
    const currentTime = hours * 60 + minutes;

    const [startH, startM] = PRAYER_TIMES_SETTINGS.jumuahPauseStart.split(':').map(Number);
    const [endH, endM] = PRAYER_TIMES_SETTINGS.jumuahPauseEnd.split(':').map(Number);

    const startTime = startH * 60 + startM;
    const endTime = endH * 60 + endM;

    return currentTime >= startTime && currentTime <= endTime;
}

// ═══════════════════════════════════════════════════════════════════════════════
// 💰 نظام الزكاة - Zakat System
// ═══════════════════════════════════════════════════════════════════════════════

const ZAKAT_CONFIG = {
    nisab: {
        gold: { grams: 85, description: 'نصاب الذهب: 85 جرام من الذهب الخالص' },
        silver: { grams: 595, description: 'نصاب الفضة: 595 جرام من الفضة الخالصة' }
    },
    rate: 0.025, // 2.5%
    hawl: 354, // سنة هجرية بالأيام
    categories: [
        'الفقراء',
        'المساكين',
        'العاملون عليها',
        'المؤلفة قلوبهم',
        'في الرقاب',
        'الغارمون',
        'في سبيل الله',
        'ابن السبيل'
    ]
};

function calculateZakat(amount, goldPricePerGram = 250) {
    const nisabValue = ZAKAT_CONFIG.nisab.gold.grams * goldPricePerGram;

    if (amount < nisabValue) {
        return {
            required: false,
            reason: 'المبلغ أقل من النصاب',
            nisabValue,
            amount
        };
    }

    const zakatAmount = amount * ZAKAT_CONFIG.rate;

    return {
        required: true,
        amount,
        nisabValue,
        zakatAmount,
        rate: '2.5%',
        categories: ZAKAT_CONFIG.categories,
        reminder: 'قال تعالى: وَأَقِيمُوا الصَّلَاةَ وَآتُوا الزَّكَاةَ'
    };
}

