function verifyTokenRole(req) {
    try {
        const authHeader = req.headers.authorization;
        const token = authHeader ? authHeader.replace('Bearer ', '') : null;
        // أيضاً من الكوكيز
        const cookieToken = req.cookies ? req.cookies.sheikha_token : null;
        const activeToken = token || cookieToken;
        if (!activeToken) return null;
        const decoded = jwt.verify(activeToken, process.env.JWT_SECRET || 'sheikha-secret-2026');
        return decoded;
    } catch (e) {
        return null;
    }
}

// Middleware لحماية الصفحات (HTML)
const IS_LOCAL = !process.env.NODE_ENV || process.env.NODE_ENV !== 'production';
app.use((req, res, next) => {
    const path = decodeURIComponent(req.path);

    // فحص إن كانت صفحة إدارية
    const isAdminPage =
        ADMIN_ONLY_PAGES.includes(path) || ADMIN_PREFIXES.some(p => path.startsWith(p));

    if (isAdminPage) {
        // في وضع PILOT / التطوير المحلي — السماح بالوصول للمالك
        if (IS_LOCAL) {
            return next();
        }
        const user = verifyTokenRole(req);
        if (!user || user.role !== 'admin') {
            return res.redirect('/');
        }
    }

    next();
});

console.log(
    '🔐 نظام حماية المسارات — مفعّل | ' +
        ADMIN_ONLY_PAGES.length +
        ' صفحة محمية | ' +
        ADMIN_PREFIXES.length +
        ' مسار إداري'
);

// === نهاية middleware الأمان ===
// تم استبدال Rate Limiting القديم بـ express-rate-limit أعلاه
const rateLimitMap = new Map(); // يبقى للتوافقية مع أي كود يستخدمه

// تنظيف rate limit map كل 5 دقائق
setInterval(() => {
    const now = Date.now();
    for (const [ip, timestamps] of rateLimitMap.entries()) {
        const valid = timestamps.filter(t => now - t < 60000);
        if (valid.length === 0) rateLimitMap.delete(ip);
        else rateLimitMap.set(ip, valid);
    }
}, 300000);

// ═══════════════════════════════════════════════════════════════════════════════
