// 🏛️ التسجيل الحكومي — Government Registration System
// ═══════════════════════════════════════════════════════════════════════════════

// سجل الجهات الحكومية المسجلة
const GOV_REGISTRY_PATH = path.join(__dirname, 'data', 'government-registry.json');
let GOV_REGISTRY = { entities: [], employees: [] };
try {
    if (fs.existsSync(GOV_REGISTRY_PATH)) {
        GOV_REGISTRY = JSON.parse(fs.readFileSync(GOV_REGISTRY_PATH, 'utf8'));
    }
} catch (_) {}

// تسجيل جهة حكومية أو موظف
app.post('/api/government/register', express.json(), (req, res) => {
    try {
        const data = req.body;
        const refCode = 'GOV-2026-' + Math.random().toString(36).substring(2, 7).toUpperCase();

        const entry = {
            refCode,
            type: data.type,
            purposes: data.purposes || [],
            role: data.role || null,
            status: 'pending_review',
            submittedAt: new Date().toISOString(),
            reviewedAt: null,
            data: data
        };

        if (data.type === 'employee') {
            GOV_REGISTRY.employees.push(entry);
        } else {
            GOV_REGISTRY.entities.push(entry);
        }

        // حفظ السجل
        try {
            fs.writeFileSync(GOV_REGISTRY_PATH, JSON.stringify(GOV_REGISTRY, null, 2), 'utf8');
        } catch (_) {}

        res.json({
            success: true,
            message: 'تم تقديم طلب التسجيل الحكومي بنجاح — سيتم المراجعة خلال 24-48 ساعة',
            refCode,
            status: 'pending_review'
        });
    } catch (err) {
        res.status(500).json({ success: false, message: 'خطأ في معالجة الطلب' });
    }
});

// استعلام عن حالة تسجيل حكومي
app.get('/api/government/status/:refCode', (req, res) => {
    const ref = req.params.refCode;
    const entity = GOV_REGISTRY.entities.find(e => e.refCode === ref);
    const employee = GOV_REGISTRY.employees.find(e => e.refCode === ref);
    const entry = entity || employee;

    if (!entry) {
        return res.status(404).json({ success: false, message: 'الرقم المرجعي غير موجود' });
    }

    res.json({
        success: true,
        refCode: entry.refCode,
        type: entry.type,
        status: entry.status,
        submittedAt: entry.submittedAt,
        reviewedAt: entry.reviewedAt
    });
});

// قائمة الجهات الحكومية المسجلة (للأدمن)
app.get('/api/government/entities', (req, res) => {
    res.json({
        success: true,
        total: GOV_REGISTRY.entities.length + GOV_REGISTRY.employees.length,
        entities: GOV_REGISTRY.entities.length,
        employees: GOV_REGISTRY.employees.length,
        data: GOV_REGISTRY
    });
});

