function getNavigatorBenchmarkData() {
    const filePath = path.join(__dirname, 'data', 'sheikha-navigator-benchmark.json');
    try {
        return JSON.parse(fs.readFileSync(filePath, 'utf8'));
    } catch (_) {
        return {
            version: '1.0.0',
            updatedAt: new Date().toISOString(),
            sourceNote: 'بيانات معيارية تعليمية قابلة للتغيّر',
            foundation: { tawhid: 'كل التمكين والرزق من الله وحده', reference: ['الكتاب والسنة'] },
            benchmarkCards: { companies: [], people: [] },
            navigatorStrengtheningPlan: { phases: [], ethicsGuardrails: [] }
        };
    }
}

app.get('/api/navigator/benchmark/cards', (req, res) => {
    const benchmark = getNavigatorBenchmarkData();
    const type = String(req.query.type || 'all').toLowerCase();
    const companies =
        benchmark.benchmarkCards && Array.isArray(benchmark.benchmarkCards.companies)
            ? benchmark.benchmarkCards.companies
            : [];
    const people =
        benchmark.benchmarkCards && Array.isArray(benchmark.benchmarkCards.people)
            ? benchmark.benchmarkCards.people
            : [];
    let cards = { companies, people };
    if (type === 'companies') cards = { companies, people: [] };
    if (type === 'people') cards = { companies: [], people };
    res.json({
        success: true,
        data: { sourceNote: benchmark.sourceNote, foundation: benchmark.foundation, cards },
        message: 'تم جلب بطاقات Navigator التعريفية',
        timestamp: new Date().toISOString()
    });
});

