// ═══════════════════════════════════════════════════════════════════════════════
// 🛡️ SAFE ACTIVATION PROTOCOL APIs — تفعيل بلا ضرر ولا ضرار
// ═══════════════════════════════════════════════════════════════════════════════
function getSafeActivationProtocol() {
    const filePath = path.join(__dirname, 'data', 'sheikha-safe-activation.json');
    try {
        return JSON.parse(fs.readFileSync(filePath, 'utf8'));
    } catch (_) {
        return {
            version: '1.0.0',
            title: 'بروتوكول التفعيل بلا ضرر ولا ضرار',
            foundation: { principle: 'لا ضرر ولا ضرار', reference: ['الكتاب والسنة'] },
            activationPhases: [],
            hardGuards: { deny: [], allow: [] },
            kpis: []
        };
    }
}

function runSafeActivationAssessment(inputText) {
    const text = String(inputText || '').toLowerCase();
    const denyPatterns = [
        'all servers',
        'every server',
        'global servers',
        'all computers',
        'control all',
        'hack',
        'exploit',
        'malware',
        'ransomware',
        'كل سيرفر',
        'كل السيرفرات',
        'كل حاسب',
        'اختراق',
        'تهكير',
        'تدمير',
        'تعطيل'
    ];
    const warnPatterns = [
        'root access',
        'admin everywhere',
        'full world',
        'وصول كامل',
        'صلاحيات مطلقة',
        'بدون حدود'
    ];

    const denyHits = denyPatterns.filter(p => text.includes(p));
    const warnHits = warnPatterns.filter(p => text.includes(p));
    const riskLevel = denyHits.length > 0 ? 'high' : warnHits.length > 0 ? 'medium' : 'low';

    return {
        allow: riskLevel === 'low',
        riskLevel,
        findings: { denyHits, warnHits },
        recommendations: [
            'قصر التفعيل على الأصول المصرح بها فقط',
            'استخدام تفعيل تدريجي (Pilot ثم توسع)',
            'تسجيل كل خطوة في سجل تدقيق',
            'تفعيل محرك الإصلاح المستمر للمحتوى المخالف'
        ]
    };
}

function sanitizeActivationIntent(inputText) {
    let text = String(inputText || '');
    const replacements = [
        { from: /كل\s*سيرفرات\s*العالم/gi, to: 'الخوادم المصرح بها فقط' },
        { from: /كل\s*حاسب/gi, to: 'الأجهزة المملوكة أو المفوضة' },
        { from: /اختراق|تهكير/gi, to: 'تدقيق أمني نظامي' },
        { from: /صلاحيات\s*مطلقة/gi, to: 'صلاحيات مقيدة ومراقبة' }
    ];
    replacements.forEach(r => {
        text = text.replace(r.from, r.to);
    });
    return text;
}

app.get('/api/activation/safe/protocol', (req, res) => {
    const protocol = getSafeActivationProtocol();
    res.json({
        success: true,
        data: protocol,
        message: 'تم جلب بروتوكول التفعيل الآمن',
        timestamp: new Date().toISOString()
    });
});

app.post('/api/activation/safe/assess', express.json(), (req, res) => {
    const intent = req.body && req.body.intent ? req.body.intent : '';
    if (!intent) {
        return res
            .status(400)
            .json({
                success: false,
                data: {},
                message: 'حقل intent مطلوب للتقييم',
                timestamp: new Date().toISOString()
            });
    }
    const assessment = runSafeActivationAssessment(intent);
    res.json({
        success: true,
        data: assessment,
        message: 'تم تقييم طلب التفعيل بنجاح',
        timestamp: new Date().toISOString()
    });
});

app.post('/api/activation/safe/correct', express.json(), (req, res) => {
    const intent = req.body && req.body.intent ? req.body.intent : '';
    if (!intent) {
        return res
            .status(400)
            .json({
                success: false,
                data: {},
                message: 'حقل intent مطلوب للتصحيح',
                timestamp: new Date().toISOString()
            });
    }
    const corrected = sanitizeActivationIntent(intent);
    const assessment = runSafeActivationAssessment(corrected);
    res.json({
        success: true,
        data: { original: intent, corrected, assessment },
        message: 'تم تصحيح نص التفعيل وفق مبدأ لا ضرر ولا ضرار',
        timestamp: new Date().toISOString()
    });
});

app.get('/api/activation/safe/one-engine-plan', (req, res) => {
    const protocol = getSafeActivationProtocol();
    const plan = {
        objective: 'الاستفادة من محركات جاهزة وتسريع التقدم العلمي بمحرك موحّد',
        mode: 'federated-one-engine',
        steps: [
            'تسجيل المحركات الجاهزة المصرح بها في سجل موحد',
            'إضافة طبقة تنسيق موحدة (Orchestrator) بدل توليد محركات جديدة',
            'توجيه الطلبات حسب التخصص: بحث، تحليل، تشغيل، مراقبة',
            'تمرير المخرجات على محرك إصلاحي شرعي/أمني قبل الاعتماد',
            'قياس الأداء والتحسين الدوري'
        ],
        constraints: protocol.hardGuards || {}
    };
    res.json({
        success: true,
        data: plan,
        message: 'خطة المحرك الموحد الجاهز تم توليدها',
        timestamp: new Date().toISOString()
    });
});
function getKhairBenefitState() {
    const statePath = path.join(__dirname, 'data', 'sheikha-safe-activation-state.json');
    const protocol = getSafeActivationProtocol();
    const defaults = ((protocol || {}).khairBenefitMode || {}).defaults || {};
    const fallback = {
        enabled: !!defaults.enabled,
        ownerName: defaults.ownerName || '',
        scope: defaults.scope || 'owned-or-delegated-assets-only',
        repairEngine: defaults.repairEngine !== false,
        shariaGate: defaults.shariaGate !== false,
        securityGate: defaults.securityGate !== false,
        autoCorrection: defaults.autoCorrection !== false,
        lastUpdatedAt: new Date().toISOString(),
        lastUpdatedBy: 'system'
    };

    try {
        const loaded = JSON.parse(fs.readFileSync(statePath, 'utf8'));
        return { statePath, state: { ...fallback, ...loaded } };
    } catch (_) {
        return { statePath, state: fallback };
    }
}

function saveKhairBenefitState(statePath, state) {
    try {
        fs.writeFileSync(statePath, JSON.stringify(state, null, 4) + '\n', 'utf8');
        return true;
    } catch (_) {
        return false;
    }
}

app.get('/api/activation/safe/khair-mode', (req, res) => {
    const protocol = getSafeActivationProtocol();
    const { state } = getKhairBenefitState();
    res.json({
        success: true,
        data: {
            profile: (protocol || {}).khairBenefitMode || {},
            state
        },
        message: 'تم جلب حالة وضع الخير والمنفعة',
        timestamp: new Date().toISOString()
    });
});

app.post('/api/activation/safe/khair-mode/enable', express.json(), (req, res) => {
    const ownerName = String((req.body && req.body.ownerName) || '').trim();
    if (!ownerName) {
        return res.status(400).json({
            success: false,
            data: {},
            message: 'ownerName مطلوب لتفعيل وضع الخير والمنفعة',
            timestamp: new Date().toISOString()
        });
    }

    const { statePath, state } = getKhairBenefitState();
    const nextState = {
        ...state,
        enabled: true,
        ownerName,
        lastUpdatedAt: new Date().toISOString(),
        lastUpdatedBy: ownerName
    };

    if (!saveKhairBenefitState(statePath, nextState)) {
        return res.status(500).json({
            success: false,
            data: {},
            message: 'تعذر حفظ حالة وضع الخير والمنفعة',
            timestamp: new Date().toISOString()
        });
    }

    res.json({
        success: true,
        data: nextState,
        message: 'تم تفعيل وضع الخير والمنفعة بنجاح',
        timestamp: new Date().toISOString()
    });
});

app.post('/api/activation/safe/khair-mode/disable', express.json(), (req, res) => {
    const actor = String((req.body && req.body.actor) || 'system').trim();
    const { statePath, state } = getKhairBenefitState();
    const nextState = {
        ...state,
        enabled: false,
        lastUpdatedAt: new Date().toISOString(),
        lastUpdatedBy: actor
    };

    if (!saveKhairBenefitState(statePath, nextState)) {
        return res.status(500).json({
            success: false,
            data: {},
            message: 'تعذر إيقاف وضع الخير والمنفعة',
            timestamp: new Date().toISOString()
        });
    }

    res.json({
        success: true,
        data: nextState,
        message: 'تم إيقاف وضع الخير والمنفعة',
        timestamp: new Date().toISOString()
    });
});

