app.post('/api/activation/ramadan/enable', express.json(), (req, res) => {
    const { ownerName, features } = req.body || {};
    if (!ownerName || !ownerName.trim())
        return res.status(400).json({ success: false, message: 'اسم المالك مطلوب' });
    let khairState = {};
    try {
        khairState = JSON.parse(
            fs.readFileSync(
                path.join(__dirname, 'data', 'sheikha-safe-activation-state.json'),
                'utf8'
            )
        );
    } catch (_) {}
    if (!khairState.enabled)
        return res
            .status(403)
            .json({ success: false, message: 'يجب تفعيل وضع الخير والمنفعة أولاً' });
    const newState = {
        active: true,
        startDate: '2026-03-01',
        endDate: '2026-03-30',
        features: Object.assign(
            {
                ramadanBanner: true,
                zakatCalculator: true,
                charityOffers: true,
                merchantExpansion: true,
                specialPricing: true
            },
            features || {}
        ),
        message: 'رمضان كريم — اللهم بارك لنا في تجارتنا',
        activatedBy: ownerName,
        updatedAt: new Date().toISOString()
    };
    try {
        fs.writeFileSync(RAMADAN_STATE_FILE, JSON.stringify(newState, null, 4), 'utf8');
    } catch (e) {
        return res.status(500).json({ success: false, message: 'تعذر حفظ حالة رمضان' });
    }
    res.json({
        success: true,
        data: newState,
        message: 'تم تفعيل وضع رمضان المبارك — اللهم تقبل',
        quran: '﴿ شَهْرُ رَمَضَانَ الَّذِي أُنزِلَ فِيهِ الْقُرْآنُ هُدًى لِّلنَّاسِ ﴾',
        timestamp: new Date().toISOString()
    });
});
