// ═══ SAUDIWIKI DIGITIZATION CENTER — رقمنة سعودي ويكي بلا ضرر ولا ضرار ═══
const SAUDIWIKI_STATE_FILE = path.join(
    __dirname,
    'data',
    'covenants',
    'saudiwiki-digitization-state.json'
);
const SAUDIWIKI_LEDGER_FILE = path.join(__dirname, 'data', 'covenants', 'saudiwiki-ledger.ndjson');

function getSaudiWikiState() {
    const fallback = {
        version: '1.0.0',
        owner: 'سلمان أحمد بن سلمان الراجح',
        mode: 'no-harm-digitization',
        active: true,
        scope: 'authorized-assets-only',
        copyrightPolicy: {
            allowMetadata: true,
            allowVerifiedSummaries: true,
            forbidFullTextCopy: true,
            requireSourceUrl: true
        },
        domains: {
            treaties: { enabled: true, count: 0 },
            history: { enabled: true, count: 0 },
            culture: { enabled: true, count: 0 },
            civilization: { enabled: true, count: 0 }
        },
        updatedAt: new Date().toISOString()
    };
    return readJsonSafe(SAUDIWIKI_STATE_FILE, fallback);
}

function saveSaudiWikiState(state) {
    return writeJsonSafe(SAUDIWIKI_STATE_FILE, { ...state, updatedAt: new Date().toISOString() });
}

function appendSaudiWikiLedger(entry) {
    try {
        fs.appendFileSync(SAUDIWIKI_LEDGER_FILE, JSON.stringify(entry) + '\\n', 'utf8');
        return true;
    } catch (_) {
        return false;
    }
}

app.get('/api/saudiwiki/digitization/status', (req, res) => {
    const state = getSaudiWikiState();
    const legalTreatiesCount = legalEngine
        ? Object.values(legalEngine.treaties || {}).reduce(
              (s, arr) => s + (Array.isArray(arr) ? arr.length : 0),
              0
          )
        : 0;
    res.json({
        success: true,
        data: {
            state,
            coverage: {
                treaties: legalTreatiesCount,
                historyEngineReady: !!historicalEngine,
                cultureSources: 1,
                civilizationSources: 1
            },
            noHarmGuard: 'مفعل — لا نسخ نصوص كاملة محمية — تلخيص موثق فقط'
        },
        message: 'حالة رقمنة سعودي ويكي',
        timestamp: new Date().toISOString()
    });
});

app.post('/api/saudiwiki/digitization/activate', express.json(), (req, res) => {
    const ownerName = String((req.body && req.body.ownerName) || '').trim();
    const active = req.body && typeof req.body.active === 'boolean' ? req.body.active : true;
    const actor = ownerName || 'system';
    const state = getSaudiWikiState();
    const next = { ...state, active, activatedBy: actor };

    if (!saveSaudiWikiState(next)) {
        return res
            .status(500)
            .json({
                success: false,
                data: {},
                message: 'تعذر حفظ حالة رقمنة سعودي ويكي',
                timestamp: new Date().toISOString()
            });
    }

    appendSaudiWikiLedger({
        id: 'SW-ACT-' + Date.now().toString(36).toUpperCase(),
        type: 'activation',
        active,
        actor,
        at: new Date().toISOString()
    });
    res.json({
        success: true,
        data: next,
        message: active ? 'تم تفعيل رقمنة سعودي ويكي' : 'تم إيقاف رقمنة سعودي ويكي',
        timestamp: new Date().toISOString()
    });
});

app.post('/api/saudiwiki/digitization/ingest-metadata', express.json(), (req, res) => {
    const category = String((req.body && req.body.category) || '')
        .trim()
        .toLowerCase();
    const title = String((req.body && req.body.title) || '').trim();
    const sourceUrl = String((req.body && req.body.sourceUrl) || '').trim();
    const summary = String((req.body && req.body.summary) || '').trim();
    const fullText = String((req.body && req.body.fullText) || '').trim();
    const actor = String((req.body && req.body.actor) || 'system').trim();

    const allowedCategories = ['treaties', 'history', 'culture', 'civilization'];
    if (!allowedCategories.includes(category) || !title || !sourceUrl || !summary) {
        return res
            .status(400)
            .json({
                success: false,
                data: {},
                message: 'category/title/sourceUrl/summary مطلوبة وبفئات محددة',
                timestamp: new Date().toISOString()
            });
    }
    if (fullText.length > 0) {
        return res
            .status(400)
            .json({
                success: false,
                data: {},
                message: 'غير مسموح إدخال نص كامل محمي — استخدم ملخصًا موثقًا فقط',
                timestamp: new Date().toISOString()
            });
    }
    if (summary.length > 4000) {
        return res
            .status(400)
            .json({
                success: false,
                data: {},
                message: 'الملخص طويل جدًا — الحد الأقصى 4000 حرف',
                timestamp: new Date().toISOString()
            });
    }

    const state = getSaudiWikiState();
    if (!state.active) {
        return res
            .status(403)
            .json({
                success: false,
                data: {},
                message: 'رقمنة سعودي ويكي غير مفعلة',
                timestamp: new Date().toISOString()
            });
    }

    const entry = {
        id: 'SW-' + Date.now().toString(36).toUpperCase(),
        type: 'metadata-ingest',
        category,
        title,
        sourceUrl,
        summary,
        actor,
        at: new Date().toISOString(),
        compliance: { noHarm: true, noFullTextCopy: true, sourceRequired: true }
    };

    if (!appendSaudiWikiLedger(entry)) {
        return res
            .status(500)
            .json({
                success: false,
                data: {},
                message: 'تعذر تسجيل إدخال سعودي ويكي',
                timestamp: new Date().toISOString()
            });
    }

    const next = {
        ...state,
        domains: {
            ...state.domains,
            [category]: {
                ...(state.domains && state.domains[category]
                    ? state.domains[category]
                    : { enabled: true, count: 0 }),
                enabled: true,
                count:
                    Number(
                        (state.domains &&
                            state.domains[category] &&
                            state.domains[category].count) ||
                            0
                    ) + 1
            }
        }
    };
    saveSaudiWikiState(next);

    res.json({
        success: true,
        data: entry,
        message: 'تمت رقمنة المعلومة الوصفية بنجاح',
        timestamp: new Date().toISOString()
    });
});

app.get('/api/saudiwiki/digitization/ledger', (req, res) => {
    let lines = [];
    try {
        const raw = fs.readFileSync(SAUDIWIKI_LEDGER_FILE, 'utf8');
        lines = raw.split('\\n').filter(Boolean).slice(-300);
    } catch (_) {}
    const entries = lines
        .map(l => {
            try {
                return JSON.parse(l);
            } catch (_) {
                return null;
            }
        })
        .filter(Boolean)
        .reverse();
    res.json({
        success: true,
        data: { totalReturned: entries.length, entries },
        message: 'تم جلب سجل رقمنة سعودي ويكي',
        timestamp: new Date().toISOString()
    });
});

app.get('/api/saudiwiki/digitization/realtime', (req, res) => {
    const state = getSaudiWikiState();
    const sync = getSyncCenterState();
    const pulse = {
        now: new Date().toISOString(),
        serverUptimeSeconds: Math.floor(process.uptime()),
        khairMode: getKhairBenefitState().state.enabled,
        ramadanMode: getRamadanState().active,
        pilotMode: pilotEngine ? pilotEngine.mode : 'UNKNOWN',
        syncStatus: sync.realtime && sync.realtime.status ? sync.realtime.status : 'unknown'
    };
    res.json({
        success: true,
        data: { state, pulse, roadmap: sync.timeline || { now: [], next: [], futureVision: [] } },
        message: 'النبض اللحظي لرقمنة سعودي ويكي',
        timestamp: new Date().toISOString()
    });
});

// ═══ METALS & SCRAP ENCYCLOPEDIA ENGINE — موسوعة المعادن والسكراب ═══
const METALS_KNOWLEDGE_DIR = path.join(__dirname, 'data', 'metals-knowledge');
const METALS_ENCYCLOPEDIA_FILE = path.join(METALS_KNOWLEDGE_DIR, 'encyclopedia.json');
const METALS_ENCYCLOPEDIA_LEDGER = path.join(METALS_KNOWLEDGE_DIR, 'encyclopedia-ledger.ndjson');
if (!fs.existsSync(METALS_KNOWLEDGE_DIR)) fs.mkdirSync(METALS_KNOWLEDGE_DIR, { recursive: true });
if (!fs.existsSync(METALS_ENCYCLOPEDIA_LEDGER))
    fs.writeFileSync(METALS_ENCYCLOPEDIA_LEDGER, '', 'utf8');

function mkReadJson(filePath, fallback) {
    try {
        return JSON.parse(fs.readFileSync(filePath, 'utf8'));
    } catch (_) {
        return fallback;
    }
}

function mkWriteJson(filePath, data) {
    try {
        fs.writeFileSync(filePath, JSON.stringify(data, null, 4) + '\\n', 'utf8');
        return true;
    } catch (_) {
        return false;
    }
}

function mkAppendLedger(entry) {
    try {
        fs.appendFileSync(METALS_ENCYCLOPEDIA_LEDGER, JSON.stringify(entry) + '\\n', 'utf8');
        return true;
    } catch (_) {
        return false;
    }
}

function getMetalsEncyclopedia() {
    const fallback = {
        version: '1.0.0',
        title: 'موسوعة المعادن والسكراب',
        owner: 'سلمان أحمد بن سلمان الراجح',
        policy: {
            noHarm: true,
            sourceRequired: true,
            note: 'أي معلومة بلا مصدر تُصنّف غير مكتملة'
        },
        updatedAt: new Date().toISOString(),
        metals: [],
        scrap: []
    };
    return mkReadJson(METALS_ENCYCLOPEDIA_FILE, fallback);
}

app.get('/api/metals/encyclopedia/dashboard', (req, res) => {
    const encyclopedia = getMetalsEncyclopedia();
    const metals = Array.isArray(encyclopedia.metals) ? encyclopedia.metals : [];
    const scrap = Array.isArray(encyclopedia.scrap) ? encyclopedia.scrap : [];
    const withSources = [...metals, ...scrap].filter(
        x => Array.isArray(x.sources) && x.sources.length > 0
    ).length;

    res.json({
        success: true,
        data: {
            title: encyclopedia.title,
            version: encyclopedia.version,
            metalsCount: metals.length,
            scrapCount: scrap.length,
            totalEntries: metals.length + scrap.length,
            sourcedEntries: withSources,
            sourceCoveragePercent:
                metals.length + scrap.length > 0
                    ? Math.round((withSources / (metals.length + scrap.length)) * 100)
                    : 0,
            noHarm: encyclopedia.policy || {}
        },
        message: 'لوحة موسوعة المعادن والسكراب',
        timestamp: new Date().toISOString()
    });
});

app.get('/api/metals/encyclopedia/metals', (req, res) => {
    const encyclopedia = getMetalsEncyclopedia();
    const q = String(req.query.q || '')
        .trim()
        .toLowerCase();
    const items = (encyclopedia.metals || []).filter(m => {
        if (!q) return true;
        return (
            String(m.nameAr || '')
                .toLowerCase()
                .includes(q) ||
            String(m.nameEn || '')
                .toLowerCase()
                .includes(q) ||
            String(m.symbol || '')
                .toLowerCase()
                .includes(q)
        );
    });

    res.json({
        success: true,
        data: items,
        message: 'بيانات المعادن',
        timestamp: new Date().toISOString()
    });
});

app.get('/api/metals/encyclopedia/scrap', (req, res) => {
    const encyclopedia = getMetalsEncyclopedia();
    const q = String(req.query.q || '')
        .trim()
        .toLowerCase();
    const items = (encyclopedia.scrap || []).filter(m => {
        if (!q) return true;
        return (
            String(m.nameAr || '')
                .toLowerCase()
                .includes(q) ||
            String(m.nameEn || '')
                .toLowerCase()
                .includes(q) ||
            String(m.id || '')
                .toLowerCase()
                .includes(q)
        );
    });

    res.json({
        success: true,
        data: items,
        message: 'بيانات السكراب',
        timestamp: new Date().toISOString()
    });
});

app.get('/api/metals/encyclopedia/item/:id', (req, res) => {
    const encyclopedia = getMetalsEncyclopedia();
    const id = String(req.params.id || '').trim();
    const items = [...(encyclopedia.metals || []), ...(encyclopedia.scrap || [])];
    const item = items.find(x => String(x.id || '') === id);

    if (!item) {
        return res.status(404).json({
            success: false,
            data: {},
            message: 'العنصر غير موجود في الموسوعة',
            timestamp: new Date().toISOString()
        });
    }

    res.json({
        success: true,
        data: item,
        message: 'تفاصيل عنصر الموسوعة',
        timestamp: new Date().toISOString()
    });
});

app.get('/api/metals/encyclopedia/production/:country', (req, res) => {
    const encyclopedia = getMetalsEncyclopedia();
    const country = String(req.params.country || '')
        .trim()
        .toLowerCase();
    const metals = encyclopedia.metals || [];
    const rows = [];

    metals.forEach(m => {
        (m.productionByCountry || []).forEach(p => {
            const c = String(p.country || '').toLowerCase();
            if (c === country) {
                rows.push({
                    metalId: m.id,
                    metalNameAr: m.nameAr,
                    metalNameEn: m.nameEn,
                    symbol: m.symbol,
                    production: p,
                    sources: m.sources || []
                });
            }
        });
    });

    res.json({
        success: true,
        data: {
            country: req.params.country,
            rows,
            total: rows.length
        },
        message: 'إنتاج المعادن حسب الدولة',
        timestamp: new Date().toISOString()
    });
});

app.get('/api/metals/encyclopedia/sources', (req, res) => {
    const encyclopedia = getMetalsEncyclopedia();
    const all = [...(encyclopedia.metals || []), ...(encyclopedia.scrap || [])];
    const sourceMap = new Map();
    all.forEach(item => {
        (item.sources || []).forEach(s => {
            const key = (s.name || '') + '|' + (s.url || '');
            if (!sourceMap.has(key)) sourceMap.set(key, { ...s, refs: 0 });
            const cur = sourceMap.get(key);
            cur.refs += 1;
            sourceMap.set(key, cur);
        });
    });

    res.json({
        success: true,
        data: Array.from(sourceMap.values()),
        message: 'مصادر موسوعة المعادن والسكراب',
        timestamp: new Date().toISOString()
    });
});

app.post('/api/metals/encyclopedia/ingest', express.json(), (req, res) => {
    const category = String((req.body && req.body.category) || '')
        .trim()
        .toLowerCase();
    const item = req.body && req.body.item ? req.body.item : null;
    const actor = String((req.body && req.body.actor) || 'system').trim();

    if (!['metals', 'scrap'].includes(category) || !item || typeof item !== 'object') {
        return res
            .status(400)
            .json({
                success: false,
                data: {},
                message: 'category يجب أن تكون metals أو scrap مع item صالح',
                timestamp: new Date().toISOString()
            });
    }

    if (!item.id || !item.nameAr || !item.nameEn) {
        return res
            .status(400)
            .json({
                success: false,
                data: {},
                message: 'item.id و item.nameAr و item.nameEn مطلوبة',
                timestamp: new Date().toISOString()
            });
    }

    if (!Array.isArray(item.sources) || item.sources.length === 0) {
        return res
            .status(400)
            .json({
                success: false,
                data: {},
                message: 'كل عنصر يجب أن يحتوي على sources موثقة',
                timestamp: new Date().toISOString()
            });
    }

    if (item.fullText) {
        return res
            .status(400)
            .json({
                success: false,
                data: {},
                message: 'حظر إدخال نص كامل غير مرخص — يسمح بالبيانات الوصفية الموثقة فقط',
                timestamp: new Date().toISOString()
            });
    }

    const encyclopedia = getMetalsEncyclopedia();
    const list = Array.isArray(encyclopedia[category]) ? encyclopedia[category] : [];
    const exists = list.findIndex(x => String(x.id) === String(item.id));
    if (exists >= 0) list[exists] = item;
    else list.push(item);

    const next = {
        ...encyclopedia,
        [category]: list,
        updatedAt: new Date().toISOString()
    };

    if (!mkWriteJson(METALS_ENCYCLOPEDIA_FILE, next)) {
        return res
            .status(500)
            .json({
                success: false,
                data: {},
                message: 'تعذر حفظ عنصر الموسوعة',
                timestamp: new Date().toISOString()
            });
    }

    mkAppendLedger({
        id: 'ME-' + Date.now().toString(36).toUpperCase(),
        type: 'ingest',
        category,
        itemId: item.id,
        actor,
        at: new Date().toISOString()
    });

    res.json({
        success: true,
        data: { category, itemId: item.id, updated: exists >= 0 },
        message: 'تمت إضافة/تحديث عنصر في موسوعة المعادن والسكراب',
        timestamp: new Date().toISOString()
    });
});

