const ANALYTICS_DIR = path.join(__dirname, 'data', 'analytics');
const PAGE_VIEWS_FILE = path.join(ANALYTICS_DIR, 'page-views.json');
if (!fs.existsSync(ANALYTICS_DIR)) fs.mkdirSync(ANALYTICS_DIR, { recursive: true });
let PAGE_VIEWS = { total: 0, byPath: {}, lastUpdated: null };
try {
    const loaded = JSON.parse(fs.readFileSync(PAGE_VIEWS_FILE, 'utf8'));
    PAGE_VIEWS = {
        total: loaded.total || 0,
        byPath: loaded.byPath || {},
        lastUpdated: loaded.lastUpdated || null
    };
} catch (_) {}
function recordPageView(path) {
    const key = path || '/';
    PAGE_VIEWS.total++;
    PAGE_VIEWS.byPath[key] = (PAGE_VIEWS.byPath[key] || 0) + 1;
    PAGE_VIEWS.lastUpdated = new Date().toISOString();
}
function flushPageViews() {
    try {
        fs.writeFileSync(PAGE_VIEWS_FILE, JSON.stringify(PAGE_VIEWS, null, 2), 'utf8');
    } catch (_) {}
}
setInterval(flushPageViews, 10000);

// ═══ Page View Recording + Auto Script Injection ═══
// يحقن sheikha-app.js تلقائياً في كل صفحة HTML — نظام موحد شامل
// يعمل بقراءة الملف من الذاكرة المؤقتة (لا يعتمد على سرعة القرص/OneDrive)
const _htmlCache = new Map();
const INJECT_TAG = '<script src="/js/sheikha-app.js"></script>';

app.use((req, res, next) => {
    if (req.method === 'GET' && (req.path === '/' || req.path.endsWith('.html'))) {
        const p = req.path === '/' ? '/' : req.path;
        recordPageView(p);

        const fileName = p === '/' ? 'index.html' : decodeURIComponent(p).replace(/^\//, '');
        const filePath = path.join(__dirname, 'public', fileName);

        try {
            // استخدم الكاش أو اقرأ الملف
            let html = _htmlCache.get(filePath);
            if (!html) {
                if (fs.existsSync(filePath)) {
                    html = fs.readFileSync(filePath, 'utf-8');
                }
            }

            if (html) {
                // حقن السكربت الموحد إذا لم يكن موجوداً
                if (!html.includes('sheikha-app.js')) {
                    if (html.includes('<head>')) {
                        html = html.replace('<head>', '<head>\n' + INJECT_TAG);
                    } else if (html.includes('<HEAD>')) {
                        html = html.replace('<HEAD>', '<HEAD>\n' + INJECT_TAG);
                    } else {
                        html = INJECT_TAG + '\n' + html;
                    }
                }
                // كاش لمدة 60 ثانية (يتجدد تلقائياً)
                _htmlCache.set(filePath, html);
                setTimeout(() => _htmlCache.delete(filePath), 60000);

                res.set('Content-Type', 'text/html; charset=utf-8');
                res.set('Cache-Control', 'no-cache');
                return res.send(html);
            }
        } catch (e) {
            console.warn('⚠️ HTML injection error:', e.message);
        }
    }
    next();
});

