// ═══════════════════════════════════════════════════════════════════════════════
// ⚖️ نظام شيخة للتسعير العادل — Sheikha Fair Pricing System (SFPS)
// ═══════════════════════════════════════════════════════════════════════════════
// المبدأ الأساسي: "لا ضَرَرَ ولا ضِرار" — القاعدة الذهبية في التسعير
// ═══════════════════════════════════════════════════════════════════════════════

// الثوابت الأساسية — لا تتغير أبداً (Fixed Constants)
const SHEIKHA_PRICING_CONSTANTS = {
    // ثابت هامش الربح العادل (Fair Profit Margin - FPM)
    FPM: {
        baseMetals: 0.1, // المعادن الأساسية: 10%
        preciousMetals: 0.05, // المعادن الثمينة: 5%
        scrap: 0.12, // السكراب: 12%
        logistics: 0.15, // الخدمات اللوجستية: 15%
        services: 0.2 // الخدمات المضافة: 20%
    },
    // ثابت حماية المنتج (Producer Protection Factor - PPF)
    PPF: 1.05, // الحد الأدنى للربح: 5% فوق التكلفة
    // ثابت حماية المستهلك (Consumer Protection Factor - CPF)
    CPF: 1.25, // الحد الأقصى للزيادة: 25% فوق السعر المرجعي
    // الأساس الشرعي
    principles: {
        noHarm: 'لا ضرر ولا ضرار',
        fairTrade: 'تجارة عن تراض',
        noMonopoly: 'لا يحتكر إلا خاطئ',
        kindMerchant: 'رحم الله امرأً سمحاً إذا باع سمحاً إذا اشترى',
        justBalance: 'وأقيموا الوزن بالقسط ولا تخسروا الميزان'
    }
};

// المتغيرات اللحظية — تتغير يومياً (Dynamic Variables)
let SHEIKHA_DYNAMIC_VARIABLES = {
    // متغير العرض والطلب (Supply-Demand Variable - SDV)
    SDV: {
        iron: 1.02,
        copper: 1.05,
        aluminum: 1.0,
        gold: 0.98,
        silver: 1.03
    },
    // متغير الأسعار العالمية (Global Price Variable - GPV)
    GPV: {
        lmeImpact: 1.0, // تأثير بورصة لندن
        comexImpact: 1.0, // تأثير بورصة نيويورك
        shfeImpact: 1.0 // تأثير بورصة شنغهاي
    },
    // متغير الموسمية (Seasonality Variable - SV)
    SV: 1.0,
    // آخر تحديث
    lastUpdated: new Date().toISOString()
};

// تحديث المتغيرات اللحظية كل 15 دقيقة
cron.schedule('*/15 * * * *', () => {
    // تحديث العرض والطلب (محاكاة)
    Object.keys(SHEIKHA_DYNAMIC_VARIABLES.SDV).forEach(metal => {
        const change = (Math.random() - 0.5) * 0.1;
        let newValue = SHEIKHA_DYNAMIC_VARIABLES.SDV[metal] + change;
        // ضمان البقاء ضمن النطاق العادل (0.85 - 1.25)
        newValue = Math.max(0.85, Math.min(1.25, newValue));
        SHEIKHA_DYNAMIC_VARIABLES.SDV[metal] = Math.round(newValue * 100) / 100;
    });
    SHEIKHA_DYNAMIC_VARIABLES.lastUpdated = new Date().toISOString();
});

// دالة حساب السعر العادل
function calculateFairPrice(baseCost, category, metal = null) {
    const FPM = SHEIKHA_PRICING_CONSTANTS.FPM[category] || 0.1;
    const SDV = metal ? SHEIKHA_DYNAMIC_VARIABLES.SDV[metal] || 1.0 : 1.0;
    const GPV = SHEIKHA_DYNAMIC_VARIABLES.GPV.lmeImpact;
    const SV = SHEIKHA_DYNAMIC_VARIABLES.SV;

    let fairPrice = baseCost * (1 + FPM) * SDV * GPV * SV;

    // التحقق من حدود العدالة
    const minPrice = baseCost * SHEIKHA_PRICING_CONSTANTS.PPF; // حماية المنتج
    const maxPrice = baseCost * (1 + FPM) * SHEIKHA_PRICING_CONSTANTS.CPF; // حماية المستهلك

    fairPrice = Math.max(minPrice, Math.min(maxPrice, fairPrice));

    return Math.round(fairPrice * 100) / 100;
}

