// حساب تكلفة رحلة لوجستية كاملة
app.get('/api/logistics/calculate', (req, res) => {
    const weight = parseFloat(req.query.weight) || 20; // طن
    const origin = (req.query.origin || 'saudi').toLowerCase();
    const destination = (req.query.destination || 'india').toLowerCase();
    const transportType = (req.query.type || 'sea').toLowerCase();

    let totalCost = 0;
    let breakdown = [];

    // تكلفة التحميل
    breakdown.push({
        stage: 'التحميل بالمصنع',
        cost: LOGISTICS_PRICES.handling.loading.fairPrice * weight,
        unit: 'SAR'
    });
    totalCost += LOGISTICS_PRICES.handling.loading.fairPrice * weight;

    // النقل للميناء (افتراض 200 كم)
    const landCost =
        200 *
        weight *
        LOGISTICS_PRICES.land.mediumRange.pricePerTonKm *
        (1 + LOGISTICS_PRICES.land.mediumRange.profitMargin);
    breakdown.push({
        stage: 'النقل البري للميناء',
        cost: Math.round(landCost),
        unit: 'SAR'
    });
    totalCost += landCost;

    // رسوم الميناء
    breakdown.push({
        stage: 'رسوم الميناء',
        cost: LOGISTICS_PRICES.handling.portFees.fairPrice * weight,
        unit: 'SAR'
    });
    totalCost += LOGISTICS_PRICES.handling.portFees.fairPrice * weight;

    // التخليص الجمركي
    breakdown.push({
        stage: 'التخليص الجمركي',
        cost: LOGISTICS_PRICES.handling.customsClearance.fairPrice * weight,
        unit: 'SAR'
    });
    totalCost += LOGISTICS_PRICES.handling.customsClearance.fairPrice * weight;

    // الشحن البحري
    let seaCost = 0;
    if (destination === 'india') seaCost = LOGISTICS_PRICES.sea.gulfIndia.fairPrice * weight;
    else if (destination === 'china') seaCost = LOGISTICS_PRICES.sea.gulfChina.fairPrice * weight;
    else if (destination === 'europe') seaCost = LOGISTICS_PRICES.sea.gulfEurope.fairPrice * weight;
    else if (destination === 'usa') seaCost = LOGISTICS_PRICES.sea.gulfUSA.fairPrice * weight;
    else seaCost = LOGISTICS_PRICES.sea.gulfIndia.fairPrice * weight;

    breakdown.push({
        stage: 'الشحن البحري',
        cost: seaCost,
        unit: 'SAR'
    });
    totalCost += seaCost;

    // التفريغ
    breakdown.push({
        stage: 'التفريغ للعميل',
        cost: LOGISTICS_PRICES.handling.unloading.fairPrice * weight,
        unit: 'SAR'
    });
    totalCost += LOGISTICS_PRICES.handling.unloading.fairPrice * weight;

    res.json({
        success: true,
        calculation: {
            weight: weight,
            unit: 'ton',
            origin: origin,
            destination: destination,
            totalCost: Math.round(totalCost),
            costPerTon: Math.round(totalCost / weight),
            currency: 'SAR',
            breakdown: breakdown
        },
        principle: 'تسعير عادل وشفاف — لا ضرر ولا ضرار',
        timestamp: new Date().toISOString()
    });
});

