// API: حساب تكلفة الشحن الكاملة
app.post('/api/logistics/quote', (req, res) => {
    const { origin, destination, weight, cargoType, transportMode } = req.body;

    // حساب المسافة التقديرية (محاكاة)
    const distances = {
        'الرياض-جدة': 950,
        'الرياض-الدمام': 400,
        'جدة-دبي': 2400,
        'الدمام-مومباي': 2800,
        default: 500
    };
    const key = `${origin}-${destination}`;
    const distance = distances[key] || distances['default'];

    // حساب التكاليف
    const weightNum = parseFloat(weight) || 20;
    const baseCost =
        transportMode === 'sea'
            ? weightNum * 50
            : transportMode === 'air'
              ? weightNum * 500
              : weightNum * (distance * 0.08);
    const handlingCost = weightNum * 11;
    const insuranceCost = baseCost * 0.02;
    const customsCost = baseCost * 0.05;
    const profitMargin = 0.15;
    const totalCost = (baseCost + handlingCost + insuranceCost + customsCost) * (1 + profitMargin);

    res.json({
        success: true,
        quote: {
            origin,
            destination,
            distance: distance + ' كم',
            weight: weightNum + ' طن',
            cargoType: cargoType || 'معادن',
            transportMode: transportMode || 'land',
            breakdown: {
                transport: Math.round(baseCost),
                handling: Math.round(handlingCost),
                insurance: Math.round(insuranceCost),
                customs: Math.round(customsCost),
                profitMargin: Math.round(
                    (baseCost + handlingCost + insuranceCost + customsCost) * profitMargin
                )
            },
            totalCost: Math.round(totalCost),
            currency: 'SAR',
            estimatedDays:
                transportMode === 'sea'
                    ? Math.ceil(distance / 500)
                    : transportMode === 'air'
                      ? 1
                      : Math.ceil(distance / 800),
            validUntil: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString()
        },
        timestamp: new Date().toISOString()
    });
});
