// ─── تحليل السياق من السؤال ─────────────────────────────────────────────────────
function detectContext(message) {
    const lower = message.toLowerCase();
    // بحث علمي
    if (
        lower.includes('بحث') ||
        lower.includes('دراسة') ||
        lower.includes('ورقة علمية') ||
        lower.includes('أكاديمي') ||
        lower.includes('باحث') ||
        lower.includes('مختبر')
    )
        return 'research';
    // أسعار
    if (
        lower.includes('سعر') ||
        lower.includes('أسعار') ||
        lower.includes('تسعير') ||
        lower.includes('كم يكلف') ||
        lower.includes('ثمن')
    )
        return 'pricing';
    // نقل ولوجستيات
    if (
        lower.includes('نقل') ||
        lower.includes('شحن') ||
        lower.includes('توصيل') ||
        lower.includes('لوجستي')
    )
        return 'logistics';
    // سلاسل الإمداد
    if (
        lower.includes('سلسلة') ||
        lower.includes('توريد') ||
        lower.includes('إمداد') ||
        lower.includes('scm')
    )
        return 'scm';
    // نظام ERP
    if (
        lower.includes('erp') ||
        lower.includes('مخزون') ||
        lower.includes('لوحة التحكم') ||
        lower.includes('dashboard')
    )
        return 'erp';
    // بيئة واستدامة
    if (
        lower.includes('بيئة') ||
        lower.includes('تدوير') ||
        lower.includes('أخضر') ||
        lower.includes('استدامة') ||
        lower.includes('co2')
    )
        return 'environment';
    // أسئلة عن المنظومة
    if (
        lower.includes('شيخة') ||
        lower.includes('المنظومة') ||
        lower.includes('النظام') ||
        lower.includes('كيف أبدأ') ||
        lower.includes('كيف استخدم')
    )
        return 'general';
    return 'general';
}

// ─── بناء السياق الكامل ─────────────────────────────────────────────────────────
function buildFullContext(message, user = null) {
    const context = detectContext(message);
    let systemPrompt = SHEIKHA_SYSTEM_PROMPT;

    if (context !== 'general' && CONTEXT_PROMPTS[context]) {
        systemPrompt += '\n\n## سياق متخصص:\n' + CONTEXT_PROMPTS[context];
    }

    if (user) {
        systemPrompt += `\n\n## معلومات المستخدم:
- الاسم: ${user.name || user.storeName || 'غير محدد'}
- نوع الحساب: ${user.role || 'تاجر'}
- صلاحياته محدودة بمتجره ومنتجاته فقط`;
    }

    return systemPrompt;
}
// ─── استدعاء Claude Opus 4.6 ─────────────────────────────────────────────────────
// 🧠 أقوى نموذج ذكاء اصطناعي في العالم (5 فبراير 2026)
// ✨ تفكير تكيفي | سياق 1M توكن | ضغط السياق | فرق وكلاء
async function callClaudeChat(messages, maxTokens = 8192, options = {}) {
    if (!ANTHROPIC_API_KEY) return { error: 'CLAUDE_NOT_CONFIGURED' };

    // تحويل الرسائل من صيغة OpenAI إلى صيغة Anthropic
    const systemMsg = messages.find(m => m.role === 'system');
    const chatMessages = messages
        .filter(m => m.role !== 'system')
        .map(m => ({
            role: m.role === 'assistant' ? 'assistant' : 'user',
            content: m.content
        }));

    const body = {
        model: ANTHROPIC_MODEL,
        max_tokens: maxTokens,
        system: systemMsg?.content || '',
        messages: chatMessages
    };

    // ─── تفعيل التفكير التكيفي (Adaptive Thinking) لـ Opus 4.6 ──────
    if (options.enableThinking && CLAUDE_FEATURES.adaptiveThinking) {
        body.thinking = {
            type: 'enabled',
            budget_tokens: options.thinkingBudget || 8192
        };
        body.max_tokens = maxTokens + (options.thinkingBudget || 8192);
    }

    try {
        const res = await fetch(ANTHROPIC_BASE_URL + '/messages', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'x-api-key': ANTHROPIC_API_KEY,
                'anthropic-version': ANTHROPIC_VERSION
            },
            body: JSON.stringify(body)
        });

        if (!res.ok) {
            const t = await res.text();
            return { error: 'CLAUDE_ERROR', status: res.status, detail: t.slice(0, 200) };
        }

        const data = await res.json();

        // استخراج الرد والتفكير (Opus 4.6 يدعم كتل التفكير)
        let reply = '';
        let thinking = null;

        if (data.content) {
            for (const block of data.content) {
                if (block.type === 'thinking') {
                    thinking = block.thinking;
                } else if (block.type === 'text') {
                    reply = block.text;
                }
            }
        }

        if (!reply) reply = data.content?.[0]?.text || '';

        return {
            reply,
            thinking,
            usage: data.usage,
            model: ANTHROPIC_MODEL,
            provider: 'anthropic-opus-4.6'
        };
    } catch (e) {
        return { error: 'CLAUDE_NETWORK_ERROR', detail: e.message };
    }
}

// ─── استدعاء GPT-5.2 مع Fallback ─────────────────────────────────────────────────────
// 🚀 أحدث نموذج من OpenAI (فبراير 2026)
// Fallback chain: gpt-5.2 → gpt-4o → gpt-4o-mini
const OPENAI_FALLBACK_MODELS = ['gpt-5.2', 'gpt-4o', 'gpt-4o-mini'];

async function callOpenAIChat(messages, maxTokens = 800, temperature = 0.5, options = {}) {
    if (!OPENAI_API_KEY) {
        return { error: 'AI_NOT_CONFIGURED' };
    }

    // Try models in order until one works
    const modelsToTry = options.forceModel
        ? [options.forceModel]
        : OPENAI_MODEL === 'gpt-5.2'
          ? OPENAI_FALLBACK_MODELS
          : [OPENAI_MODEL];

    for (const model of modelsToTry) {
        // GPT-5 / o1 models use max_completion_tokens instead of max_tokens
        const isNewModel =
            model.startsWith('gpt-5') || model.startsWith('o1') || model.startsWith('o3');

        const body = {
            model: model,
            messages
        };

        // Handle token parameter naming based on model
        if (isNewModel) {
            body.max_completion_tokens = Math.min(maxTokens, 4000);
            // GPT-5 / o1 doesn't support temperature
        } else {
            body.max_tokens = Math.min(maxTokens, 4000);
            body.temperature = temperature;
        }

        // ميزات GPT-5 الجديدة (فقط للنماذج التي تدعمها)
        if (isNewModel && options.reasoning_effort) {
            body.reasoning_effort = options.reasoning_effort;
        }
        if (isNewModel && options.verbosity) {
            body.verbosity = options.verbosity;
        }

        const url = OPENAI_BASE_URL + '/chat/completions';
        try {
            const res = await fetch(url, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: 'Bearer ' + OPENAI_API_KEY
                },
                body: JSON.stringify(body)
            });

            if (!res.ok) {
                const t = await res.text();
                // If model not found, try next model
                if (res.status === 404 || t.includes('does not exist') || t.includes('not found')) {
                    console.log(`[AI] Model ${model} not available, trying next...`);
                    continue;
                }
                // Check for billing/quota issues
                if (res.status === 429 || t.includes('quota') || t.includes('billing')) {
                    return {
                        error: 'AI_QUOTA_EXCEEDED',
                        status: res.status,
                        detail: 'الرصيد منتهي في OpenAI. يرجى شحن الحساب.'
                    };
                }
                return { error: 'LLM_ERROR', status: res.status, detail: t.slice(0, 200) };
            }

            const data = await res.json();
            const choice = data.choices && data.choices[0];
            const reply =
                choice && choice.message && choice.message.content
                    ? choice.message.content.trim()
                    : '';

            // Log which model actually worked
            if (model !== OPENAI_MODEL) {
                console.log(`[AI] ✓ Using fallback model: ${model}`);
            }

            return {
                reply,
                usage: data.usage,
                model: model, // Return actual model used
                provider: 'openai',
                reasoning: choice?.message?.reasoning
            };
        } catch (e) {
            continue;
        }
    }

    // All models failed
    return { error: 'LLM_ALL_MODELS_FAILED', detail: 'تعذر الاتصال بأي نموذج AI' };
}

// ─── استدعاء LLM الذكي (يختار الأفضل تلقائياً) ─────────────────────────────────────
async function callLLMChat(messages, maxTokens = 800, temperature = 0.5, options = {}) {
    const isDevelopment =
        options.mode === 'development' ||
        messages.some(
            m =>
                m.content?.includes('كود') ||
                m.content?.includes('برمج') ||
                m.content?.includes('تطوير')
        );

    // للتطوير والبرمجة: استخدم Claude Opus 4.6 (الأقوى في العالم)
    if (isDevelopment && ANTHROPIC_API_KEY) {
        const result = await callClaudeChat(messages, maxTokens, options);
        if (!result.error) return result;
        // fallback to OpenAI if Claude fails
    }

    // للمحادثات العامة: استخدم GPT-5.2
    if (OPENAI_API_KEY) {
        return await callOpenAIChat(messages, maxTokens, temperature, options);
    }

    // لا يوجد مفتاح API
    return { error: 'AI_NOT_CONFIGURED' };
}

// ─── دالة قديمة للتوافق ─────────────────────────────────────────────────────────────
// (للحفاظ على التوافق مع الكود القديم)
async function callLLMChatLegacy(messages, maxTokens = 800, temperature = 0.5, options = {}) {
    return callLLMChat(messages, maxTokens, temperature, options);
}

// ─── LLM متخصص للأسعار ─────────────────────────────────────────────────────────
async function callPricingLLM(metalType, quantity, quality, region) {
    const prompt = `بناءً على خبرتك في سوق المعادن السعودي، اقترح سعراً مناسباً لـ:
- نوع المعدن: ${metalType}
- الكمية: ${quantity}
- الجودة: ${quality}
- المنطقة: ${region}

قدم:
1. السعر المقترح (ريال/طن)
2. نطاق السعر (من - إلى)
3. العوامل المؤثرة
4. نصيحة للبائع`;

    const messages = [
        { role: 'system', content: CONTEXT_PROMPTS.pricing },
        { role: 'user', content: prompt }
    ];
    return callLLMChat(messages, 600, 0.3);
}

// ─── LLM متخصص للتحليل ─────────────────────────────────────────────────────────
async function callAnalyticsLLM(data, question) {
    const prompt = `بناءً على البيانات التالية:
${JSON.stringify(data, null, 2)}

أجب عن السؤال: ${question}

قدم تحليلاً مختصراً مع توصيات عملية.`;

    const messages = [
        {
            role: 'system',
            content: 'أنت محلل بيانات متخصص في سوق المعادن والسكراب. قدم تحليلات دقيقة ومختصرة.'
        },
        { role: 'user', content: prompt }
    ];
    return callLLMChat(messages, 800, 0.4);
}

// ─── LLM للبحث والاقتراحات ─────────────────────────────────────────────────────
async function callSearchLLM(query, context) {
    const prompt = `المستخدم يبحث عن: "${query}"
السياق: ${context}

اقترح:
1. نتائج بحث مناسبة
2. منتجات/خدمات ذات صلة
3. نصائح للمستخدم`;

    const messages = [
        { role: 'system', content: 'أنت محرك بحث ذكي لسوق المعادن والسكراب.' },
        { role: 'user', content: prompt }
    ];
    return callLLMChat(messages, 500, 0.5);
}
