// 🧠 نظام جمع البيانات والتعلم — AI Learning System
// ═══════════════════════════════════════════════════════════════════════════════

const AI_LEARNING_FILE = path.join(__dirname, 'data', 'ai-learning.json');
let AI_LEARNING_DATA = {
    conversations: [],
    unansweredQuestions: [],
    popularTopics: {},
    userFeedback: [],
    statistics: {
        totalConversations: 0,
        totalMessages: 0,
        averageResponseTime: 0,
        satisfactionRate: 0,
        lastUpdated: null
    },
    knowledgeGaps: [],
    suggestedImprovements: []
};

// تحميل بيانات التعلم
try {
    if (fs.existsSync(AI_LEARNING_FILE)) {
        AI_LEARNING_DATA = JSON.parse(fs.readFileSync(AI_LEARNING_FILE, 'utf8'));
    }
} catch (e) {
    console.log('AI learning data init');
}

// حفظ بيانات التعلم
function saveAILearning() {
    try {
        AI_LEARNING_DATA.statistics.lastUpdated = new Date().toISOString();
        fs.writeFileSync(AI_LEARNING_FILE, JSON.stringify(AI_LEARNING_DATA, null, 2), 'utf8');
    } catch (e) {
        console.error('Failed to save AI learning data');
    }
}

// تسجيل المحادثة للتعلم
function recordConversation(userMessage, aiResponse, context, responseTime, wasHelpful = null) {
    const record = {
        id: uuidv4(),
        timestamp: new Date().toISOString(),
        userMessage: userMessage.slice(0, 500),
        aiResponsePreview: aiResponse.slice(0, 200),
        context,
        responseTime,
        wasHelpful,
        intent: detectContext(userMessage)
    };

    // إضافة للمحادثات (آخر 1000)
    AI_LEARNING_DATA.conversations.unshift(record);
    if (AI_LEARNING_DATA.conversations.length > 1000) {
        AI_LEARNING_DATA.conversations = AI_LEARNING_DATA.conversations.slice(0, 1000);
    }

    // تحديث المواضيع الشائعة
    const topic = record.intent || 'general';
    AI_LEARNING_DATA.popularTopics[topic] = (AI_LEARNING_DATA.popularTopics[topic] || 0) + 1;

    // تحديث الإحصائيات
    AI_LEARNING_DATA.statistics.totalConversations++;
    AI_LEARNING_DATA.statistics.totalMessages++;

    // اكتشاف الأسئلة التي لم تُجب عليها جيداً
    if (
        aiResponse.includes('لم أتمكن') ||
        aiResponse.includes('لا أعرف') ||
        aiResponse.length < 50
    ) {
        AI_LEARNING_DATA.unansweredQuestions.push({
            question: userMessage.slice(0, 300),
            timestamp: new Date().toISOString(),
            context
        });
        if (AI_LEARNING_DATA.unansweredQuestions.length > 100) {
            AI_LEARNING_DATA.unansweredQuestions = AI_LEARNING_DATA.unansweredQuestions.slice(-100);
        }
    }
}

// تسجيل تقييم المستخدم
function recordFeedback(conversationId, rating, comment) {
    AI_LEARNING_DATA.userFeedback.push({
        conversationId,
        rating,
        comment: comment?.slice(0, 500),
        timestamp: new Date().toISOString()
    });

    // حساب معدل الرضا
    const recentFeedback = AI_LEARNING_DATA.userFeedback.slice(-100);
    const avgRating =
        recentFeedback.reduce((sum, f) => sum + (f.rating || 0), 0) / recentFeedback.length;
    AI_LEARNING_DATA.statistics.satisfactionRate = Math.round(avgRating * 20); // تحويل من 5 إلى 100%
}

// حفظ دوري
setInterval(saveAILearning, 60000);

