// المحادثة للزوار (بدون مصادقة)
app.post('/api/ai/chat-public', express.json(), async (req, res) => {
    const message =
        req.body && req.body.message ? String(req.body.message).trim().slice(0, 1000) : '';
    if (!message)
        return res.status(400).json({ success: false, message: 'أرسل message في الجسم.' });

    const systemContent =
        SHEIKHA_SYSTEM_PROMPT + '\n\nهذا زائر غير مسجل. وجّهه للتسجيل إن كان مهتماً بالتجارة.';

    const messages = [
        { role: 'system', content: systemContent },
        { role: 'user', content: message }
    ];

    try {
        const result = await callLLMChat(messages, 500, 0.6);
        if (result.error) {
            return res.json({
                success: true,
                reply: getDefaultReply(message),
                source: 'نظام الردود الافتراضية'
            });
        }
        res.json({ success: true, reply: result.reply, model: result.model });
    } catch (e) {
        res.json({
            success: true,
            reply: getDefaultReply(message),
            source: 'نظام الردود الافتراضية'
        });
    }
});

// ═══════════════════════════════════════════════════════════════════════════════
// 🌍 سوق شيخة مركز وأساس أسواق السكراب — تسجيل تاجر وعرض بضائع + تسجيل منتجات آلياً
// ═══════════════════════════════════════════════════════════════════════════════
const TRADERS_FILE = path.join(DATA_DIR, 'traders.json');
const LISTINGS_FILE = path.join(DATA_DIR, 'listings.json');
const USERS_FILE = path.join(DATA_DIR, 'users.json');
const CONTAINERS_FILE = path.join(DATA_DIR, 'containers.json');
const NOTIFICATIONS_FILE = path.join(DATA_DIR, 'notifications.json');

// ═══════════════════════════════════════════════════════════════════════════════
// 📦 نظام حفظ العمليات والأرشفة والشبكة السحابية (بدون تأخير، سرعة، كفاءة عالية)
// ═══════════════════════════════════════════════════════════════════════════════
const OPERATIONS_DIR = path.join(DATA_DIR, 'operations');
const OPERATIONS_ESSENTIAL_DIR = path.join(OPERATIONS_DIR, 'essential');
const OPERATIONS_ARCHIVE_DIR = path.join(OPERATIONS_DIR, 'archive');
const OPERATIONS_CLOUD_STAGING_DIR = path.join(OPERATIONS_DIR, 'cloud-staging');
[
    OPERATIONS_DIR,
    OPERATIONS_ESSENTIAL_DIR,
    OPERATIONS_ARCHIVE_DIR,
    OPERATIONS_CLOUD_STAGING_DIR
].forEach(d => {
    if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true });
});

const OPERATIONS_ESSENTIAL_THRESHOLD =
    Number(process.env.OPERATIONS_ESSENTIAL_VALUE_THRESHOLD) || 100000; // ريال — عروض تتجاوزها تُحفظ كضرورية
const CLOUD_SYNC_ENABLED = (process.env.CLOUD_SYNC_ENABLED || '').toLowerCase() === 'true';
const CLOUD_SYNC_URL = (process.env.CLOUD_SYNC_URL || '').trim();

let OPERATIONS_QUEUE = [];
let OPERATIONS_STATS = {
    totalLogged: 0,
    totalEssential: 0,
    lastFlush: null,
    cloudQueueLength: 0,
    cloudLastSync: null
};

function isEssentialOperation(opType, payload) {
    if (opType === 'trader_register' || opType === 'user_register') return true;
    if (opType === 'listing_add' || opType === 'listing_edit' || opType === 'listing_delete') {
        const p = payload || {};
        const price = Number(p.price) || 0;
        const qty = Number(p.quantity) || 1;
        const value = price * qty;
        return value >= OPERATIONS_ESSENTIAL_THRESHOLD;
    }
    if (opType === 'container_add' || opType === 'container_edit') return true;
    return false;
}

function logOperation(opType, entityType, summary, fullPayload) {
    const ts = new Date().toISOString();
    const id = uuidv4();
    const essential = isEssentialOperation(opType, fullPayload || summary);
    const entry = {
        id,
        opType,
        entityType,
        summary: summary || {},
        fullPayload: fullPayload || null,
        ts,
        essential
    };
    OPERATIONS_QUEUE.push(entry);
    OPERATIONS_STATS.totalLogged++;
    if (essential) OPERATIONS_STATS.totalEssential++;
    if (OPERATIONS_QUEUE.length >= 50) flushOperationsLog();
    if (essential) appendEssentialSync(entry);
    if (CLOUD_SYNC_ENABLED && CLOUD_SYNC_URL) enqueueCloudSync(entry);
}

function appendEssentialSync(entry) {
    try {
        const today = new Date().toISOString().slice(0, 10);
        const f = path.join(OPERATIONS_ESSENTIAL_DIR, `essential-${today}.json`);
        let list = [];
        try {
            list = JSON.parse(fs.readFileSync(f, 'utf8'));
        } catch (_) {}
        if (!Array.isArray(list)) list = [];
        list.push(entry);
        fs.writeFileSync(f, JSON.stringify(list, null, 2), 'utf8');
    } catch (e) {
        console.error('[ops] appendEssentialSync:', e.message);
    }
}

let CLOUD_QUEUE = [];
let CLOUD_SYNCING = false;
function enqueueCloudSync(entry) {
    CLOUD_QUEUE.push(entry);
    OPERATIONS_STATS.cloudQueueLength = CLOUD_QUEUE.length;
    if (!CLOUD_SYNCING && CLOUD_QUEUE.length > 0) setImmediate(cloudSync);
}
function cloudSync() {
    if (CLOUD_SYNCING || CLOUD_QUEUE.length === 0) return;
    CLOUD_SYNCING = true;
    const batch = CLOUD_QUEUE.splice(0, 100);
    OPERATIONS_STATS.cloudQueueLength = CLOUD_QUEUE.length;
    const body = JSON.stringify({
        source: 'sheikha-main-portal',
        ts: new Date().toISOString(),
        operations: batch
    });
    fetch(CLOUD_SYNC_URL, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body })
        .then(() => {
            OPERATIONS_STATS.cloudLastSync = new Date().toISOString();
        })
        .catch(e => {
            CLOUD_QUEUE.unshift(...batch);
            OPERATIONS_STATS.cloudQueueLength = CLOUD_QUEUE.length;
        })
        .finally(() => {
            CLOUD_SYNCING = false;
            if (CLOUD_QUEUE.length > 0) setImmediate(cloudSync);
        });
}

function flushOperationsLog() {
    if (OPERATIONS_QUEUE.length === 0) return;
    const batch = OPERATIONS_QUEUE.splice(0, OPERATIONS_QUEUE.length);
    const today = new Date().toISOString().slice(0, 10);
    const logFile = path.join(OPERATIONS_DIR, `ops-${today}.ndjson`);
    try {
        const lines = batch.map(e => JSON.stringify(e)).join('\n') + '\n';
        fs.appendFileSync(logFile, lines, 'utf8');
        OPERATIONS_STATS.lastFlush = new Date().toISOString();
    } catch (e) {
        console.error('[ops] flushOperationsLog:', e.message);
    }
}
setInterval(flushOperationsLog, 1000);

function loadJSON(file, def = []) {
    try {
        return JSON.parse(fs.readFileSync(file, 'utf8'));
    } catch (_) {
        return def;
    }
}
function saveJSON(file, data) {
    fs.writeFileSync(file, JSON.stringify(data, null, 2), 'utf8');
}

let TRADERS = loadJSON(TRADERS_FILE, []);
let LISTINGS = loadJSON(LISTINGS_FILE, []);
let USERS = loadJSON(USERS_FILE, []);
let CONTAINERS = loadJSON(CONTAINERS_FILE, []);
