function autoCategory(productName) {
    const n = (productName || '').toLowerCase();
    for (const cat of SCRAP_CATEGORIES) {
        if (cat.keywords.some(k => n.includes(k.toLowerCase())))
            return { id: cat.id, name: cat.name };
    }
    return { id: 'other', name: 'أخرى' };
}

function getHSCategory(id) {
    const c = HS_SCRAP_CATEGORIES.find(x => x.id === id);
    return c
        ? { id: c.id, nameAr: c.nameAr, icon: c.icon }
        : { id: 'other', nameAr: 'أخرى', icon: '□' };
}

