// مصادقة JWT (اختيارية — إن وُجد التوكن يُضاف req.user)
function authOptional(req, res, next) {
    const token =
        (req.headers.authorization && req.headers.authorization.split(' ')[1]) ||
        req.body?.token ||
        req.query?.token;
    if (!token) return next();
    try {
        const payload = jwt.verify(token, JWT_SECRET);
        const user = USERS.find(u => u.id === payload.userId);
        if (user) {
            req.user = {
                id: user.id,
                phone: user.phone,
                name: user.name,
                email: user.email,
                storeName: user.storeName,
                region: user.region,
                marketingEnabled: user.marketingEnabled,
                role: user.role || 'user'
            };
        }
    } catch (_) {}
    next();
}
function authRequired(req, res, next) {
    const token =
        (req.headers.authorization && req.headers.authorization.split(' ')[1]) ||
        req.body?.token ||
        req.query?.token;
    if (!token) return res.status(401).json({ success: false, message: 'يجب تسجيل الدخول.' });
    try {
        const payload = jwt.verify(token, JWT_SECRET);
        const user = USERS.find(u => u.id === payload.userId);
        if (!user) return res.status(401).json({ success: false, message: 'مستخدم غير موجود.' });
        req.user = {
            id: user.id,
            phone: user.phone,
            name: user.name,
            email: user.email,
            storeName: user.storeName,
            region: user.region,
            marketingEnabled: user.marketingEnabled,
            role: user.role || 'user'
        };
        next();
    } catch (_) {
        res.status(401).json({ success: false, message: 'جلسة منتهية. سجّل الدخول مرة أخرى.' });
    }
}

// تم إزالة البيانات الوهمية نهائياً - المنتجات تأتي فقط من التجار الحقيقيين
const MARKET_STORES_SAMPLE = [];

// ─── تحقق الاسم والبريد (للتسجيل) ─────────────────────────────────────────────
function validateName(name) {
    const n = (name || '').trim();
    if (n.length < 2) return { valid: false, message: 'الاسم يجب أن يكون حرفين على الأقل.' };
    if (n.length > 120) return { valid: false, message: 'الاسم طويل جداً.' };
    return { valid: true, value: n };
}
function validateEmail(email) {
    const e = (email || '').trim();
    if (!e) return { valid: true, value: e };
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e))
        return { valid: false, message: 'صيغة البريد الإلكتروني غير صحيحة.' };
    if (e.length > 200) return { valid: false, message: 'البريد طويل جداً.' };
    return { valid: true, value: e };
}

// ═══════════════════════════════════════════════════════════════════════════════
// 🔐 تسجيل الدخول والتسجيل — داشبورد مستخدم
// ═══════════════════════════════════════════════════════════════════════════════
app.post('/api/auth/register', (req, res) => {
    const {
        phone,
        password,
        name,
        email,
        storeName,
        region,
        specialty: specialtyId
    } = req.body || {};
    if (!phone || !password || !name)
        return res
            .status(400)
            .json({ success: false, message: 'الجوال وكلمة المرور والاسم مطلوبان.' });
    const nameCheck = validateName(name);
    if (!nameCheck.valid)
        return res.status(400).json({ success: false, message: nameCheck.message });
    const emailCheck = validateEmail(email);
    if (!emailCheck.valid)
        return res.status(400).json({ success: false, message: emailCheck.message });
    if (USERS.some(u => String(u.phone) === String(phone).trim()))
        return res.status(400).json({ success: false, message: 'هذا الجوال مسجّل مسبقاً.' });
    const id = uuidv4();
    const specialtyKey = (specialtyId || '').trim() || 'metals_trader';
    const spec = getSpecialty(specialtyKey);
    const user = {
        id,
        phone: String(phone).trim(),
        passwordHash: hashPassword(password),
        name: nameCheck.value,
        email: emailCheck.value,
        storeName: (storeName || spec.storeLabel || nameCheck.value).trim(),
        region: (region || '').trim(),
        marketingEnabled: false,
        specialty: spec.id,
        role: 'user',
        verified: false,
        authMethods: ['phone'],
        securityLog: [{ action: 'registered', at: new Date().toISOString(), method: 'phone' }],
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };
    USERS.push(user);
    saveJSON(USERS_FILE, USERS);
    const trader = {
        id,
        name: user.name,
        email: user.email,
        phone: user.phone,
        region: user.region,
        company: user.storeName,
        specialty: spec.id,
        specialtyLabel: spec.nameAr,
        createdAt: user.createdAt
    };
    if (!TRADERS.find(t => t.id === id)) {
        TRADERS.push(trader);
        saveJSON(TRADERS_FILE, TRADERS);
    }
    logOperation('user_register', 'user', { id, phone: user.phone, name: user.name }, user);
    const token = jwt.sign({ userId: id, role: user.role }, JWT_SECRET, { expiresIn: '7d' });
    const out = {
        id: user.id,
        phone: user.phone,
        name: user.name,
        email: user.email,
        storeName: user.storeName,
        region: user.region,
        marketingEnabled: user.marketingEnabled,
        role: user.role
    };
    res.status(201).json({
        success: true,
        user: out,
        token,
        role: user.role,
        message: 'تم التسجيل بنجاح. يمكنك الدخول إلى لوحة التحكم.'
    });
    // ═══ إطلاق حدث الأتمتة — تسجيل مستخدم جديد ═══
    if (automationEngine)
        try {
            automationEngine.emit('user:registered', {
                id,
                name: user.name,
                email: user.email,
                phone: user.phone
            });
        } catch (_) {}

    // ═══ Meta CAPI — Lead ═══
    if (metaEngine)
        try {
            metaEngine.sendLeadEvent(
                { email: user.email, phone: user.phone, firstName: user.name },
                { contentName: 'تسجيل مستخدم — سوق شيخة', contentCategory: user.specialty || 'metals_trader', market: region || null }
            ).catch(() => {});
        } catch (_) {}
});

app.post('/api/auth/login', (req, res) => {
    const { phone, password, email: loginEmail } = req.body || {};
    const identifier = (phone || loginEmail || '').trim();
    if (!identifier || !password)
        return res
            .status(400)
            .json({ success: false, message: 'الجوال/الإيميل وكلمة المرور مطلوبان.' });

    // البحث بالجوال أو الإيميل — «وَتَعَاوَنُوا عَلَى الْبِرِّ وَالتَّقْوَىٰ»
    const user = USERS.find(
        u =>
            String(u.phone) === identifier ||
            (u.email && u.email.toLowerCase() === identifier.toLowerCase()) ||
            (u.syncEmails && u.syncEmails.some(e => e.toLowerCase() === identifier.toLowerCase()))
    );

    // حماية من هجمات القوة الغاشمة
    if (user && user.accountLockedUntil && new Date(user.accountLockedUntil) > new Date()) {
        const mins = Math.ceil((new Date(user.accountLockedUntil) - new Date()) / 60000);
        return res
            .status(423)
            .json({
                success: false,
                message: 'الحساب مقفل مؤقتاً. حاول بعد ' + mins + ' دقيقة.',
                code: 'ACCOUNT_LOCKED'
            });
    }

    if (!user || !verifyPassword(password, user.passwordHash)) {
        // تسجيل محاولة فاشلة
        if (user) {
            user.failedLoginAttempts = (user.failedLoginAttempts || 0) + 1;
            if (user.failedLoginAttempts >= 5) {
                user.accountLockedUntil = new Date(Date.now() + 15 * 60 * 1000).toISOString(); // قفل 15 دقيقة
                if (!user.securityLog) user.securityLog = [];
                user.securityLog.push({
                    action: 'account_locked',
                    at: new Date().toISOString(),
                    reason: 'too_many_failed_attempts',
                    count: user.failedLoginAttempts
                });
            }
            saveJSON(USERS_FILE, USERS);
        }
        return res.status(401).json({ success: false, message: 'بيانات دخول غير صحيحة.' });
    }

    // نجاح — إعادة تعيين المحاولات الفاشلة
    user.failedLoginAttempts = 0;
    user.accountLockedUntil = null;
    user.lastLoginAt = new Date().toISOString();
    if (!user.securityLog) user.securityLog = [];
    user.securityLog.push({
        action: 'login_success',
        at: new Date().toISOString(),
        method: identifier.includes('@') ? 'email' : 'phone'
    });
    // الاحتفاظ بآخر 100 سجل أمني فقط
    if (user.securityLog.length > 100) user.securityLog = user.securityLog.slice(-100);
    saveJSON(USERS_FILE, USERS);

    const role = user.role || 'user';
    const token = jwt.sign({ userId: user.id, role }, JWT_SECRET, { expiresIn: '7d' });
    const out = {
        id: user.id,
        phone: user.phone,
        name: user.name,
        email: user.email,
        storeName: user.storeName,
        region: user.region,
        marketingEnabled: user.marketingEnabled,
        specialty: user.specialty,
        role
    };
    onUserLoggedIn(out);
    res.json({ success: true, user: out, token, role, message: 'تم تسجيل الدخول.' });
});

