// ══════ OAuth / Social Login — تسجيل الدخول بالحسابات الاجتماعية ══════
// ═══════════════════════════════════════════════════════════════
const OAUTH_CONFIG = {
    // ─── مزودو تسجيل الدخول المسموح بهم ───────────────────────────────────────
    // ملاحظة: Facebook Personal Login ممنوع بقرار المالك.
    //         Meta Pixel / CAPI للإعلانات: مسموح (sheikha-meta-engine.js).
    // ──────────────────────────────────────────────────────────────────────────
    google: {
        clientId: process.env.GOOGLE_CLIENT_ID || '',
        clientSecret: process.env.GOOGLE_CLIENT_SECRET || '',
        name: 'Google',
        enabled: !!process.env.GOOGLE_CLIENT_ID
    },
    apple: {
        clientId: process.env.APPLE_CLIENT_ID || '',
        clientSecret: process.env.APPLE_CLIENT_SECRET || '',
        name: 'Apple',
        enabled: !!process.env.APPLE_CLIENT_ID
    },
    microsoft: {
        clientId: process.env.MICROSOFT_CLIENT_ID || '',
        clientSecret: process.env.MICROSOFT_CLIENT_SECRET || '',
        name: 'Microsoft',
        enabled: !!process.env.MICROSOFT_CLIENT_ID
    },
    twitter: {
        clientId: process.env.TWITTER_CLIENT_ID || '',
        clientSecret: process.env.TWITTER_CLIENT_SECRET || '',
        name: 'X (Twitter)',
        enabled: !!process.env.TWITTER_CLIENT_ID
    },
    snapchat: {
        clientId: process.env.SNAPCHAT_CLIENT_ID || '',
        clientSecret: process.env.SNAPCHAT_CLIENT_SECRET || '',
        name: 'Snapchat',
        enabled: !!process.env.SNAPCHAT_CLIENT_ID
    },
    instagram: {
        clientId: process.env.INSTAGRAM_CLIENT_ID || '',
        clientSecret: process.env.INSTAGRAM_CLIENT_SECRET || '',
        name: 'Instagram',
        enabled: !!process.env.INSTAGRAM_CLIENT_ID
    },
    tiktok: {
        clientId: process.env.TIKTOK_CLIENT_ID || '',
        clientSecret: process.env.TIKTOK_CLIENT_SECRET || '',
        name: 'TikTok',
        enabled: !!process.env.TIKTOK_CLIENT_ID
    }
    // facebook: ممنوع — لا يُضاف هنا. استخدم Instagram أو Snapchat بديلاً.
};

// OAuth endpoint لكل مزود
['google', 'apple', 'microsoft', 'twitter', 'snapchat', 'instagram', 'tiktok'].forEach(provider => {
    app.get(`/api/auth/oauth/${provider}`, (req, res) => {
        const config = OAUTH_CONFIG[provider];
        const mode = req.query.mode || 'login';

        if (!config || !config.enabled) {
            // المزود غير مُعد — أرسل رسالة إعداد
            return res.json({
                success: false,
                setup: true,
                provider,
                name: config ? config.name : provider,
                message: `خدمة ${config ? config.name : provider} تحتاج إعداد — أضف ${provider.toUpperCase()}_CLIENT_ID و ${provider.toUpperCase()}_CLIENT_SECRET في متغيرات البيئة`,
                instructions: {
                    step1: `أنشئ تطبيقاً في ${config ? config.name : provider} Developer Console`,
                    step2: `أضف Redirect URI: ${req.protocol}://${req.get('host')}/api/auth/oauth/${provider}/callback`,
                    step3: `ضع Client ID و Client Secret في ملف .env`
                }
            });
        }

        // بناء رابط OAuth حسب المزود
        const redirectUri = `${req.protocol}://${req.get('host')}/api/auth/oauth/${provider}/callback`;
        let authUrl = '';

        switch (provider) {
            case 'google':
                authUrl = `https://accounts.google.com/o/oauth2/v2/auth?client_id=${config.clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&response_type=code&scope=openid%20email%20profile&state=${mode}&prompt=consent`;
                break;
            case 'apple':
                authUrl = `https://appleid.apple.com/auth/authorize?client_id=${config.clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&response_type=code&scope=name%20email&state=${mode}&response_mode=form_post`;
                break;
            case 'microsoft':
                authUrl = `https://login.microsoftonline.com/common/oauth2/v2.0/authorize?client_id=${config.clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&response_type=code&scope=openid%20email%20profile&state=${mode}`;
                break;
            case 'twitter':
                authUrl = `https://twitter.com/i/oauth2/authorize?client_id=${config.clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&response_type=code&scope=tweet.read%20users.read%20offline.access&state=${mode}&code_challenge=challenge&code_challenge_method=plain`;
                break;
            case 'snapchat':
                authUrl = `https://accounts.snapchat.com/accounts/oauth2/auth?client_id=${config.clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&response_type=code&scope=https://auth.snapchat.com/oauth2/api/user.display_name%20https://auth.snapchat.com/oauth2/api/user.bitmoji.avatar&state=${mode}`;
                break;
            case 'instagram':
                authUrl = `https://api.instagram.com/oauth/authorize?client_id=${config.clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&response_type=code&scope=user_profile&state=${mode}`;
                break;
            case 'tiktok':
                authUrl = `https://www.tiktok.com/v2/auth/authorize/?client_key=${config.clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&response_type=code&scope=user.info.basic&state=${mode}`;
                break;
        }

        res.json({ success: true, authUrl, provider, name: config.name });
    });

    // Callback لكل مزود
    app.get(`/api/auth/oauth/${provider}/callback`, async (req, res) => {
        const { code, state, error } = req.query;
        const mode = state || 'login';

        if (error || !code) {
            return res.redirect(
                `/%D8%AA%D8%B3%D8%AC%D9%8A%D9%84-%D8%A7%D9%84%D8%AF%D8%AE%D9%88%D9%84.html?error=${encodeURIComponent('فشل المصادقة عبر ' + (OAUTH_CONFIG[provider] || {}).name)}`
            );
        }

        try {
            // تبادل الكود بتوكن — يتطلب مكتبة HTTP حسب المزود
            // هنا نبني المنطق العام — كل مزود له token endpoint مختلف
            const config = OAUTH_CONFIG[provider];
            const redirectUri = `${req.protocol}://${req.get('host')}/api/auth/oauth/${provider}/callback`;

            // سيتم تطوير هذا الجزء عند ربط كل مزود فعلياً
            // حالياً: نسجل المحاولة ونعيد التوجيه
            console.log(
                `[OAuth] ${provider} callback received — code: ${code ? 'yes' : 'no'}, mode: ${mode}`
            );

            // البحث عن مستخدم مربوط أو إنشاء جديد
            let user = USERS.find(u => u.oauthProviders && u.oauthProviders[provider]);

            if (!user && mode === 'register') {
                // إنشاء حساب جديد
                const id = 'U' + Date.now();
                user = {
                    id,
                    name: `مستخدم ${config.name}`,
                    phone: '',
                    email: '',
                    passwordHash: '',
                    storeName: '',
                    region: '',
                    role: 'user',
                    verified: true,
                    createdAt: new Date().toISOString(),
                    oauthProviders: { [provider]: { code, linkedAt: new Date().toISOString() } },
                    authMethods: [provider]
                };
                USERS.push(user);
                saveJSON(USERS_FILE, USERS);
            }

            if (user) {
                const token = jwt.sign({ userId: user.id, role: user.role || 'user' }, JWT_SECRET, {
                    expiresIn: '7d'
                });
                return res.redirect(
                    `/%D8%AA%D8%B3%D8%AC%D9%8A%D9%84-%D8%A7%D9%84%D8%AF%D8%AE%D9%88%D9%84.html?token=${token}&role=${user.role || 'user'}`
                );
            }

            // لا يوجد حساب — أعد للتسجيل
            return res.redirect(
                `/%D8%AA%D8%B3%D8%AC%D9%8A%D9%84-%D8%A7%D9%84%D8%AF%D8%AE%D9%88%D9%84.html?error=${encodeURIComponent('لا يوجد حساب مربوط بـ ' + config.name + ' — سجّل أولاً')}`
            );
        } catch (e) {
            console.error(`[OAuth] ${provider} error:`, e.message);
            return res.redirect(
                `/%D8%AA%D8%B3%D8%AC%D9%8A%D9%84-%D8%A7%D9%84%D8%AF%D8%AE%D9%88%D9%84.html?error=${encodeURIComponent('خطأ في المصادقة')}`
            );
        }
    });
});

// حالة OAuth — لوحة التحكم
app.get('/api/auth/oauth/status', (req, res) => {
    const providers = {};
    for (const [k, v] of Object.entries(OAUTH_CONFIG)) {
        providers[k] = { name: v.name, enabled: v.enabled, configured: !!v.clientId };
    }
    res.json({
        success: true,
        providers,
        totalConfigured: Object.values(OAUTH_CONFIG).filter(v => v.enabled).length
    });
});

app.get('/api/me', authRequired, (req, res) => {
    const fullUser = USERS.find(u => u.id === req.user.id);
    const out = { ...req.user };
    if (fullUser) {
        out.verified = fullUser.verified || false;
        out.nafathVerified = fullUser.nafathVerified || false;
        out.authMethods = fullUser.authMethods || [];
        out.twoFactorEnabled = fullUser.twoFactorEnabled || false;
        out.twoFactorMethod = fullUser.twoFactorMethod || null;
        out.identity = fullUser.identity || null;
        out.contact = fullUser.contact || null;
        out.recoveryEmail = fullUser.recoveryEmail || null;
        out.syncEmails = fullUser.syncEmails || [];
        out.lastLoginAt = fullUser.lastLoginAt || null;
    }
    res.json({ success: true, user: out });
});

// ═══ حالة توثيق حساب المدير — Admin Identity Verification Status ═══
app.get('/api/admin/identity-status', authRequired, (req, res) => {
    if (req.user.role !== 'admin')
        return res.status(403).json({ success: false, message: 'غير مصرح.' });
    const admin = USERS.find(u => u.id === req.user.id);
    if (!admin) return res.status(404).json({ success: false, message: 'المدير غير موجود.' });
    const id = admin.identity || {};
    const c = admin.contact || {};
    // ─── تحذير انتهاء السجل التجاري ───
    let crWarning = null;
    if (id.crExpiryDate) {
        const expiry = new Date(id.crExpiryDate);
        const now = new Date();
        const daysLeft = Math.ceil((expiry - now) / (1000 * 60 * 60 * 24));
        if (daysLeft <= 0)
            crWarning = {
                level: 'expired',
                message: 'السجل التجاري منتهي! يجب تجديده فوراً.',
                daysLeft: 0
            };
        else if (daysLeft <= 30)
            crWarning = {
                level: 'urgent',
                message: 'السجل التجاري ينتهي خلال ' + daysLeft + ' يوم — جدّده الآن!',
                daysLeft
            };
        else if (daysLeft <= 90)
            crWarning = {
                level: 'warning',
                message: 'السجل التجاري ينتهي خلال ' + daysLeft + ' يوم.',
                daysLeft
            };
    }
    const checks = {
        ownerName: {
            value: id.ownerFullName || admin.name,
            valueEn: id.ownerFullNameEn || null,
            status: admin.name ? 'verified' : 'missing',
            label: 'اسم المالك'
        },
        businessName: {
            value: id.businessName || null,
            valueEn: id.businessNameEn || null,
            status: id.businessName ? 'verified' : 'missing',
            label: 'اسم المؤسسة التجارية'
        },
        email: {
            value: admin.email,
            status: admin.email ? 'verified' : 'missing',
            label: 'البريد الرئيسي'
        },
        secondaryEmail: {
            value: c.secondaryEmail || null,
            status: c.secondaryEmail ? 'verified' : 'missing',
            label: 'البريد الثانوي'
        },
        phone: {
            value: admin.phone,
            status: admin.phone ? 'verified' : 'missing',
            label: 'رقم الجوال'
        },
        recoveryEmail: {
            value: admin.recoveryEmail,
            status: admin.recoveryEmail ? 'verified' : 'missing',
            label: 'بريد الطوارئ'
        },
        nationalId: {
            value: id.nationalId ? '****' + String(id.nationalId).slice(-4) : null,
            status: id.nafathStatus || 'pending',
            label: 'رقم الهوية الوطنية (الأحوال)'
        },
        nafath: {
            status: id.nafathStatus || 'pending',
            verifiedAt: id.nafathVerifiedAt || null,
            label: 'نفاذ (التحقق الشخصي)'
        },
        businessRegistry: {
            value: id.businessRegistry ? '****' + String(id.businessRegistry).slice(-4) : null,
            status: id.businessRegistryStatus || 'pending',
            label: 'رقم السجل التجاري',
            unifiedNumber: id.unifiedNumber || null,
            issueDate: id.crIssueDate || null,
            expiryDate: id.crExpiryDate || null,
            reference: id.crReference || null,
            capital: id.capital || null,
            warning: crWarning
        },
        nafathBusiness: {
            value: id.nafathBusinessId ? '****' + String(id.nafathBusinessId).slice(-4) : null,
            status: id.nafathBusinessStatus || 'pending',
            label: 'نفاذ أعمال'
        },
        twoFactor: {
            enabled: admin.twoFactorEnabled || false,
            method: admin.twoFactorMethod || 'none',
            label: 'المصادقة الثنائية (2FA)'
        },
        authMethods: {
            methods: admin.authMethods || [],
            count: (admin.authMethods || []).length,
            label: 'طرق المصادقة المُفعّلة'
        }
    };
    const total = 8;
    let verified = 0;
    if (checks.email.status === 'verified') verified++;
    if (checks.phone.status === 'verified') verified++;
    if (checks.recoveryEmail.status === 'verified') verified++;
    if (checks.nationalId.status === 'verified') verified++;
    if (checks.businessRegistry.status === 'verified') verified++;
    if (checks.nafathBusiness.status === 'verified') verified++;
    if (checks.twoFactor.enabled) verified++;
    if (checks.ownerName.status === 'verified') verified++;
    const percentage = Math.round((verified / total) * 100);
    res.json({
        success: true,
        owner: admin.name,
        verificationScore: percentage + '%',
        verified,
        total,
        level:
            percentage === 100
                ? 'مُوثّق بالكامل'
                : percentage >= 62
                  ? 'مُوثّق جزئياً'
                  : 'يحتاج توثيق',
        checks,
        syncEmails: admin.syncEmails || [],
        contact: c,
        quran: id.quran || '',
        hadith: id.hadith || '',
        instructions:
            percentage < 100
                ? {
                      ar: 'لإكمال التوثيق: أضف ADMIN_NATIONAL_ID و ADMIN_BUSINESS_REGISTRY و ADMIN_NAFATH_BUSINESS_ID في ملف .env ثم أعد تشغيل الخادم.',
                      steps: [
                          checks.nationalId.status !== 'verified'
                              ? 'أضف رقم الهوية الوطنية (10 أرقام) في ADMIN_NATIONAL_ID في .env'
                              : null,
                          checks.businessRegistry.status !== 'verified'
                              ? 'أضف رقم السجل التجاري في ADMIN_BUSINESS_REGISTRY في .env'
                              : null,
                          checks.nafathBusiness.status !== 'verified'
                              ? 'أضف معرّف نفاذ أعمال في ADMIN_NAFATH_BUSINESS_ID في .env'
                              : null
                      ].filter(Boolean)
                  }
                : null,
        timestamp: new Date().toISOString()
    });
});

// الإشعارات — تكامل مع لوحة التحكم والبريد والواتساب
app.get('/api/notifications', authRequired, (req, res) => {
    const list = NOTIFICATIONS.filter(n => n.userId === req.user.id).sort(
        (a, b) => new Date(b.createdAt) - new Date(a.createdAt)
    );
    const unreadCount = list.filter(n => !n.read).length;
    res.json({ success: true, notifications: list, unreadCount });
});
app.patch('/api/notifications/:id/read', authRequired, (req, res) => {
    const n = NOTIFICATIONS.find(x => x.id === req.params.id && x.userId === req.user.id);
    if (!n) return res.status(404).json({ success: false, message: 'إشعار غير موجود.' });
    n.read = true;
    saveJSON(NOTIFICATIONS_FILE, NOTIFICATIONS);
    res.json({ success: true, notification: n });
});

// ═══════════════════════════════════════════════════════════════════════════════
// 🔐 منظومة أمان الحساب — تغيير كلمة المرور + استعادة + توثيق + مصادقة
// «إِنَّ اللَّهَ يَأْمُرُكُمْ أَن تُؤَدُّوا الْأَمَانَاتِ إِلَىٰ أَهْلِهَا» — النساء ٥٨
// ═══════════════════════════════════════════════════════════════════════════════

// 🔑 تغيير كلمة المرور — من داخل لوحة التحكم
app.post('/api/auth/change-password', authRequired, (req, res) => {
    const { currentPassword, newPassword } = req.body || {};
    if (!currentPassword || !newPassword)
        return res
            .status(400)
            .json({ success: false, message: 'كلمة المرور الحالية والجديدة مطلوبتان.' });
    if (newPassword.length < 6)
        return res
            .status(400)
            .json({ success: false, message: 'كلمة المرور الجديدة يجب أن تكون 6 أحرف على الأقل.' });

    const user = USERS.find(u => u.id === req.user.id);
    if (!user) return res.status(404).json({ success: false, message: 'مستخدم غير موجود.' });
    if (!verifyPassword(currentPassword, user.passwordHash))
        return res.status(401).json({ success: false, message: 'كلمة المرور الحالية غير صحيحة.' });

    user.passwordHash = hashPassword(newPassword);
    user.passwordChangedAt = new Date().toISOString();
    user.updatedAt = new Date().toISOString();
    if (!user.securityLog) user.securityLog = [];
    user.securityLog.push({
        action: 'password_changed',
        at: new Date().toISOString(),
        hadith: 'من بدّل دينه فاقتلوه — التبديل يحتاج توثيقاً'
    });
    saveJSON(USERS_FILE, USERS);
    res.json({
        success: true,
        message: 'تم تغيير كلمة المرور بنجاح. — وَمَن يَتَّقِ اللَّهَ يَجْعَل لَّهُ مَخْرَجًا'
    });
});

// 🔐 طلب استعادة كلمة المرور (بالإيميل أو الجوال)
const PASSWORD_RESET_TOKENS = new Map();
app.post('/api/auth/forgot-password', (req, res) => {
    const { identifier } = req.body || {};
    if (!identifier)
        return res.status(400).json({ success: false, message: 'أدخل الإيميل أو رقم الجوال.' });
    const id = identifier.trim();
    const user = USERS.find(
        u =>
            String(u.phone) === id ||
            (u.email && u.email.toLowerCase() === id.toLowerCase()) ||
            (u.recoveryEmail && u.recoveryEmail.toLowerCase() === id.toLowerCase()) ||
            (u.syncEmails && u.syncEmails.some(e => e.toLowerCase() === id.toLowerCase()))
    );
    // رسالة عامة لحماية الخصوصية — لا نكشف هل الحساب موجود
    const genericMsg = 'إذا كان هذا الحساب موجوداً، تم إرسال رمز الاستعادة.';
    if (!user) return res.json({ success: true, message: genericMsg });

    const resetCode = String(100000 + Math.floor(Math.random() * 900000)); // رمز 6 أرقام
    const expires = Date.now() + 15 * 60 * 1000; // 15 دقيقة
    PASSWORD_RESET_TOKENS.set(user.id, { code: resetCode, expires, attempts: 0 });

    if (!user.securityLog) user.securityLog = [];
    user.securityLog.push({
        action: 'password_reset_requested',
        at: new Date().toISOString(),
        identifier: id.substring(0, 4) + '***'
    });
    saveJSON(USERS_FILE, USERS);

    // إرسال الرمز عبر منظومة الاتصالات (SMS + Email + واتساب)
    if (commsEngine) {
        commsEngine.sendTemplate(
            'password_reset',
            { code: resetCode, minutes: '15', to: user.email, phone: user.phone },
            ['sms', 'email']
        );
    }
    console.log('[SECURITY] رمز استعادة كلمة المرور للمستخدم ' + user.name + ': ' + resetCode);
    res.json({ success: true, message: genericMsg, _devCode: IS_LOCAL ? resetCode : undefined });
});

// التحقق من رمز الاستعادة وتعيين كلمة مرور جديدة
app.post('/api/auth/reset-password', (req, res) => {
    const { identifier, code, newPassword } = req.body || {};
    if (!identifier || !code || !newPassword)
        return res.status(400).json({ success: false, message: 'جميع الحقول مطلوبة.' });
    if (newPassword.length < 6)
        return res
            .status(400)
            .json({ success: false, message: 'كلمة المرور الجديدة يجب أن تكون 6 أحرف على الأقل.' });

    const id = identifier.trim();
    const user = USERS.find(
        u =>
            String(u.phone) === id ||
            (u.email && u.email.toLowerCase() === id.toLowerCase()) ||
            (u.recoveryEmail && u.recoveryEmail.toLowerCase() === id.toLowerCase()) ||
            (u.syncEmails && u.syncEmails.some(e => e.toLowerCase() === id.toLowerCase()))
    );
    if (!user)
        return res
            .status(400)
            .json({ success: false, message: 'رمز الاستعادة غير صحيح أو منتهي الصلاحية.' });

    const resetData = PASSWORD_RESET_TOKENS.get(user.id);
    if (!resetData)
        return res
            .status(400)
            .json({ success: false, message: 'لم يُطلب استعادة كلمة المرور. أعد الطلب.' });
    if (resetData.attempts >= 5) {
        PASSWORD_RESET_TOKENS.delete(user.id);
        return res
            .status(429)
            .json({ success: false, message: 'تجاوزت المحاولات المسموحة. أعد الطلب.' });
    }
    if (Date.now() > resetData.expires) {
        PASSWORD_RESET_TOKENS.delete(user.id);
        return res.status(400).json({ success: false, message: 'انتهت صلاحية الرمز. أعد الطلب.' });
    }
    if (String(resetData.code) !== String(code).trim()) {
        resetData.attempts++;
        return res
            .status(400)
            .json({
                success: false,
                message: 'رمز الاستعادة غير صحيح. محاولات متبقية: ' + (5 - resetData.attempts)
            });
    }

    // نجاح الاستعادة
    PASSWORD_RESET_TOKENS.delete(user.id);
    user.passwordHash = hashPassword(newPassword);
    user.passwordChangedAt = new Date().toISOString();
    user.failedLoginAttempts = 0;
    user.accountLockedUntil = null;
    user.updatedAt = new Date().toISOString();
    if (!user.securityLog) user.securityLog = [];
    user.securityLog.push({ action: 'password_reset_completed', at: new Date().toISOString() });
    saveJSON(USERS_FILE, USERS);
    res.json({ success: true, message: 'تم تعيين كلمة المرور الجديدة بنجاح. سجّل دخولك الآن.' });
});

// ═══════════════════════════════════════════════════════════════════════════════
// 🛡️ Sheikha Authenticator — منظومة مصادقة شيخة الخاصة
// «وَالَّذِينَ هُمْ لِأَمَانَاتِهِمْ وَعَهْدِهِمْ رَاعُونَ» — المؤمنون ٨
// ═══════════════════════════════════════════════════════════════════════════════
const SHEIKHA_AUTH_CODES = new Map(); // userId -> { code, expires, method }

// طلب رمز مصادقة شيخة (عند الدخول أو العمليات الحساسة)
app.post('/api/auth/sheikha-authenticator/request', (req, res) => {
    const { userId, method } = req.body || {};
    if (!userId) return res.status(400).json({ success: false, message: 'معرّف المستخدم مطلوب.' });
    const user = USERS.find(u => u.id === userId);
    if (!user) return res.status(404).json({ success: false, message: 'مستخدم غير موجود.' });

    const authMethod = method || user.twoFactorMethod || 'sheikha_auth';
    const code = String(100000 + Math.floor(Math.random() * 900000));
    const expires = Date.now() + 5 * 60 * 1000; // 5 دقائق
    SHEIKHA_AUTH_CODES.set(userId, { code, expires, method: authMethod, attempts: 0 });

    // إرسال عبر منظومة الاتصالات
    if (commsEngine) {
        const channels =
            authMethod === 'sms' ? ['sms'] : authMethod === 'email' ? ['email'] : ['sms', 'email'];
        commsEngine.sendTemplate(
            'otp',
            { code, minutes: '5', to: user.email, phone: user.phone },
            channels
        );
    }
    console.log(
        '[Sheikha Auth] رمز المصادقة لـ ' + user.name + ': ' + code + ' | طريقة: ' + authMethod
    );
    res.json({
        success: true,
        message: 'تم إرسال رمز المصادقة.',
        method: authMethod,
        expiresIn: 300,
        _devCode: IS_LOCAL ? code : undefined
    });
});

// التحقق من رمز مصادقة شيخة
app.post('/api/auth/sheikha-authenticator/verify', (req, res) => {
    const { userId, code } = req.body || {};
    if (!userId || !code)
        return res.status(400).json({ success: false, message: 'المعرّف والرمز مطلوبان.' });

    const authData = SHEIKHA_AUTH_CODES.get(userId);
    if (!authData) return res.status(400).json({ success: false, message: 'لم يُطلب رمز مصادقة.' });
    if (authData.attempts >= 5) {
        SHEIKHA_AUTH_CODES.delete(userId);
        return res.status(429).json({ success: false, message: 'تجاوزت المحاولات. أعد الطلب.' });
    }
    if (Date.now() > authData.expires) {
        SHEIKHA_AUTH_CODES.delete(userId);
        return res.status(400).json({ success: false, message: 'انتهت صلاحية الرمز.' });
    }
    if (String(authData.code) !== String(code).trim()) {
        authData.attempts++;
        return res.status(400).json({ success: false, message: 'رمز غير صحيح.' });
    }

    SHEIKHA_AUTH_CODES.delete(userId);
    const user = USERS.find(u => u.id === userId);
    if (user) {
        if (!user.securityLog) user.securityLog = [];
        user.securityLog.push({
            action: '2fa_verified',
            at: new Date().toISOString(),
            method: authData.method
        });
        saveJSON(USERS_FILE, USERS);
    }
    res.json({ success: true, message: 'تم التحقق بنجاح.', verified: true });
});

