function calculateSecurityScore(user) {
    let score = 0;
    if (user.passwordHash) score += 15;
    if (user.twoFactorEnabled) score += 20;
    if (user.nafathVerified) score += 20;
    if (user.identity?.businessRegistryStatus === 'verified') score += 15;
    if (user.recoveryEmail) score += 10;
    if ((user.authMethods || []).length >= 3) score += 10;
    if (user.passwordChangedAt) score += 10;
    return Math.min(100, score);
}

