app.post('/api/auth/apple/callback', express.urlencoded({ extended: true }), async (req, res) => {
    const base = getBaseUrl(req);
    const { code, id_token, user: userJson } = req.body || {};
    const errorMsg = req.body && req.body.error ? req.body.error : null;
    if (errorMsg) return redirectWithToken(res, base, null, 'فشل الدخول بأبل.');
    if (!code && !id_token) return redirectWithToken(res, base, null, 'لم يُستلم رمز من أبل.');
    try {
        let sub = null;
        let name = '';
        let email = '';
        if (id_token) {
            const parts = (id_token || '').split('.');
            if (parts[1]) {
                const payload = JSON.parse(Buffer.from(parts[1], 'base64url').toString());
                sub = payload.sub;
                email = payload.email || '';
            }
        }
        if (userJson)
            try {
                const u = JSON.parse(userJson);
                name =
                    u.name && (u.name.firstName || u.name.lastName)
                        ? [u.name.firstName, u.name.lastName].filter(Boolean).join(' ')
                        : name;
            } catch (_) {}
        if (!sub) return redirectWithToken(res, base, null, 'فشل التحقق من أبل.');
        const user = findOrCreateOAuthUser('apple', sub, { name: name || email || sub, email });
        const token = jwt.sign({ userId: user.id }, JWT_SECRET, { expiresIn: '7d' });
        redirectWithToken(res, base, token);
    } catch (e) {
        redirectWithToken(res, base, null, 'خطأ في التحقق من أبل.');
    }
});

