app.patch('/api/me', authRequired, (req, res) => {
    const { storeName, region, marketingEnabled } = req.body || {};
    const user = USERS.find(u => u.id === req.user.id);
    if (!user) return res.status(404).json({ success: false, message: 'مستخدم غير موجود.' });
    if (storeName !== undefined) user.storeName = String(storeName).trim();
    if (region !== undefined) user.region = String(region).trim();
    if (marketingEnabled !== undefined) user.marketingEnabled = !!marketingEnabled;
    saveJSON(USERS_FILE, USERS);
    const t = TRADERS.find(x => x.id === user.id);
    if (t) {
        t.name = user.name;
        t.region = user.region;
        t.company = user.storeName;
        saveJSON(TRADERS_FILE, TRADERS);
    }
    logOperation(
        'user_update',
        'user',
        { id: user.id, storeName: user.storeName, region: user.region },
        user
    );
    const out = {
        id: user.id,
        phone: user.phone,
        name: user.name,
        email: user.email,
        storeName: user.storeName,
        region: user.region,
        marketingEnabled: user.marketingEnabled
    };
    res.json({ success: true, user: out, message: 'تم تحديث البيانات.' });
});

