app.post('/api/traders/register', (req, res) => {
    const { name, email, phone, region, company, specialty } = req.body || {};
    if (!name || !phone)
        return res.status(400).json({ success: false, message: 'الاسم والهاتف مطلوبان.' });
    const nameCheck = validateName(name);
    if (!nameCheck.valid)
        return res.status(400).json({ success: false, message: nameCheck.message });
    const emailCheck = validateEmail(email);
    if (!emailCheck.valid)
        return res.status(400).json({ success: false, message: emailCheck.message });
    const id = uuidv4();
    const spec = getSpecialty((specialty || '').trim() || 'metals_trader');
    const trader = {
        id,
        name: nameCheck.value,
        email: emailCheck.value,
        phone: String(phone).trim(),
        region: (region || '').trim(),
        company: (company || nameCheck.value).trim(),
        specialty: spec.id,
        specialtyLabel: spec.nameAr,
        createdAt: new Date().toISOString()
    };
    TRADERS.push(trader);
    saveJSON(TRADERS_FILE, TRADERS);
    logOperation(
        'trader_register',
        'trader',
        { id, name: trader.name, phone: trader.phone, region: trader.region },
        trader
    );
    res.status(201).json({
        success: true,
        trader: { ...trader, storeLabel: spec.storeLabel },
        message: 'تم تسجيل التاجر بنجاح. متجرك حسب تخصصك: ' + spec.storeLabel + '.'
    });
});

