app.post('/api/listings', (req, res) => {
    const {
        traderId,
        traderPhone,
        name,
        quantity,
        unit,
        price,
        currency,
        description,
        weight,
        hsCode,
        locationAddress,
        locationLat,
        locationLng,
        proofOfOwnership,
        supplyChainStage,
        scrapType
    } = req.body || {};
    if (!name) return res.status(400).json({ success: false, message: 'اسم البضاعة مطلوب.' });
    let storeName = 'تاجر',
        storeRegion = '',
        traderSpecialty = null;
    if (traderId) {
        const t = TRADERS.find(x => x.id === traderId);
        if (t) {
            storeName = t.name;
            storeRegion = t.region;
            traderSpecialty = t.specialty;
        }
    } else if (traderPhone) {
        const t = TRADERS.find(x => x.phone === String(traderPhone).trim());
        if (t) {
            storeName = t.name;
            storeRegion = t.region;
            traderSpecialty = t.specialty;
        } else {
            storeName = 'تاجر (هاتف: ' + traderPhone + ')';
        }
    }
    const ac = autoCategory(name);
    const cat = hsCode
        ? getHSCategory(hsCode)
        : { id: ac.id, nameAr: ac.name, icon: getHSCategory(ac.id).icon };
    const stage = getStage(
        supplyChainStage || (traderSpecialty ? getSpecialty(traderSpecialty).stage : 'source')
    );
    const scrapDisplay = getScrapDisplayType(scrapType || 'collection');
    const lid = uuidv4();
    const listing = {
        id: lid,
        traderId: traderId || null,
        traderPhone: traderPhone || null,
        storeName,
        storeRegion,
        name,
        quantity: quantity || '',
        unit: unit || 'طن',
        price: price || '',
        currency: currency || 'ريال',
        category: cat.id,
        categoryName: cat.nameAr || cat.name,
        hsCode: cat.id,
        description: (description || '').trim(),
        weight: weight || '',
        locationAddress: (locationAddress || '').trim(),
        locationLat: locationLat || null,
        locationLng: locationLng || null,
        proofOfOwnership: (proofOfOwnership || '').trim(),
        supplyChainStage: stage.id,
        scrapType: scrapDisplay.id,
        createdAt: new Date().toISOString()
    };
    LISTINGS.push(listing);
    saveJSON(LISTINGS_FILE, LISTINGS);
    logOperation(
        'listing_add',
        'listing',
        {
            id: lid,
            name: listing.name,
            price: listing.price,
            quantity: listing.quantity,
            storeName: listing.storeName
        },
        listing
    );
    res.status(201).json({
        success: true,
        listing: { ...listing, icon: cat.icon },
        message: 'تم تسجيل المنتج وعرض البضاعة بنجاح.'
    });
});

