function categoryName(id) {
    const c = SCRAP_CATEGORIES.find(x => x.id === id);
    return c ? c.name : 'أخرى';
}

// تحويل نص إلى رقم (للكمية، السعر، الوزن)
function toNum(s) {
    const n = parseFloat(String(s || '').replace(/[^\d.-]/g, ''));
    return isNaN(n) ? 0 : n;
}

// ═══════════════════════════════════════════════════════════════════════════════
// نظام معرفة الكميات الكاملة — حسب المتجر، النوع (نفس الخواص)، والمنطقة الجغرافية
// ═══════════════════════════════════════════════════════════════════════════════
app.get('/api/quantities-by-store', (req, res) => {
    const stores = TRADERS.map(t => {
        const list = LISTINGS.filter(l => l.traderId === t.id || l.traderPhone === t.phone);
        const byType = {};
        let totalQuantity = 0,
            totalWeight = 0,
            totalValue = 0;
        list.forEach(l => {
            const key = [
                l.category || l.hsCode || 'other',
                l.supplyChainStage || 'source',
                l.scrapType || 'collection'
            ].join('|');
            if (!byType[key])
                byType[key] = {
                    category: l.category,
                    supplyChainStage: l.supplyChainStage,
                    scrapType: l.scrapType,
                    count: 0,
                    quantity: 0,
                    weight: 0,
                    value: 0,
                    unit: l.unit
                };
            const q = toNum(l.quantity);
            const w = toNum(l.weight);
            const p = toNum(l.price);
            byType[key].count++;
            byType[key].quantity += q;
            byType[key].weight += w;
            byType[key].value += p * (q || 1);
            totalQuantity += q;
            totalWeight += w;
            totalValue += p * (q || 1);
        });
        return {
            traderId: t.id,
            storeName: t.name,
            region: t.region || '',
            specialty: t.specialty,
            listingsCount: list.length,
            byType: Object.values(byType),
            totalQuantity,
            totalWeight,
            totalValue,
            valueDescription: { count: list.length, totalQuantity, totalWeight, totalValue }
        };
    });
    res.json({ success: true, byStore: stores });
});

app.get('/api/quantities-by-type', (req, res) => {
    const region = (req.query.region || '').trim().toLowerCase();
    let list = LISTINGS;
    if (region) list = list.filter(l => (l.storeRegion || '').toLowerCase() === region);
    const byType = {};
    list.forEach(l => {
        const key = [
            l.category || l.hsCode || 'other',
            l.supplyChainStage || 'source',
            l.scrapType || 'collection'
        ].join('|');
        if (!byType[key])
            byType[key] = {
                category: l.category,
                categoryName: (getHSCategory(l.category || l.hsCode) || {}).nameAr,
                supplyChainStage: l.supplyChainStage,
                scrapType: l.scrapType,
                count: 0,
                stores: new Set(),
                quantity: 0,
                weight: 0,
                value: 0
            };
        const q = toNum(l.quantity);
        const w = toNum(l.weight);
        const p = toNum(l.price);
        byType[key].count++;
        byType[key].stores.add(l.traderId || l.traderPhone || l.storeName);
        byType[key].quantity += q;
        byType[key].weight += w;
        byType[key].value += p * (q || 1);
    });
    const result = Object.values(byType).map(x => ({
        category: x.category,
        categoryName: x.categoryName,
        supplyChainStage: x.supplyChainStage,
        scrapType: x.scrapType,
        listingsCount: x.count,
        storesCount: x.stores.size,
        totalQuantity: x.quantity,
        totalWeight: x.weight,
        totalValue: x.value,
        valueDescription: {
            count: x.count,
            storesCount: x.stores.size,
            totalQuantity: x.quantity,
            totalWeight: x.weight,
            totalValue: x.value
        }
    }));
    res.json({ success: true, byType: result, region: region || null });
});

app.get('/api/quantities-by-region', (req, res) => {
    const byRegion = {};
    LISTINGS.forEach(l => {
        const reg = (l.storeRegion || '').trim() || 'غير محدد';
        if (!byRegion[reg])
            byRegion[reg] = {
                region: reg,
                stores: new Set(),
                count: 0,
                quantity: 0,
                weight: 0,
                value: 0,
                byType: {}
            };
        const q = toNum(l.quantity);
        const w = toNum(l.weight);
        const p = toNum(l.price);
        byRegion[reg].stores.add(l.traderId || l.traderPhone || l.storeName);
        byRegion[reg].count++;
        byRegion[reg].quantity += q;
        byRegion[reg].weight += w;
        byRegion[reg].value += p * (q || 1);
        const key = [
            l.category || 'other',
            l.supplyChainStage || 'source',
            l.scrapType || 'collection'
        ].join('|');
        if (!byRegion[reg].byType[key])
            byRegion[reg].byType[key] = { count: 0, quantity: 0, weight: 0, value: 0 };
        byRegion[reg].byType[key].count++;
        byRegion[reg].byType[key].quantity += q;
        byRegion[reg].byType[key].weight += w;
        byRegion[reg].byType[key].value += p * (q || 1);
    });
    const result = Object.values(byRegion).map(x => ({
        region: x.region,
        storesCount: x.stores.size,
        listingsCount: x.count,
        totalQuantity: x.quantity,
        totalWeight: x.weight,
        totalValue: x.value,
        byType: Object.values(x.byType),
        valueDescription: {
            count: x.count,
            storesCount: x.stores.size,
            totalQuantity: x.quantity,
            totalWeight: x.weight,
            totalValue: x.value
        }
    }));
    res.json({ success: true, byRegion: result });
});

app.get('/api/resource-summary', (req, res) => {
    const byStore = TRADERS.map(t => {
        const list = LISTINGS.filter(l => l.traderId === t.id || l.traderPhone === t.phone);
        let q = 0,
            w = 0,
            v = 0;
        list.forEach(l => {
            q += toNum(l.quantity);
            w += toNum(l.weight);
            v += toNum(l.price) * (toNum(l.quantity) || 1);
        });
        return {
            traderId: t.id,
            storeName: t.name,
            region: t.region || '',
            listingsCount: list.length,
            totalQuantity: q,
            totalWeight: w,
            totalValue: v
        };
    });
    const byType = {};
    LISTINGS.forEach(l => {
        const key = [
            l.category || 'other',
            l.supplyChainStage || 'source',
            l.scrapType || 'collection'
        ].join('|');
        if (!byType[key])
            byType[key] = {
                category: l.category,
                supplyChainStage: l.supplyChainStage,
                scrapType: l.scrapType,
                count: 0,
                quantity: 0,
                weight: 0,
                value: 0
            };
        byType[key].count++;
        byType[key].quantity += toNum(l.quantity);
        byType[key].weight += toNum(l.weight);
        byType[key].value += toNum(l.price) * (toNum(l.quantity) || 1);
    });
    const byRegion = {};
    LISTINGS.forEach(l => {
        const reg = (l.storeRegion || '').trim() || 'غير محدد';
        if (!byRegion[reg])
            byRegion[reg] = { region: reg, count: 0, quantity: 0, weight: 0, value: 0 };
        byRegion[reg].count++;
        byRegion[reg].quantity += toNum(l.quantity);
        byRegion[reg].weight += toNum(l.weight);
        byRegion[reg].value += toNum(l.price) * (toNum(l.quantity) || 1);
    });
    res.json({
        success: true,
        byStore,
        byType: Object.values(byType),
        byRegion: Object.values(byRegion),
        totals: {
            stores: TRADERS.length,
            listings: LISTINGS.length,
            totalQuantity: byStore.reduce((s, x) => s + x.totalQuantity, 0),
            totalWeight: byStore.reduce((s, x) => s + x.totalWeight, 0),
            totalValue: byStore.reduce((s, x) => s + x.totalValue, 0)
        }
    });
});

// ═══════════════════════════════════════════════════════════════════════════════
// عروض السوق - بيانات حقيقية فقط (لا توجد بيانات وهمية)
