// ═══════════════════════════════════════════════════════════════════════════════
// API للسوق - عرض المنتجات الحقيقية للصفحة الرئيسية
// ═══════════════════════════════════════════════════════════════════════════════
app.get('/api/market/products', (req, res) => {
    const market = (req.query.market || '').toLowerCase();
    const chapter = (req.query.chapter || '').toLowerCase();
    const heading = (req.query.heading || '').toLowerCase();
    const region = (req.query.region || '').toLowerCase();
    const search = (req.query.search || '').toLowerCase();

    // جلب المنتجات الحقيقية من قاعدة البيانات
    let products = LISTINGS.filter(l => l.status !== 'deleted').map(l => {
        const hs = getHSCategory(l.hsCode || l.category);
        const st = getStage(l.supplyChainStage);
        const trader = TRADERS.find(t => t.id === l.traderId);
        const user = USERS.find(u => u.id === l.traderId);

        return {
            id: l.id,
            name: l.name,
            description: l.description || '',
            quantity: l.quantity || 0,
            unit: l.unit || 'طن',
            price: Number(l.price) || 0,
            currency: l.currency || 'ريال',
            category: l.categoryName || hs.nameAr,
            hs: l.hsCode || hs.id,
            icon: hs.icon,
            badge: l.categoryName || hs.nameAr,
            location: l.storeRegion || l.locationAddress || 'غير محدد',
            quality: l.quality || 'جيد',
            seller: l.storeName || (trader ? trader.name : 'تاجر'),
            sellerId: l.traderId,
            verified: trader ? true : false,
            rating: trader?.rating || null,
            // بيانات المصنع
            supplyType: l.supplyType || 'stock',
            bulkAvailable: l.supplyType === 'factory' || l.supplyType === 'continuous',
            storeCapacity:
                l.supplyType === 'factory' || l.supplyType === 'continuous'
                    ? {
                          daily: l.dailyCapacity || '—',
                          monthly: l.monthlyCapacity || '—',
                          available: l.quantity || '—'
                      }
                    : null,
            // بيانات الشحن
            delivery: l.delivery || 'pickup',
            transportTypes: l.transportTypes || [],
            shippingCost: l.shippingCost || 'buyer',
            // خصم الكميات
            hasBulkDiscount: l.hasBulkDiscount || false,
            bulkQty: l.bulkQty || null,
            bulkDiscount: l.bulkDiscount || null,
            createdAt: l.createdAt
        };
    });

    // الفلترة حسب السوق (metals, scrap, precious)
    if (market === 'metals') {
        products = products.filter(
            p =>
                [
                    'iron',
                    'copper',
                    'aluminum',
                    'stainless',
                    '7204',
                    '7404',
                    '7602',
                    '8002'
                ].includes(p.hs) ||
                p.hs.startsWith('72') ||
                p.hs.startsWith('73') ||
                p.hs.startsWith('74') ||
                p.hs.startsWith('75') ||
                p.hs.startsWith('76')
        );
    } else if (market === 'scrap') {
        products = products.filter(
            p =>
                ['7204', '7404', '7602', '8002', '8548', '8549'].includes(p.hs) ||
                p.category.includes('سكراب') ||
                p.category.includes('نفايات')
        );
    } else if (market === 'precious') {
        products = products.filter(
            p =>
                p.hs.startsWith('71') ||
                p.category.includes('ذهب') ||
                p.category.includes('فضة') ||
                p.category.includes('بلاتين')
        );
    }

    // الفلترة حسب الفصل
    if (chapter) {
        products = products.filter(p => p.hs.startsWith(chapter));
    }

    // الفلترة حسب البند
    if (heading) {
        products = products.filter(p => p.hs === heading || p.hs.startsWith(heading));
    }

    // الفلترة حسب المنطقة
    if (region) {
        products = products.filter(p => p.location.toLowerCase().includes(region));
    }

    // البحث النصي
    if (search) {
        products = products.filter(
            p =>
                p.name.toLowerCase().includes(search) ||
                p.description.toLowerCase().includes(search) ||
                p.category.toLowerCase().includes(search) ||
                p.seller.toLowerCase().includes(search)
        );
    }

    // ترتيب حسب الأحدث
    products.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));

    res.json({
        success: true,
        products,
        count: products.length,
        totalListings: LISTINGS.length,
        totalTraders: TRADERS.length
    });
});

// ═══════════════════════════════════════════════════════════════════════════════
// API تفاصيل منتج واحد — «التَّاجِرُ الصَّدُوقُ الأَمِين»
// ═══════════════════════════════════════════════════════════════════════════════
app.get('/api/products/:id', (req, res) => {
    const id = req.params.id;
    const listing = LISTINGS.find(l => String(l.id) === String(id) && l.status !== 'deleted');
    if (!listing) return res.status(404).json({ success: false, message: 'المنتج غير موجود' });

    const hs = getHSCategory(listing.hsCode || listing.category);
    const trader = TRADERS.find(t => t.id === listing.traderId);
    const user = USERS.find(u => u.id === listing.traderId);

    // تقييم التاجر — نظام الصدق والأمانة
    const traderOrders = []; // TODO: من جدول الطلبات
    const trustScore = trader
        ? {
              overall: trader.rating || 4.2,
              honesty: trader.rating ? Math.min(5, trader.rating + 0.1) : 4.3, // الصدق
              trustworthiness: trader.rating ? Math.min(5, trader.rating) : 4.2, // الأمانة
              quality: trader.rating ? Math.min(5, trader.rating - 0.1) : 4.1, // جودة المنتج
              delivery: trader.rating ? Math.min(5, trader.rating + 0.05) : 4.15, // الالتزام بالتسليم
              totalReviews: Math.floor(Math.random() * 50) + 5,
              verified: !!trader,
              badge:
                  (trader?.rating || 4.2) >= 4.5
                      ? 'التاجر الصدوق الأمين'
                      : (trader?.rating || 4.2) >= 3.5
                        ? 'تاجر موثوق'
                        : 'تاجر جديد',
              hadith: '«التَّاجِرُ الصَّدُوقُ الأَمِينُ مَعَ النَّبِيِّينَ وَالصِّدِّيقِينَ وَالشُّهَدَاءِ» — رواه الترمذي'
          }
        : null;

    // معايير جودة المنتج
    const qualityStandards = {
        declared: listing.quality || 'جيد',
        purityMatch: true,
        certifications: listing.proofOfOwnership ? ['إثبات ملكية'] : [],
        hsVerified: !!listing.hsCode,
        shariaCompliant: true,
        quranReference: '﴿ وَأَوْفُوا الْكَيْلَ وَالْمِيزَانَ بِالْقِسْطِ ﴾ — الأنعام: 152'
    };

    // عروض تجار آخرين لنفس الفئة
    const similarOffers = LISTINGS.filter(
        l =>
            l.status !== 'deleted' &&
            String(l.id) !== String(id) &&
            (l.categoryName === listing.categoryName ||
                l.hsCode === listing.hsCode ||
                l.category === listing.category)
    )
        .slice(0, 5)
        .map(l => {
            const offerTrader = TRADERS.find(t => t.id === l.traderId);
            return {
                id: l.id,
                name: l.name,
                price: Number(l.price) || 0,
                currency: l.currency || 'ريال',
                unit: l.unit || 'طن',
                quantity: l.quantity,
                seller: l.storeName || (offerTrader ? offerTrader.name : 'تاجر'),
                location: l.storeRegion || l.locationAddress || 'غير محدد',
                verified: !!offerTrader,
                rating: offerTrader?.rating || null
            };
        });

    // إحصائيات
    listing.views = (listing.views || 0) + 1;
    saveJSON(LISTINGS_FILE, LISTINGS);

    res.json({
        success: true,
        product: {
            id: listing.id,
            name: listing.name,
            description: listing.description || '',
            quantity: listing.quantity || 0,
            unit: listing.unit || 'طن',
            price: Number(listing.price) || 0,
            currency: listing.currency || 'ريال',
            priceType: listing.priceType || 'fixed',
            category: listing.categoryName || hs.nameAr,
            hs: listing.hsCode || hs.id,
            quality: listing.quality || 'جيد',
            location: listing.storeRegion || listing.locationAddress || 'غير محدد',
            delivery: listing.delivery || 'pickup',
            transportTypes: listing.transportTypes || [],
            shippingCost: listing.shippingCost || 'buyer',
            minOrder: listing.minOrder,
            notes: listing.notes || '',
            supplyType: listing.supplyType || 'stock',
            dailyCapacity: listing.dailyCapacity,
            monthlyCapacity: listing.monthlyCapacity,
            leadTime: listing.leadTime,
            hasBulkDiscount: listing.hasBulkDiscount || false,
            bulkQty: listing.bulkQty,
            bulkDiscount: listing.bulkDiscount,
            views: listing.views || 0,
            inquiries: listing.inquiries || 0,
            createdAt: listing.createdAt
        },
        seller: {
            id: listing.traderId,
            name: listing.storeName || (trader ? trader.name : 'تاجر'),
            region: listing.storeRegion || 'غير محدد',
            verified: !!trader,
            trust: trustScore
        },
        qualityStandards,
        similarOffers,
        totalSimilar: similarOffers.length
    });

});

// ═══════════════════════════════════════════════════════════════════════════════
// API طلب عرض سعر (RFQ)
// ═══════════════════════════════════════════════════════════════════════════════
const SHEIKHA_COUNTRY_TREATY_PROFILES = {
    SA: {
        name: 'المملكة العربية السعودية',
        region: 'gcc',
        treaties: {
            AE: ['gcc-common-market', 'customs-cooperation'],
            BH: ['gcc-common-market'],
            KW: ['gcc-common-market'],
            OM: ['gcc-common-market'],
            QA: ['gcc-common-market'],
            EG: ['gafta-trade'],
            JO: ['gafta-trade'],
            US: ['investment-framework'],
            GB: ['investment-framework']
        }
    },
    AE: { name: 'الإمارات', region: 'gcc', treaties: { SA: ['gcc-common-market'] } },
    EG: { name: 'مصر', region: 'mena', treaties: { SA: ['gafta-trade'] } },
    JO: { name: 'الأردن', region: 'mena', treaties: { SA: ['gafta-trade'] } },
    US: { name: 'الولايات المتحدة', region: 'global', treaties: { SA: ['investment-framework'] } },
    GB: { name: 'المملكة المتحدة', region: 'global', treaties: { SA: ['investment-framework'] } },
    CN: { name: 'الصين', region: 'global', treaties: {} },
    IN: { name: 'الهند', region: 'global', treaties: {} }
};

const SHEIKHA_TREATY_PACKS = {
    'gcc-common-market': {
        name: 'السوق الخليجية المشتركة',
        requirements: ['تسهيل التجارة البينية', 'توثيق المنشأ', 'الامتثال الجمركي الخليجي'],
        controls: ['شفافية التسعير', 'توثيق المواصفات', 'منع الغش التجاري']
    },
    'customs-cooperation': {
        name: 'تعاون جمركي',
        requirements: ['تصنيف HS صحيح', 'بيانات شحن دقيقة', 'التزام المنافذ الجمركية'],
        controls: ['إقرار بيانات صحيح', 'عدم تضليل المنشأ']
    },
    'gafta-trade': {
        name: 'منطقة التجارة العربية الحرة',
        requirements: ['شهادة منشأ عربية', 'التزام المواصفات المعتمدة', 'إفصاح تكاليف النقل'],
        controls: ['حماية المستهلك', 'منع الممارسات الاحتكارية']
    },
    'investment-framework': {
        name: 'إطار تعاون استثماري',
        requirements: ['توثيق الالتزامات التعاقدية', 'التزامات امتثال دولي', 'حوكمة المخاطر'],
        controls: ['شفافية الإفصاح', 'عدالة الإجراءات', 'حماية سرية البيانات']
    }
};

function normalizeCountryCode(input) {
    return String(input || 'SA')
        .trim()
        .toUpperCase();
}

function resolveUserSegment(userType) {
    const key = String(userType || '')
        .trim()
        .toLowerCase();
    if (key === 'muslim' || key === 'مسلم') return 'muslim';
    if (key === 'treaty' || key === 'معاهد') return 'treaty';
    return 'non-muslim';
}

function uniqueArray(values) {
    return Array.from(new Set((values || []).filter(Boolean)));
}

function buildTreatyResolution({ homeCountry, userCountry, targetCountry, userType }) {
    const home = normalizeCountryCode(homeCountry || 'SA');
    const user = normalizeCountryCode(userCountry || home);
    const target = normalizeCountryCode(targetCountry || home);
    const segment = resolveUserSegment(userType);
    const mode = user === target ? 'domestic' : 'international';

    const userProfile = SHEIKHA_COUNTRY_TREATY_PROFILES[user] || { treaties: {}, name: user };
    const targetProfile = SHEIKHA_COUNTRY_TREATY_PROFILES[target] || { treaties: {}, name: target };
    const directTreaties = uniqueArray(
        (userProfile.treaties && userProfile.treaties[target]) || []
    );
    const reverseTreaties = uniqueArray(
        (targetProfile.treaties && targetProfile.treaties[user]) || []
    );
    const treatyKeys = uniqueArray(directTreaties.concat(reverseTreaties));

    const packs = treatyKeys.map(key => SHEIKHA_TREATY_PACKS[key]).filter(Boolean);
    const legalRequirements = uniqueArray(packs.flatMap(pack => pack.requirements || []));
    const operationalControls = uniqueArray(packs.flatMap(pack => pack.controls || []));

    // بوابة الشريعة: تمنع البنود المخالفة الصريحة فقط وتستثني عبارات المنع الوقائي مثل "منع الغش".
    const prohibitedKeywords = [
        'فوائد ربوية',
        'ربوية',
        'interest-bearing',
        'riba',
        'غرر فاحش',
        'gharar',
        'gambling',
        'maysir',
        'قمار',
        'احتكار إلزامي',
        'غش متعمد'
    ];
    const allTexts = legalRequirements.concat(operationalControls).join(' | ').toLowerCase();
    const blockedClauses = prohibitedKeywords.filter(key =>
        allTexts.includes(String(key).toLowerCase())
    );

    return {
        homeCountry: home,
        userCountry: user,
        targetCountry: target,
        mode,
        userSegment: segment,
        treaties: packs.map(pack => pack.name),
        legalRequirements,
        operationalControls,
        shariaValidation: {
            status: blockedClauses.length ? 'blocked' : 'approved',
            blockedClauses,
            rules: [
                'لا ربا',
                'لا غرر',
                'لا غش',
                'لا احتكار',
                'التراضي والشفافية',
                'الالتزام بالكتاب والسنة'
            ]
        },
        notes: [
            'التفعيل الآلي استرشادي ويخضع لاعتماد الجهة القانونية والتنظيمية المعتمدة.',
            'أي بند يخالف الشريعة يُستبعد تلقائياً من المسار التنفيذي.'
        ]
    };
}

app.get('/api/sheikha/compliance/treaty-resolution', (req, res) => {
    const resolution = buildTreatyResolution({
        homeCountry: req.query.homeCountry,
        userCountry: req.query.userCountry,
        targetCountry: req.query.targetCountry,
        userType: req.query.userType
    });

    res.json({
        success: true,
        data: resolution,
        message: 'تم توليد تفعيل المعاهدات والتشريعات تلقائياً مع فلترة شرعية بالكتاب والسنة',
        timestamp: new Date().toISOString()
    });
});

app.post('/api/rfq', (req, res) => {
    const {
        productId,
        quantity,
        notes,
        contact,
        userCountry,
        targetCountry,
        userType,
        homeCountry
    } = req.body;
    if (!productId) return res.status(400).json({ success: false, message: 'حدد المنتج' });

    const listing = LISTINGS.find(l => String(l.id) === String(productId));
    if (!listing) return res.status(404).json({ success: false, message: 'المنتج غير موجود' });

    const treatyResolution = buildTreatyResolution({
        homeCountry: homeCountry || 'SA',
        userCountry,
        targetCountry,
        userType
    });

    if (treatyResolution.shariaValidation.status === 'blocked') {
        return res.status(400).json({
            success: false,
            message: 'تعذر تنفيذ الطلب: توجد بنود تنظيمية/تعاقدية متعارضة مع الشريعة.',
            data: treatyResolution,
            timestamp: new Date().toISOString()
        });
    }

    listing.inquiries = (listing.inquiries || 0) + 1;
    saveJSON(LISTINGS_FILE, LISTINGS);

    res.json({
        success: true,
        message: 'تم إرسال طلب عرض السعر بنجاح — سيتم الرد خلال 24 ساعة بإذن الله',
        rfq: {
            id: 'RFQ-' + Date.now().toString(36).toUpperCase(),
            productId,
            productName: listing.name,
            quantity: quantity || 'غير محدد',
            notes: notes || '',
            compliance: treatyResolution,
            status: 'pending',
            createdAt: new Date().toISOString()
        }
    });
});

// ═══════════════════════════════════════════════════════════════════════════════
// API للعرض حسب مرحلة سلسلة التوريد
// ═══════════════════════════════════════════════════════════════════════════════
app.get('/api/market-by-stage', (req, res) => {
    const stage = (req.query.stage || '').toLowerCase();

    let listings = LISTINGS.filter(l => l.status !== 'deleted');

    // فلترة حسب مرحلة سلسلة التوريد
    if (stage && stage !== 'all') {
        listings = listings.filter(l => {
            const traderStage = l.supplyChainStage || '';
            const trader = TRADERS.find(t => t.id === l.traderId);
            const traderSpecialty = trader?.specialty || '';

            // التطابق المباشر أو حسب تخصص التاجر
            return (
                traderStage === stage ||
                traderSpecialty === stage ||
                (stage === 'source' && ['source', 'mine', 'factory'].includes(traderStage)) ||
                (stage === 'collection' &&
                    ['collection', 'collector', 'gatherer'].includes(traderStage)) ||
                (stage === 'transport' &&
                    ['transport', 'trucks', 'shipping'].includes(traderSpecialty)) ||
                (stage === 'smelter' && ['smelter', 'refinery'].includes(traderStage)) ||
                (stage === 'manufacturing' &&
                    ['manufacturing', 'factory', 'producer'].includes(traderStage)) ||
                (stage === 'end' && ['retail', 'end', 'consumer'].includes(traderStage))
            );
        });
    }

    const result = listings.map(l => {
        const hs = getHSCategory(l.hsCode || l.category);
        const st = getStage(l.supplyChainStage);
        const trader = TRADERS.find(t => t.id === l.traderId);

        return {
            id: l.id,
            name: l.name,
            description: l.description,
            quantity: l.quantity,
            unit: l.unit,
            price: l.price,
            currency: l.currency,
            storeName: trader?.company || l.storeName || 'متجر',
            storeRegion: trader?.region || l.storeRegion || 'السعودية',
            categoryName: l.categoryName || hs.nameAr,
            scrapTypeName: l.scrapTypeName || '',
            hsCode: l.hsCode || hs.id,
            icon: hs.icon,
            supplyChainStage: l.supplyChainStage || trader?.specialty || 'general',
            stageName: st.nameAr,
            quality: l.quality,
            createdAt: l.createdAt
        };
    });

    // ترتيب حسب الأحدث
    result.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));

    res.json({
        success: true,
        stage: stage || 'all',
        listings: result,
        count: result.length
    });
});

