// مؤشر شيخة للمعادن (SMI) - النسخة المتقدمة
function calculateAdvancedSMI() {
    const weights = {
        iron_rebar: 0.35,
        aluminum_pure: 0.2,
        copper_1: 0.15,
        gold_24k: 0.15,
        stainless_304: 0.1,
        silver_999: 0.05
    };

    const baseValues = {
        iron_rebar: 2400,
        aluminum_pure: 9500,
        copper_1: 32000,
        gold_24k: 280,
        stainless_304: 8500,
        silver_999: 3.8
    };

    let index = 0;
    for (const [metal, weight] of Object.entries(weights)) {
        const current =
            SHEIKHA_REFERENCE_PRICES?.basemetals?.[metal]?.sheikha ||
            SHEIKHA_REFERENCE_PRICES?.precious?.[metal]?.sheikha ||
            baseValues[metal];
        const base = baseValues[metal];
        index += (current / base) * weight * 1000;
    }

    return Math.round(index);
}

// حساب سعر شيخة العادل
function calculateSheikhaFairPrice(metal, region = 'السعودية', quality = 'B', quantity = 1) {
    // البحث عن المعدن في كل الفئات
    let metalData =
        SHEIKHA_REFERENCE_PRICES.basemetals[metal] ||
        SHEIKHA_REFERENCE_PRICES.precious[metal] ||
        SHEIKHA_REFERENCE_PRICES.scrap[metal];

    if (!metalData) {
        return { error: 'معدن غير معروف', metal };
    }

    const regionData =
        SHEIKHA_PRICING_SYSTEM.regionFactors[region] ||
        SHEIKHA_PRICING_SYSTEM.regionFactors['أخرى'];
    const qualityData =
        SHEIKHA_PRICING_SYSTEM.qualityFactors[quality] ||
        SHEIKHA_PRICING_SYSTEM.qualityFactors['B'];

    const basePrice = metalData.sheikha;
    const regionFactor = regionData.factor;
    const qualityFactor = qualityData.factor;

    const fairPrice = Math.round(basePrice * regionFactor * qualityFactor);
    const totalPrice = fairPrice * quantity;

    return {
        metal: metalData.nameAr,
        metalEn: metalData.nameEn,
        unit: metalData.unit,
        quantity,
        region,
        regionFactor,
        quality,
        qualityFactor,
        basePrice,
        fairPricePerUnit: fairPrice,
        totalPrice,
        currency: 'SAR',
        hsCode: metalData.hsCode,
        isri: metalData.isri,
        sources: {
            lme: metalData.lme,
            comex: metalData.comex,
            sheikha: metalData.sheikha
        }
    };
}

