// حساب تكلفة النقل الداخلي
function calculateDomesticShipping(from, to, truckType, weight) {
    const route = `${from}-${to}`;
    const reverseRoute = `${to}-${from}`;
    const distance =
        SHEIKHA_LOGISTICS_SYSTEM.saudiDistances[route] ||
        SHEIKHA_LOGISTICS_SYSTEM.saudiDistances[reverseRoute];

    if (!distance) {
        return {
            error: 'مسار غير متوفر',
            availableRoutes: Object.keys(SHEIKHA_LOGISTICS_SYSTEM.saudiDistances)
        };
    }

    const truck =
        SHEIKHA_LOGISTICS_SYSTEM.domesticRates[truckType] ||
        SHEIKHA_LOGISTICS_SYSTEM.domesticRates['trailer'];

    let cost = distance * truck.ratePerKm + truck.fixedFee;
    cost = Math.max(cost, truck.minCharge);

    const pricePerTon = weight > 0 ? Math.round(cost / weight) : 0;

    return {
        from,
        to,
        distance,
        distanceUnit: 'كم',
        truckType: truck.nameAr,
        truckCapacity: truck.capacity,
        weight,
        weightUnit: 'طن',
        breakdown: {
            distanceCost: Math.round(distance * truck.ratePerKm),
            fixedFee: truck.fixedFee,
            minCharge: truck.minCharge
        },
        totalCost: Math.round(cost),
        pricePerTon,
        currency: 'SAR',
        estimatedDays: Math.ceil(distance / 500) // ~500 كم/يوم
    };
}

// حساب تكلفة الشحن الدولي
function calculateInternationalShipping(destination, containerType, incoterm) {
    const rates = SHEIKHA_LOGISTICS_SYSTEM.internationalSeaRates[destination];
    if (!rates) {
        return {
            error: 'وجهة غير متوفرة',
            availableDestinations: Object.keys(SHEIKHA_LOGISTICS_SYSTEM.internationalSeaRates)
        };
    }

    const container =
        SHEIKHA_LOGISTICS_SYSTEM.containerTypes[containerType] ||
        SHEIKHA_LOGISTICS_SYSTEM.containerTypes['20ft_standard'];

    const baseCost = rates.avg * container.multiplier;
    const incoData =
        SHEIKHA_LOGISTICS_SYSTEM.incoterms[incoterm] || SHEIKHA_LOGISTICS_SYSTEM.incoterms['FOB'];

    // تقدير التكاليف الإضافية حسب الـ Incoterm
    let additionalCosts = 0;
    if (incoterm === 'CIF' || incoterm === 'DDP') additionalCosts += baseCost * 0.03; // تأمين 3%
    if (incoterm === 'DDP') additionalCosts += baseCost * 0.1; // جمارك تقديرية 10%

    return {
        destination,
        containerType: container.nameAr,
        containerVolume: container.volume,
        containerMaxWeight: container.maxWeight,
        incoterm,
        incotermName: incoData.nameAr,
        sellerResponsibility: incoData.seller,
        buyerResponsibility: incoData.buyer,
        pricing: {
            min: Math.round(rates.min * container.multiplier),
            avg: Math.round(baseCost),
            max: Math.round(rates.max * container.multiplier),
            additionalCosts: Math.round(additionalCosts)
        },
        totalEstimate: Math.round(baseCost + additionalCosts),
        currency: 'USD',
        transitDays: rates.days,
        requiredDocuments: SHEIKHA_LOGISTICS_SYSTEM.requiredDocuments.international
    };
}

// API: حاسبة النقل الداخلي
app.get('/api/logistics/domestic/calculate', (req, res) => {
    const { from, to, truckType, weight } = req.query;

    if (!from || !to) {
        return res.status(400).json({
            success: false,
            error: 'يجب تحديد نقطة الانطلاق والوجهة',
            availableCities: [
                'الرياض',
                'جدة',
                'الدمام',
                'مكة',
                'المدينة',
                'تبوك',
                'أبها',
                'جازان',
                'نجران',
                'الجبيل',
                'الأحساء'
            ]
        });
    }

    const result = calculateDomesticShipping(
        from,
        to,
        truckType || 'trailer',
        parseFloat(weight) || 25
    );

    if (result.error) {
        return res.status(404).json({ success: false, ...result });
    }

    res.json({
        success: true,
        shipping: result,
        note: 'أسعار تقديرية — الأسعار الفعلية قد تختلف حسب ظروف السوق',
        timestamp: new Date().toISOString()
    });
});

