// سجل الجهات الحكومية (تحميل من ملف — التعريف الأصلي في السطر 1096)
try {
    const govFile = path.join(__dirname, 'data', 'gov-registry.json');
    if (fs.existsSync(govFile)) {
        GOV_REGISTRY = JSON.parse(fs.readFileSync(govFile, 'utf8'));
    }
} catch (_) {}

function saveGovRegistry() {
    try {
        const dir = path.join(__dirname, 'data');
        if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
        fs.writeFileSync(
            path.join(dir, 'gov-registry.json'),
            JSON.stringify(GOV_REGISTRY, null, 2),
            'utf8'
        );
    } catch (e) {
        console.error('خطأ في حفظ السجل الحكومي:', e.message);
    }
}

// (تم حذف المسارات المكررة: /api/government/register و /api/government/entities — الأصلية في السطور 1104 و 1164)

// GET /api/government/employees — قائمة الموظفين الحكوميين
app.get('/api/government/employees', (req, res) => {
    const { agency, role, status } = req.query;
    let employees = GOV_REGISTRY.employees || [];
    if (agency) employees = employees.filter(e => e.agency === agency);
    if (role) employees = employees.filter(e => e.role === role);
    if (status) employees = employees.filter(e => e.status === status);

    res.json({
        success: true,
        total: employees.length,
        employees: employees.map(e => ({
            id: e.id,
            refCode: e.refCode,
            name: e.name,
            agency: e.agency,
            title: e.title,
            role: e.role,
            purposes: e.purposes,
            status: e.status,
            createdAt: e.createdAt
        }))
    });
});

// GET /api/government/status/:refCode — حالة طلب التسجيل
app.get('/api/government/status/:refCode', (req, res) => {
    const ref = req.params.refCode;
    const entity = GOV_REGISTRY.entities.find(e => e.refCode === ref);
    const employee = GOV_REGISTRY.employees.find(e => e.refCode === ref);
    const record = entity || employee;

    if (!record) {
        return res.status(404).json({ success: false, message: 'الرقم المرجعي غير موجود' });
    }

    res.json({
        success: true,
        refCode: record.refCode,
        type: record.type,
        name: record.name,
        status: record.status,
        createdAt: record.createdAt,
        updatedAt: record.updatedAt
    });
});

// PUT /api/government/approve/:refCode — موافقة الأدمن على طلب (محمي)
app.put('/api/government/approve/:refCode', express.json(), (req, res) => {
    const ref = req.params.refCode;
    const { status } = req.body; // 'approved' | 'rejected' | 'pending_review'

    let found = false;
    for (const e of GOV_REGISTRY.entities) {
        if (e.refCode === ref) {
            e.status = status || 'approved';
            e.updatedAt = new Date().toISOString();
            found = true;
            break;
        }
    }
    if (!found) {
        for (const e of GOV_REGISTRY.employees) {
            if (e.refCode === ref) {
                e.status = status || 'approved';
                e.updatedAt = new Date().toISOString();
                found = true;
                break;
            }
        }
    }

    if (!found) return res.status(404).json({ success: false, message: 'الرقم المرجعي غير موجود' });

    saveGovRegistry();
    res.json({
        success: true,
        message: `تم تحديث حالة الطلب إلى: ${status || 'approved'}`,
        refCode: ref
    });
});

// GET /api/government/stats — إحصائيات التسجيل الحكومي
app.get('/api/government/stats', (req, res) => {
    const entities = GOV_REGISTRY.entities || [];
    const employees = GOV_REGISTRY.employees || [];
    res.json({
        success: true,
        stats: {
            totalEntities: entities.length,
            totalEmployees: employees.length,
            byType: {
                country: entities.filter(e => e.type === 'country').length,
                empire: entities.filter(e => e.type === 'empire').length,
                agency: entities.filter(e => e.type === 'agency').length
            },
            byStatus: {
                pending:
                    entities.filter(e => e.status === 'pending_review').length +
                    employees.filter(e => e.status === 'pending_review').length,
                approved:
                    entities.filter(e => e.status === 'approved').length +
                    employees.filter(e => e.status === 'approved').length,
                rejected:
                    entities.filter(e => e.status === 'rejected').length +
                    employees.filter(e => e.status === 'rejected').length
            }
        }
    });
});

// صلاحيات افتراضية حسب الدور
function getDefaultPermissions(role) {
    const perms = {
        'gov-admin': {
            projects: 'full',
            pricing: 'read',
            products: 'full',
            community: 'full',
            reports: 'full',
            regulation: 'full'
        },
        'gov-procurement': {
            projects: 'read',
            pricing: 'read',
            products: 'full',
            community: 'read',
            reports: 'read',
            regulation: 'none'
        },
        'gov-analyst': {
            projects: 'read',
            pricing: 'read',
            products: 'read',
            community: 'read',
            reports: 'full',
            regulation: 'read'
        },
        'gov-regulator': {
            projects: 'read',
            pricing: 'read',
            products: 'read',
            community: 'full',
            reports: 'full',
            regulation: 'full'
        },
        'gov-observer': {
            projects: 'read',
            pricing: 'read',
            products: 'read',
            community: 'read',
            reports: 'read',
            regulation: 'read'
        },
        'gov-diplomat': {
            projects: 'read',
            pricing: 'read',
            products: 'read',
            community: 'full',
            reports: 'read',
            regulation: 'none'
        }
    };
    return perms[role] || perms['gov-observer'];
}

function getDefaultEntityPermissions(type) {
    if (type === 'country')
        return {
            projects: 'full',
            pricing: 'full',
            products: 'full',
            community: 'full',
            reports: 'full',
            regulation: 'full'
        };
    if (type === 'empire')
        return {
            projects: 'full',
            pricing: 'read',
            products: 'full',
            community: 'full',
            reports: 'full',
            regulation: 'read'
        };
    return {
        projects: 'full',
        pricing: 'read',
        products: 'full',
        community: 'full',
        reports: 'read',
        regulation: 'none'
    };
}

