// الذكاء المخصص للشركة
app.post('/api/company/:id/ai/chat', express.json(), async (req, res) => {
    const id = req.params.id;
    const { message } = req.body;
    const company = COMPANIES_REGISTRY.registeredCompanies.find(c => c.companyId === id);

    if (!company) {
        return res.status(404).json({ success: false, message: 'الشركة غير موجودة' });
    }

    // بناء سياق مخصص للشركة
    const companyContext = `
أنتِ شيخة، المساعدة الذكية المخصصة لشركة "${company.nameAr}" (${company.nameEn || ''}).
اسمك: شيخة
أنتِ متخصصة في قطاع المعادن والسكراب في المملكة العربية السعودية.
- الشركة: ${company.nameAr}
- التخصص: ${company.category}
- المقر: ${company.headquarters?.city || 'السعودية'}
- الرؤية: ${company.vision || 'غير محددة'}
- الرسالة: ${company.mission || 'غير محددة'}
${company.aiModel?.customPrompt ? `\nتعليمات إضافية من الشركة: ${company.aiModel.customPrompt}` : ''}

أهم صفاتك:
- تتحدثين بلباقة واحترافية
- تقدمين معلومات دقيقة عن الشركة ومنتجاتها
- تساعدين في إعداد عروض الأسعار
- تلتزمين بالضوابط الشرعية في جميع المعاملات

ساعد المستخدم بما يتعلق بمنتجات الشركة وخدماتها. كن محترفاً ومفيداً.
`;

    try {
        const messages = [
            { role: 'system', content: companyContext },
            { role: 'user', content: message }
        ];

        const result = await callLLMChat(messages, 800, 0.6);

        res.json({
            success: true,
            reply: result.reply || 'مرحباً، كيف يمكنني مساعدتك؟',
            companyId: id,
            model: result.model || 'sheikha-ai'
        });
    } catch (e) {
        res.json({
            success: true,
            reply: `مرحباً بك في ${company.nameAr}. كيف يمكنني مساعدتك؟`,
            companyId: id
        });
    }
});

