// حساب السعر الإجمالي للباقة + الإضافات
app.post('/api/marketing/calculate-price', express.json(), (req, res) => {
    const { packageId, addons, quantity } = req.body;

    let total = 0;
    const breakdown = [];

    // سعر الباقة
    const pkg = MARKETING_SERVICES.packages?.[packageId];
    if (pkg && pkg.price) {
        total += pkg.price;
        breakdown.push({
            item: pkg.nameAr,
            price: pkg.price,
            type: 'package'
        });
    }

    // الإضافات
    if (addons && Array.isArray(addons)) {
        addons.forEach(addonId => {
            const addon = MARKETING_SERVICES.addons?.find(a => a.id === addonId);
            if (addon) {
                total += addon.price;
                breakdown.push({
                    item: addon.nameAr,
                    price: addon.price,
                    type: 'addon'
                });
            }
        });
    }

    res.json({
        success: true,
        total,
        currency: 'SAR',
        breakdown,
        billingCycle: pkg?.billingCycle || 'monthly'
    });
});

