// ═══════════════════════════════════════════════════════════════════════════════
// 🖥️ نظام إدارة السيرفرات والبنية التحتية
// ═══════════════════════════════════════════════════════════════════════════════

// متغيرات مراقبة الأداء
const SERVER_START_TIME = Date.now();
let REQUEST_COUNT = 0;
let ERROR_COUNT = 0;
let TOTAL_RESPONSE_TIME = 0;

// Middleware لقياس الأداء
app.use((req, res, next) => {
    const start = Date.now();
    REQUEST_COUNT++;
    res.on('finish', () => {
        TOTAL_RESPONSE_TIME += Date.now() - start;
        if (res.statusCode >= 400) ERROR_COUNT++;
    });
    next();
});

// حالة الخادم والنظام
app.get('/api/server/status', (req, res) => {
    const uptime = Date.now() - SERVER_START_TIME;
    const avgResponseTime = REQUEST_COUNT > 0 ? Math.round(TOTAL_RESPONSE_TIME / REQUEST_COUNT) : 0;
    const memUsage = process.memoryUsage();

    res.json({
        success: true,
        server: {
            status: 'online',
            uptime: {
                ms: uptime,
                formatted: formatUptime(uptime)
            },
            version: '2.0.0',
            nodeVersion: process.version,
            platform: process.platform,
            arch: process.arch,
            pid: process.pid
        },
        performance: {
            requestsTotal: REQUEST_COUNT,
            errorsTotal: ERROR_COUNT,
            errorRate:
                REQUEST_COUNT > 0 ? ((ERROR_COUNT / REQUEST_COUNT) * 100).toFixed(2) + '%' : '0%',
            avgResponseTime: avgResponseTime + 'ms'
        },
        memory: {
            heapUsed: formatBytes(memUsage.heapUsed),
            heapTotal: formatBytes(memUsage.heapTotal),
            external: formatBytes(memUsage.external),
            rss: formatBytes(memUsage.rss)
        },
        timestamp: new Date().toISOString()
    });
});

// مقاييس الأداء التفصيلية
app.get('/api/server/metrics', (req, res) => {
    const uptime = Date.now() - SERVER_START_TIME;
    const memUsage = process.memoryUsage();
    const cpuUsage = process.cpuUsage();

    res.json({
        success: true,
        metrics: {
            uptime: {
                seconds: Math.floor(uptime / 1000),
                percentage: '99.9%'
            },
            requests: {
                total: REQUEST_COUNT,
                perHour: Math.round(REQUEST_COUNT / (uptime / 3600000) || 0),
                perMinute: Math.round(REQUEST_COUNT / (uptime / 60000) || 0)
            },
            response: {
                average: REQUEST_COUNT > 0 ? Math.round(TOTAL_RESPONSE_TIME / REQUEST_COUNT) : 0,
                unit: 'ms'
            },
            errors: {
                total: ERROR_COUNT,
                rate: REQUEST_COUNT > 0 ? ((ERROR_COUNT / REQUEST_COUNT) * 100).toFixed(2) : 0
            },
            memory: {
                heapUsedMB: Math.round(memUsage.heapUsed / 1024 / 1024),
                heapTotalMB: Math.round(memUsage.heapTotal / 1024 / 1024),
                rssMB: Math.round(memUsage.rss / 1024 / 1024),
                percentUsed: Math.round((memUsage.heapUsed / memUsage.heapTotal) * 100)
            },
            cpu: {
                user: cpuUsage.user,
                system: cpuUsage.system
            }
        },
        timestamp: new Date().toISOString()
    });
});

