// سجلات النظام
const SYSTEM_LOGS = [];
function addSystemLog(level, service, message) {
    SYSTEM_LOGS.unshift({
        id: uuidv4(),
        timestamp: new Date().toISOString(),
        level,
        service,
        message
    });
    if (SYSTEM_LOGS.length > 100) SYSTEM_LOGS.pop();
}

// إضافة سجلات أولية
addSystemLog('info', 'Server', 'System initialized successfully');
addSystemLog('success', 'Database', 'JSON storage connected');
addSystemLog('success', 'WebSocket', 'Real-time server started');

app.get('/api/server/logs', (req, res) => {
    const limit = parseInt(req.query.limit) || 50;
    const level = req.query.level;

    let logs = [...SYSTEM_LOGS];
    if (level) {
        logs = logs.filter(l => l.level === level);
    }

    res.json({
        success: true,
        logs: logs.slice(0, limit),
        total: SYSTEM_LOGS.length,
        timestamp: new Date().toISOString()
    });
});

