// ─── حسابات القيمة والاهلاك ─────────────────────────────────────────────────────

/**
 * حساب قيمة السكراب مع الاهلاك
 */
function calculateScrapValue(item) {
    const now = new Date();
    const purchaseDate = new Date(item.purchaseDate || now);
    const monthsHeld = Math.floor((now - purchaseDate) / (30 * 24 * 60 * 60 * 1000));

    // السعر الأساسي
    let currentValue = item.purchasePrice || 0;

    // 1. الاهلاك الزمني (بالتلف)
    const timeDepreciation =
        currentValue * SMART_INVENTORY.depreciation.timeDepreciation * monthsHeld;

    // 2. الاهلاك الشكلي (إن وجد)
    const physicalDepreciation = item.hasPhysicalDamage
        ? currentValue * SMART_INVENTORY.depreciation.physicalDepreciation
        : 0;

    // 3. فقد المعالجة (قص، فرز، إلخ)
    const processingLoss = item.wasProcessed
        ? currentValue * SMART_INVENTORY.depreciation.processingLoss
        : 0;

    // 4. فرق الوزن الحقيقي
    const weightVariance =
        item.actualWeight && item.originalWeight
            ? (Math.abs(item.originalWeight - item.actualWeight) / item.originalWeight) *
              currentValue
            : 0;

    // القيمة الحالية بعد الاهلاك
    const depreciation = timeDepreciation + physicalDepreciation + processingLoss + weightVariance;
    const currentNetValue = Math.max(0, currentValue - depreciation);

    return {
        originalValue: item.purchasePrice,
        currentValue: Math.round(currentNetValue),
        totalDepreciation: Math.round(depreciation),
        depreciationBreakdown: {
            time: Math.round(timeDepreciation),
            physical: Math.round(physicalDepreciation),
            processing: Math.round(processingLoss),
            weightVariance: Math.round(weightVariance)
        },
        monthsHeld,
        depreciationRate:
            item.purchasePrice > 0 ? ((depreciation / item.purchasePrice) * 100).toFixed(1) : 0
    };
}

/**
 * توقع امتلاء المخزون
 */
function predictInventoryFill(userId, warehouseCapacity = 1000) {
    const userItems = SMART_INVENTORY.items.filter(i => i.userId === userId);
    if (userItems.length < 2) return null;

    // حساب معدل الإضافة اليومي
    const sortedItems = userItems.sort((a, b) => new Date(a.addedAt) - new Date(b.addedAt));
    const firstDate = new Date(sortedItems[0].addedAt);
    const lastDate = new Date(sortedItems[sortedItems.length - 1].addedAt);
    const daysDiff = Math.max(1, (lastDate - firstDate) / (24 * 60 * 60 * 1000));

    const totalWeight = userItems.reduce(
        (sum, i) => sum + (i.actualWeight || i.originalWeight || 0),
        0
    );
    const dailyRate = totalWeight / daysDiff;

    // توقع تاريخ الامتلاء
    const remainingCapacity = warehouseCapacity - totalWeight;
    const daysToFill =
        remainingCapacity > 0 && dailyRate > 0 ? Math.ceil(remainingCapacity / dailyRate) : null;

    const predictedFillDate = daysToFill
        ? new Date(Date.now() + daysToFill * 24 * 60 * 60 * 1000)
        : null;

    return {
        currentWeight: Math.round(totalWeight),
        capacity: warehouseCapacity,
        usagePercent: Math.round((totalWeight / warehouseCapacity) * 100),
        dailyRate: Math.round(dailyRate * 100) / 100,
        daysToFill,
        predictedFillDate: predictedFillDate?.toISOString().split('T')[0],
        recommendation:
            remainingCapacity < warehouseCapacity * 0.2
                ? 'يوصى بالبيع قريباً - المخزون يقترب من الامتلاء'
                : remainingCapacity < warehouseCapacity * 0.5
                  ? 'المخزون في مستوى جيد - راقب الأسعار للبيع الأمثل'
                  : 'مساحة كافية - يمكن الاستمرار في التجميع'
    };
}

/**
 * تحليل جدوى المخزون
 */
function analyzeInventoryFeasibility(items) {
    if (!items || items.length === 0) return null;

    let totalPurchaseValue = 0;
    let totalCurrentValue = 0;
    let totalWeight = 0;
    let totalDepreciation = 0;

    const byCategory = {};
    const byQuality = {};

    items.forEach(item => {
        const valuation = calculateScrapValue(item);
        totalPurchaseValue += item.purchasePrice || 0;
        totalCurrentValue += valuation.currentValue;
        totalWeight += item.actualWeight || item.originalWeight || 0;
        totalDepreciation += valuation.totalDepreciation;

        // تجميع حسب النوع
        const cat = item.category || 'other';
        if (!byCategory[cat]) byCategory[cat] = { count: 0, weight: 0, value: 0 };
        byCategory[cat].count++;
        byCategory[cat].weight += item.actualWeight || item.originalWeight || 0;
        byCategory[cat].value += valuation.currentValue;

        // تجميع حسب الجودة
        const qual = item.quality || 'unknown';
        if (!byQuality[qual]) byQuality[qual] = { count: 0, weight: 0, value: 0 };
        byQuality[qual].count++;
        byQuality[qual].weight += item.actualWeight || item.originalWeight || 0;
        byQuality[qual].value += valuation.currentValue;
    });

    return {
        summary: {
            totalItems: items.length,
            totalWeight: Math.round(totalWeight),
            totalPurchaseValue: Math.round(totalPurchaseValue),
            totalCurrentValue: Math.round(totalCurrentValue),
            totalDepreciation: Math.round(totalDepreciation),
            depreciationPercent:
                totalPurchaseValue > 0
                    ? ((totalDepreciation / totalPurchaseValue) * 100).toFixed(1)
                    : 0,
            averageValuePerTon:
                totalWeight > 0 ? Math.round((totalCurrentValue / totalWeight) * 1000) : 0
        },
        byCategory: Object.entries(byCategory).map(([k, v]) => ({
            category: k,
            ...v,
            weight: Math.round(v.weight),
            value: Math.round(v.value)
        })),
        byQuality: Object.entries(byQuality).map(([k, v]) => ({
            quality: k,
            ...v,
            weight: Math.round(v.weight),
            value: Math.round(v.value)
        })),
        recommendation:
            totalDepreciation > totalPurchaseValue * 0.15
                ? '⚠️ نسبة الاهلاك مرتفعة - يوصى بالبيع السريع'
                : totalDepreciation > totalPurchaseValue * 0.08
                  ? '📊 الاهلاك في المعدل الطبيعي - راقب السوق'
                  : '✅ المخزون في حالة ممتازة'
    };
}

/**
 * عرض المخزون آلياً مع الجدولة
 */
function autoScheduleInventory(items, marketPrices = {}) {
    if (!items || items.length === 0) return [];

    const scheduled = items.map(item => {
        const valuation = calculateScrapValue(item);
        const marketPrice = marketPrices[item.category] || item.estimatedMarketPrice || 0;
        const profitMargin =
            marketPrice > 0
                ? (((marketPrice - valuation.currentValue) / valuation.currentValue) * 100).toFixed(
                      1
                  )
                : 0;

        // تحديد الأولوية
        let priority = 'normal';
        let action = 'hold';

        if (valuation.depreciationRate > 15) {
            priority = 'urgent';
            action = 'sell_immediately';
        } else if (profitMargin > 20) {
            priority = 'high';
            action = 'sell_now';
        } else if (profitMargin > 10) {
            priority = 'medium';
            action = 'list_for_sale';
        } else if (profitMargin < 0) {
            priority = 'low';
            action = 'wait_for_better_price';
        }

        return {
            itemId: item.id,
            name: item.name,
            category: item.category,
            weight: item.actualWeight || item.originalWeight,
            currentValue: valuation.currentValue,
            marketPrice,
            profitMargin: parseFloat(profitMargin),
            depreciationRate: parseFloat(valuation.depreciationRate),
            priority,
            action,
            specifications: {
                quality: item.quality,
                purity: item.purity,
                hsCode: item.hsCode,
                isriCode: item.isriCode
            },
            recommendation: getItemRecommendation(action, profitMargin, valuation.depreciationRate)
        };
    });

    // ترتيب حسب الأولوية
    const priorityOrder = { urgent: 0, high: 1, medium: 2, normal: 3, low: 4 };
    return scheduled.sort((a, b) => priorityOrder[a.priority] - priorityOrder[b.priority]);
}

function getItemRecommendation(action, profitMargin, depreciationRate) {
    switch (action) {
        case 'sell_immediately':
            return `⚠️ بيع فوري - الاهلاك ${depreciationRate}% مرتفع`;
        case 'sell_now':
            return `🟢 فرصة بيع ممتازة - هامش ربح ${profitMargin}%`;
        case 'list_for_sale':
            return `📋 أضف للسوق - هامش ربح جيد ${profitMargin}%`;
        case 'wait_for_better_price':
            return `⏳ انتظر سعر أفضل - الهامش حالياً ${profitMargin}%`;
        default:
            return '📊 راقب السوق';
    }
}

