// API للبحث الشامل (منتدى + أبحاث + سوق)
app.get('/api/search/all', (req, res) => {
    const { q, limit = 30 } = req.query;
    if (!q) return res.json({ success: true, results: { forum: [], research: [], market: [] } });

    const query = q.toLowerCase();

    // البحث في المنتدى
    const forumResults = FORUM_DATA.topics
        .filter(
            t => t.title.toLowerCase().includes(query) || t.content.toLowerCase().includes(query)
        )
        .slice(0, 10)
        .map(t => ({ ...t, source: 'forum' }));

    // البحث في الأبحاث
    const researchResults = RESEARCH_DATA.papers
        .filter(
            p => p.title.toLowerCase().includes(query) || p.abstract.toLowerCase().includes(query)
        )
        .slice(0, 10)
        .map(p => ({ ...p, source: 'research' }));

    // البحث في السوق
    const marketResults = LISTINGS.filter(
        l => l.name?.toLowerCase().includes(query) || l.category?.toLowerCase().includes(query)
    )
        .slice(0, 10)
        .map(l => ({ ...l, source: 'market' }));

    // تسجيل البحث للذكاء
    collectIntelligence('search_query', {
        query: q,
        resultsCount: forumResults.length + researchResults.length + marketResults.length
    });

    res.json({
        success: true,
        results: {
            forum: forumResults,
            research: researchResults,
            market: marketResults
        },
        total: forumResults.length + researchResults.length + marketResults.length,
        timestamp: new Date().toISOString()
    });
});

// دوال مساعدة
function formatUptime(ms) {
    const seconds = Math.floor(ms / 1000);
    const minutes = Math.floor(seconds / 60);
    const hours = Math.floor(minutes / 60);
    const days = Math.floor(hours / 24);

    if (days > 0) return `${days}d ${hours % 24}h ${minutes % 60}m`;
    if (hours > 0) return `${hours}h ${minutes % 60}m ${seconds % 60}s`;
    if (minutes > 0) return `${minutes}m ${seconds % 60}s`;
    return `${seconds}s`;
}

function formatBytes(bytes) {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    if (bytes < 1024 * 1024 * 1024) return (bytes / 1024 / 1024).toFixed(1) + ' MB';
    return (bytes / 1024 / 1024 / 1024).toFixed(1) + ' GB';
}

