// نظام الرد الآلي
const AUTO_REPLIES = {
    keywords: {
        سعر: 'يمكنك الاطلاع على الأسعار الحية في: https://sheikha.top/السوق.html',
        price: 'Check live prices at: https://sheikha.top/السوق.html',
        طلب: 'لمتابعة طلبك، يرجى تسجيل الدخول: https://sheikha.top/تسجيل-الدخول.html',
        order: 'Track your order at: https://sheikha.top/تسجيل-الدخول.html',
        شحن: 'لتتبع شحنتك: https://sheikha.top/التتبع.html',
        shipping: 'Track shipment: https://sheikha.top/التتبع.html',
        تسجيل: 'للتسجيل في السوق: https://sheikha.top/التسجيل.html',
        register: 'Register at: https://sheikha.top/التسجيل.html',
        مساعدة: 'فريق الدعم متاح على: market@sheikha.top',
        help: 'Support available at: market@sheikha.top'
    },
    defaultReply: {
        ar: 'شكراً لتواصلك مع سوق شيخة. سيتم الرد عليك قريباً. للاستفسارات العاجلة: market@sheikha.top',
        en: 'Thank you for contacting Sheikha Market. We will respond shortly. For urgent inquiries: market@sheikha.top'
    }
};

function getAutoReply(message) {
    const lowerMessage = message.toLowerCase();
    for (const [keyword, reply] of Object.entries(AUTO_REPLIES.keywords)) {
        if (lowerMessage.includes(keyword)) {
            return reply;
        }
    }
    return AUTO_REPLIES.defaultReply.ar;
}

