// Broadcast notification helper
function broadcastNotification(notification) {
    const data = JSON.stringify({
        type: 'notification',
        notification,
        timestamp: new Date().toISOString()
    });
    clients.forEach(client => {
        if (client.readyState === WebSocket.OPEN) {
            client.send(data);
        }
    });
}

