// جلب جميع الشركات المجهزة مسبقاً
app.get('/api/market/preloaded', (req, res) => {
    const sector = req.query.sector;
    let companies = SAUDI_MARKET_DATA.preloadedCompanies || [];

    if (sector && sector !== 'all') {
        companies = companies.filter(c => c.sector === sector);
    }

    res.json({
        success: true,
        total: companies.length,
        sectors: SAUDI_MARKET_DATA.sectors,
        companies: companies,
        timestamp: new Date().toISOString()
    });
});

// جلب شركة مجهزة بالمعرف
app.get('/api/market/preloaded/:id', (req, res) => {
    const id = req.params.id;
    const company = (SAUDI_MARKET_DATA.preloadedCompanies || []).find(c => c.companyId === id);

    if (!company) {
        return res.status(404).json({ success: false, message: 'الشركة غير موجودة' });
    }

    res.json({
        success: true,
        company: company,
        supplyChainStage: findCompanyInSupplyChain(id),
        suggestedBlocks: suggestBlocksForCompany(company),
        timestamp: new Date().toISOString()
    });
});

// البحث في الشركات المجهزة
app.get('/api/market/search', (req, res) => {
    const query = (req.query.q || '').toLowerCase();
    const sector = req.query.sector;

    let companies = SAUDI_MARKET_DATA.preloadedCompanies || [];

    if (query) {
        companies = companies.filter(
            c =>
                c.nameAr.toLowerCase().includes(query) ||
                (c.nameEn && c.nameEn.toLowerCase().includes(query)) ||
                (c.products || []).some(p => p.name.toLowerCase().includes(query))
        );
    }

    if (sector && sector !== 'all') {
        companies = companies.filter(c => c.sector === sector);
    }

    res.json({
        success: true,
        query: query,
        total: companies.length,
        companies: companies,
        timestamp: new Date().toISOString()
    });
});

// التسجيل السريع بالبيانات المجهزة
app.post('/api/companies/quick-register', express.json(), async (req, res) => {
    try {
        const data = req.body;

        // إنشاء سجل الشركة من البيانات المجهزة
        const company = {
            companyId: data.companyId,
            nameAr: data.nameAr,
            nameEn: data.nameEn || '',
            category: data.sector,
            logo: data.logo,
            headquarters: data.headquarters,
            contacts: data.contacts || {},
            profile: data.profile || {},
            products: data.products || [],
            user: data.user,
            selectedSolutions: data.selectedSolutions || [],
            package: data.package || 'business',
            registeredAt: data.registeredAt || new Date().toISOString(),
            apiKey: data.apiKey || 'shk_' + crypto.randomBytes(16).toString('hex'),
            status: 'active',
            preloaded: true,
            gaps: data.gaps || [],
            opportunities: data.opportunities || []
        };

        // إضافة للسجل
        if (!COMPANIES_REGISTRY.registeredCompanies) {
            COMPANIES_REGISTRY.registeredCompanies = [];
        }

        // التحقق من عدم التكرار
        const existingIndex = COMPANIES_REGISTRY.registeredCompanies.findIndex(
            c => c.companyId === company.companyId
        );
        if (existingIndex >= 0) {
            COMPANIES_REGISTRY.registeredCompanies[existingIndex] = company;
        } else {
            COMPANIES_REGISTRY.registeredCompanies.push(company);
        }

        // حفظ في الملف
        try {
            const registryPath = path.join(__dirname, 'data', 'companies-registry.json');
            fs.writeFileSync(registryPath, JSON.stringify(COMPANIES_REGISTRY, null, 2), 'utf8');
        } catch (e) {
            console.log('[Error] Could not save registry:', e.message);
        }

        addSystemLog('success', 'QuickRegister', `Quick registered: ${company.nameAr}`);

        res.json({
            success: true,
            message: 'تم التسجيل السريع بنجاح!',
            company: {
                companyId: company.companyId,
                nameAr: company.nameAr,
                apiKey: company.apiKey,
                productsCount: company.products.length,
                solutionsCount: company.selectedSolutions.length
            },
            timestamp: new Date().toISOString()
        });
    } catch (e) {
        addSystemLog('error', 'QuickRegister', e.message);
        res.status(500).json({ success: false, message: 'خطأ في التسجيل: ' + e.message });
    }
});

