// ═══ API: إنشاء عقد جديد ═══
app.post('/api/contracts', express.json(), authRequired, (req, res) => {
    const user = req.user;
    const perms = ROLE_PERMISSIONS[user.role] || ROLE_PERMISSIONS.visitor;
    if (!perms.canBuy && !perms.canSell)
        return res.status(403).json({ success: false, message: 'غير مصرح بإنشاء عقود' });

    const {
        type,
        title,
        description,
        counterpartyId,
        counterpartyName,
        metalType,
        quantity,
        unit,
        price,
        currency,
        deliveryDate,
        supplyChainStage,
        isGreen,
        greenMetrics,
        terms
    } = req.body || {};
    if (!type || !title)
        return res.status(400).json({ success: false, message: 'يرجى تحديد نوع العقد والعنوان' });

    const contractType = CONTRACT_TYPES[type];
    if (!contractType) return res.status(400).json({ success: false, message: 'نوع عقد غير صالح' });

    const contract = {
        id:
            'CTR-' +
            Date.now().toString(36).toUpperCase() +
            '-' +
            crypto.randomBytes(3).toString('hex').toUpperCase(),
        type,
        typeName: contractType.nameAr,
        category: contractType.category,
        title,
        description: description || '',
        creatorId: user.id,
        creatorName: user.name || user.storeName || 'مستخدم',
        creatorRole: user.role,
        counterpartyId: counterpartyId || null,
        counterpartyName: counterpartyName || null,
        metalType: metalType || null,
        quantity: quantity || null,
        unit: unit || 'طن',
        price: price || null,
        currency: currency || 'SAR',
        deliveryDate: deliveryDate || null,
        supplyChainStage: supplyChainStage || null,
        stage: 'draft',
        stageHistory: [{ stage: 'draft', at: new Date().toISOString(), by: user.id }],
        isGreen: !!isGreen,
        greenMetrics: isGreen
            ? greenMetrics || { recyclingRate: 0, co2Saved: 0, energySaved: 0, greenScore: 0 }
            : null,
        terms: terms || [],
        shariaCompliance: {
            noRiba: true,
            noGharar: true,
            noIhtikar: true,
            ruling: 'يَا أَيُّهَا الَّذِينَ آمَنُوا أَوْفُوا بِالْعُقُودِ — المائدة 1'
        },
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString()
    };

    CONTRACTS.push(contract);
    try {
        fs.writeFileSync(CONTRACTS_FILE, JSON.stringify(CONTRACTS, null, 2));
    } catch (_) {}

    res.json({ success: true, contract, message: 'تم إنشاء العقد بنجاح' });
});

// ═══ API: قائمة العقود (حسب الدور) ═══
app.get('/api/contracts', authRequired, (req, res) => {
    const user = req.user;
    const perms = ROLE_PERMISSIONS[user.role] || ROLE_PERMISSIONS.visitor;
    const { type, stage, category, isGreen } = req.query;

    let result = perms.canManageAll
        ? CONTRACTS
        : CONTRACTS.filter(c => c.creatorId === user.id || c.counterpartyId === user.id);

    if (type) result = result.filter(c => c.type === type);
    if (stage) result = result.filter(c => c.stage === stage);
    if (category) result = result.filter(c => c.category === category);
    if (isGreen === 'true') result = result.filter(c => c.isGreen);

    res.json({
        success: true,
        contracts: result.slice(-100),
        total: result.length,
        permissions: perms
    });
});

// ═══ API: تفاصيل عقد ═══
app.get('/api/contracts/:id', authRequired, (req, res) => {
    const contract = CONTRACTS.find(c => c.id === req.params.id);
    if (!contract) return res.status(404).json({ success: false, message: 'العقد غير موجود' });
    res.json({ success: true, contract });
});

// ═══ API: تحديث مرحلة العقد ═══
app.patch('/api/contracts/:id/stage', express.json(), authRequired, (req, res) => {
    const contract = CONTRACTS.find(c => c.id === req.params.id);
    if (!contract) return res.status(404).json({ success: false, message: 'العقد غير موجود' });

    const user = req.user;
    const { stage } = req.body;
    const validStage = CONTRACT_STAGES.find(s => s.id === stage);
    if (!validStage) return res.status(400).json({ success: false, message: 'مرحلة غير صالحة' });

    contract.stage = stage;
    contract.stageHistory.push({ stage, at: new Date().toISOString(), by: user.id });
    contract.updatedAt = new Date().toISOString();

    try {
        fs.writeFileSync(CONTRACTS_FILE, JSON.stringify(CONTRACTS, null, 2));
    } catch (_) {}
    res.json({ success: true, contract, message: `تم تحديث المرحلة إلى: ${validStage.nameAr}` });
});

// ═══ API: إنشاء طلب (شراء/بيع) ═══
app.post('/api/orders', express.json(), authRequired, (req, res) => {
    const user = req.user;
    const perms = ROLE_PERMISSIONS[user.role] || ROLE_PERMISSIONS.visitor;

    const {
        type,
        metalType,
        quantity,
        unit,
        price,
        currency,
        description,
        supplyChainStage,
        contractId,
        deliveryAddress,
        isGreen
    } = req.body || {};
    if (!type || !['buy', 'sell'].includes(type))
        return res.status(400).json({ success: false, message: 'حدد نوع الطلب: buy أو sell' });
    if (type === 'buy' && !perms.canBuy)
        return res.status(403).json({ success: false, message: 'غير مصرح بالشراء' });
    if (type === 'sell' && !perms.canSell)
        return res.status(403).json({ success: false, message: 'غير مصرح بالبيع' });

    const order = {
        id:
            'ORD-' +
            Date.now().toString(36).toUpperCase() +
            '-' +
            crypto.randomBytes(3).toString('hex').toUpperCase(),
        type,
        typeLabel: type === 'buy' ? 'طلب شراء' : 'طلب بيع',
        userId: user.id,
        userName: user.name || user.storeName || 'مستخدم',
        userRole: user.role,
        metalType: metalType || null,
        quantity: quantity || null,
        unit: unit || 'طن',
        price: price || null,
        currency: currency || 'SAR',
        description: description || '',
        supplyChainStage: supplyChainStage || null,
        contractId: contractId || null,
        deliveryAddress: deliveryAddress || null,
        status: 'open',
        isGreen: !!isGreen,
        greenScore: isGreen ? Math.floor(Math.random() * 30 + 70) : 0,
        createdAt: new Date().toISOString()
    };

    ORDERS.push(order);
    try {
        fs.writeFileSync(ORDERS_FILE, JSON.stringify(ORDERS, null, 2));
    } catch (_) {}
    res.json({ success: true, order, message: `تم إنشاء ${order.typeLabel} بنجاح` });
});

// ═══ API: قائمة الطلبات ═══
app.get('/api/orders', authRequired, (req, res) => {
    const user = req.user;
    const perms = ROLE_PERMISSIONS[user.role] || ROLE_PERMISSIONS.visitor;
    const { type, status } = req.query;

    let result = perms.canManageAll ? ORDERS : ORDERS.filter(o => o.userId === user.id);
    if (type) result = result.filter(o => o.type === type);
    if (status) result = result.filter(o => o.status === status);

    res.json({
        success: true,
        orders: result.slice(-100),
        total: result.length,
        permissions: perms
    });
});

// ═══ API: مرحلة المستخدم في سلسلة التوريد ═══
app.get('/api/my-supply-chain-stage', authRequired, (req, res) => {
    const user = req.user;
    const specialty = user.specialty || user.traderType || null;

    // تحديد المرحلة من تخصص التاجر
    const stageMap = {
        source: 'source',
        mine: 'source',
        factory: 'source',
        collector: 'collection',
        gatherer: 'collection',
        transporter: 'transport',
        trucks_equipment: 'transport',
        smelter: 'smelter',
        refinery: 'smelter',
        manufacturing: 'manufacturing',
        producer: 'manufacturing',
        metals_trader: 'end',
        buyer: 'end',
        retailer: 'end'
    };

    const stageId = stageMap[specialty] || 'end';
    const stage = SUPPLY_CHAIN_STAGES.find(s => s.id === stageId) || SUPPLY_CHAIN_STAGES[5];

    // إحصائيات المستخدم
    const myContracts = CONTRACTS.filter(
        c => c.creatorId === user.id || c.counterpartyId === user.id
    );
    const myOrders = ORDERS.filter(o => o.userId === user.id);
    const myProducts = LISTINGS.filter(l => l.traderId === user.id);

    res.json({
        success: true,
        user: { id: user.id, name: user.name || user.storeName, role: user.role, specialty },
        supplyChainStage: stage,
        allStages: SUPPLY_CHAIN_STAGES,
        stats: {
            activeContracts: myContracts.filter(c => c.stage === 'active').length,
            totalContracts: myContracts.length,
            openBuyOrders: myOrders.filter(o => o.type === 'buy' && o.status === 'open').length,
            openSellOrders: myOrders.filter(o => o.type === 'sell' && o.status === 'open').length,
            listedProducts: myProducts.length,
            greenContracts: myContracts.filter(c => c.isGreen).length
        },
        permissions: ROLE_PERMISSIONS[user.role] || ROLE_PERMISSIONS.visitor,
        circularEconomy: {
            greenScore: myContracts.filter(c => c.isGreen).length > 0 ? 75 : 0,
            recyclingParticipation: myProducts.some(p => p.scrapType) ? true : false,
            supplyChainComplete: stage.order >= 4
        }
    });
});

// ═══ API: إحصائيات الاقتصاد الدائري ═══
app.get('/api/circular-economy/stats', (req, res) => {
    const greenContracts = CONTRACTS.filter(c => c.isGreen);
    const recyclingContracts = CONTRACTS.filter(c => c.type === 'recycling');
    const totalContracts = CONTRACTS.length;

    res.json({
        success: true,
        circularEconomy: {
            greenContracts: greenContracts.length,
            recyclingContracts: recyclingContracts.length,
            totalContracts,
            greenPercentage:
                totalContracts > 0 ? Math.round((greenContracts.length / totalContracts) * 100) : 0,
            metrics: {
                totalCO2Saved: greenContracts.reduce(
                    (s, c) => s + (c.greenMetrics?.co2Saved || 0),
                    0
                ),
                avgGreenScore:
                    greenContracts.length > 0
                        ? Math.round(
                              greenContracts.reduce(
                                  (s, c) => s + (c.greenMetrics?.greenScore || 0),
                                  0
                              ) / greenContracts.length
                          )
                        : 0,
                totalRecycled: recyclingContracts.reduce(
                    (s, c) => s + (parseFloat(c.quantity) || 0),
                    0
                )
            },
            principles: [
                'تصميم للتدوير',
                'إطالة العمر',
                'استرداد المواد',
                'تجديد الأنظمة',
                'تكافل صناعي'
            ],
            islamicBasis: '"وَلَا تُفْسِدُوا فِي الْأَرْضِ بَعْدَ إِصْلَاحِهَا" — الأعراف 56'
        }
    });
});

