// ⭐ حساب المؤشر الأخضر
app.post('/api/green/score', (req, res) => {
    if (!greenCircularEngine) return res.status(503).json({ error: 'المنظومة غير مفعلة' });
    const data = req.body || {};
    const score = greenCircularEngine.calculateGreenScore(data);
    const levels =
        greenCircularEngine.greenSystem.pillars.find(p => p.id === 'green-scoring')?.levels || [];
    let level = levels[levels.length - 1];
    for (const l of levels) {
        const [min] = l.score.split('-').map(Number);
        if (score >= min) {
            level = l;
            break;
        }
    }
    res.json({
        success: true,
        النتيجة: score,
        المستوى: level.label,
        الشارة: level.badge,
        الوصف: level.desc,
        البيانات_المدخلة: data,
        الأساس_الشرعي: 'وَلَا تُفْسِدُوا فِي الْأَرْضِ بَعْدَ إِصْلَاحِهَا — الأعراف 56'
    });
});

// 🏭 حساب البصمة الكربونية
app.post('/api/green/carbon-footprint', (req, res) => {
    if (!greenCircularEngine) return res.status(503).json({ error: 'المنظومة غير مفعلة' });
    const { metalType, quantity, isRecycled } = req.body || {};
    if (!metalType || !quantity)
        return res.status(400).json({ error: 'يرجى تحديد نوع المعدن والكمية' });
    const result = greenCircularEngine.calculateCarbonFootprint(metalType, quantity, isRecycled);
    if (!result) return res.status(404).json({ error: 'نوع المعدن غير موجود' });
    res.json({
        success: true,
        البصمة_الكربونية: result,
        التوصية: isRecycled
            ? '✅ استخدام المعدن المعاد تدويره — "وَلَا تُسْرِفُوا" — تقليل الانبعاثات'
            : '⚠️ يُنصح باستخدام معدن معاد تدويره لتقليل الانبعاثات',
        الأساس_الشرعي:
            'ظَهَرَ الْفَسَادُ فِي الْبَرِّ وَالْبَحْرِ بِمَا كَسَبَتْ أَيْدِي النَّاسِ — الروم 41'
    });
});

