const ownerAuth = (req, res, next) => {
    const key = req.headers['x-owner-key'] || req.query.ownerKey;
    if (key !== '1031605270-OWNER-PRIVATE') {
        return res
            .status(403)
            .json({
                error: '⛔ محظور — هذا القسم خاص بالمالك فقط',
                verse: '"إِنَّ اللَّهَ يَأْمُرُكُمْ أَن تُؤَدُّوا الْأَمَانَاتِ إِلَىٰ أَهْلِهَا"'
            });
    }
    next();
};

