app.get('/api/survey/dashboard', (req, res) => {
    if (!surveyEngine)
        return res.status(503).json({ success: false, message: 'محرك الاستبيانات غير متوفر' });
    res.json({ success: true, ...surveyEngine.getDashboard() });
});
app.get('/api/survey/templates', (req, res) => {
    if (!surveyEngine) return res.status(503).json({ success: false });
    res.json({ success: true, ...surveyEngine.getSurveyTemplates() });
});
app.get('/api/survey/system', (req, res) => {
    if (!surveyEngine) return res.status(503).json({ success: false });
    res.json({ success: true, ...surveyEngine.getFullSystem() });
});
app.post('/api/survey/create', express.json(), (req, res) => {
    if (!surveyEngine) return res.status(503).json({ success: false });
    const { templateKey, audience, meta } = req.body;
    res.json(surveyEngine.createSurvey(templateKey, audience, meta));
});
app.post('/api/survey/respond', express.json(), (req, res) => {
    if (!surveyEngine) return res.status(503).json({ success: false });
    const { surveySerial, answers, respondent } = req.body;
    res.json(surveyEngine.submitResponse(surveySerial, answers, respondent));
});
app.post('/api/survey/observation', express.json(), (req, res) => {
    if (!surveyEngine) return res.status(503).json({ success: false });
    const obs = surveyEngine.submitObservation(req.body);
    res.json({ success: true, observation: obs });
});
app.get('/api/survey/observations', (req, res) => {
    if (!surveyEngine) return res.status(503).json({ success: false });
    res.json({ success: true, observations: surveyEngine.getObservations(req.query) });
});
app.post('/api/survey/rca', express.json(), (req, res) => {
    if (!surveyEngine) return res.status(503).json({ success: false });
    res.json(surveyEngine.performRCA(req.body.serial, req.body.whys));
});
app.post('/api/survey/report', express.json(), (req, res) => {
    if (!surveyEngine) return res.status(503).json({ success: false });
    res.json(surveyEngine.generateReport(req.body.type));
});
console.log(
    '   📋 Survey APIs: /api/survey/dashboard, /templates, /system, /create, /respond, /observation, /observations, /rca, /report'
);

