function sheikhaResolveLanguageCategory(language) {
    const lang = (language || '').toLowerCase();
    const map = {
        javascript: 'web',
        javascriptreact: 'web',
        typescript: 'web',
        typescriptreact: 'web',
        html: 'web',
        css: 'web',
        scss: 'web',
        sass: 'web',
        less: 'web',
        vue: 'web',
        svelte: 'web',
        astro: 'web',
        python: 'general-purpose',
        java: 'general-purpose',
        c: 'systems',
        cpp: 'systems',
        rust: 'systems',
        go: 'systems',
        csharp: 'general-purpose',
        php: 'web',
        ruby: 'web',
        swift: 'mobile',
        kotlin: 'mobile',
        sql: 'data',
        mysql: 'data',
        postgres: 'data',
        plsql: 'data',
        kusto: 'data',
        bash: 'shell',
        shellscript: 'shell',
        powershell: 'shell',
        batch: 'shell',
        zsh: 'shell',
        fish: 'shell',
        json: 'config',
        jsonc: 'config',
        yaml: 'config',
        xml: 'config',
        toml: 'config',
        ini: 'config',
        dockerfile: 'devops',
        makefile: 'devops',
        cmake: 'devops',
        terraform: 'devops',
        bicep: 'devops',
        hcl: 'devops'
    };
    return map[lang] || 'specialized';
}

function sheikhaBuildLanguageCatalog(languages) {
    return (languages || []).map((language, index) => ({
        id: index + 1,
        language,
        category: sheikhaResolveLanguageCategory(language),
        governance: {
            basis: SHEIKHA_LANGUAGE_GOVERNANCE.basis,
            principle: SHEIKHA_LANGUAGE_GOVERNANCE.principle
        }
    }));
}

