// 🧠 SHEIKHA LOCAL MIND APIs — العقل المحلي المستقل
// ═══════════════════════════════════════════════════════════════════════════════

// API — العقل المحلي
app.post('/api/mind/chat', (req, res) => {
    if (!sheikhaLocalMind)
        return res.status(503).json({ success: false, message: 'العقل المحلي غير متوفر' });
    const { message, conversationId } = req.body;
    if (!message) return res.status(400).json({ success: false, message: 'يرجى إدخال رسالة' });
    const result = sheikhaLocalMind.process(message, conversationId || `conv-${Date.now()}`);
    res.json(result);
});

app.get('/api/mind/dashboard', (req, res) => {
    if (!sheikhaLocalMind)
        return res.status(503).json({ success: false, message: 'العقل المحلي غير متوفر' });
    res.json({ success: true, dashboard: sheikhaLocalMind.getDashboard() });
});

app.get('/api/mind/search', (req, res) => {
    if (!sheikhaLocalMind)
        return res.status(503).json({ success: false, message: 'العقل المحلي غير متوفر' });
    const query = req.query.q || '';
    if (!query)
        return res.status(400).json({ success: false, message: 'يرجى إدخال كلمة بحث ?q=...' });
    const results = sheikhaLocalMind.semanticSearch(query, parseInt(req.query.limit) || 10);
    res.json({ success: true, query, results });
});

app.get('/api/mind/lexicon', (req, res) => {
    if (!sheikhaLocalMind)
        return res.status(503).json({ success: false, message: 'العقل المحلي غير متوفر' });
    const word = req.query.word || '';
    if (!word) return res.json({ success: true, stats: sheikhaLocalMind.lexicon.getStats() });
    const result = sheikhaLocalMind.lexicon.lookup(word);
    res.json({ success: true, word, result });
});

app.get('/api/mind/lexicon/search', (req, res) => {
    if (!sheikhaLocalMind)
        return res.status(503).json({ success: false, message: 'العقل المحلي غير متوفر' });
    const q = req.query.q || '';
    const results = sheikhaLocalMind.lexicon.search(q, parseInt(req.query.limit) || 10);
    res.json({ success: true, query: q, count: results.length, results });
});

