// ═══════════════════════════════════════════════════════════════════════════════
// 🚀 بدء الخادم
// ═══════════════════════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════════════════════
// 🚀 بدء الخادم — الشبكة العصبية تكتشف المنفذ الحر تلقائياً
// ═══════════════════════════════════════════════════════════════════════════════

async function _startServer() {
    // ① اكتشاف المنفذ الفعلي عبر الشبكة العصبية (إذا كانت متاحة)
    let actualPort = PORT;
    if (_portEngine) {
        try {
            await _portEngine.ignite();
            actualPort = _portEngine.mainPort || PORT;
        } catch (e) {
            console.log('⚠️  الشبكة العصبية: استخدام المنفذ الافتراضي بسبب:', e.message);
        }
    }

    // ② تشغيل الخادم على المنفذ الفعلي
    const server = app.listen(actualPort, HOST, () => {
        PORT = actualPort;   // تحديث المتغير العالمي بالمنفذ الفعلي
        addSystemLog('success', 'Server', `Server started on port ${actualPort}`);

        // ═══ تفعيل محرك الأتمتة v2.0 — تسجيل APIs + بدء الجدولة ═══
        if (automationEngine) {
            try {
                automationEngine.registerRoutes(app);
                automationEngine.startScheduler();
                console.log(
                    `⚙️ Automation Engine v2.0 — الجدولة فعّالة | ${automationEngine.kpis.cronJobsActive} مهمة مجدولة | n8n bridge: مُفعَّل`
                );
            } catch (e) {
                console.log('⚠️ خطأ في تفعيل الأتمتة:', e.message);
            }
        }

        // ═══ تسجيل مسارات منظومة التطوير ═══
        if (devPlatformEngine) {
            try {
                devPlatformEngine.registerRoutes(app);
                console.log(
                    `🛠️ Dev Platform v1.0 — SDK: ${devPlatformEngine.sdk.modules.length} وحدة | MCP: ${devPlatformEngine.mcp.tools.length} أداة | IDE: ${devPlatformEngine.ide.supportedIDEs.length} بيئة`
                );
            } catch (e) {
                console.log('⚠️ خطأ في تفعيل منظومة التطوير:', e.message);
            }
        }

        const relocated = actualPort !== _PORT_ENV ? `🔄 انتقل من ${_PORT_ENV} إلى ${actualPort}` : '✅ المنفذ المفضّل';
        console.log(`
╔═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗
║                           🏪 سوق شيخة للمعادن والسكراب - البوابة الرئيسية                                          ║
║                           Sheikha Metals & Scrap Market - Main Portal                                              ║
╠═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════╣
║   🌐 http://${HOST}:${actualPort}  ${relocated}                                                                     ║
║   🧠 الشبكة العصبية: لا اعتماد على منفذ واحد                                                                       ║
║   ⚙️  محرك الأتمتة v2.0 — أقوى من n8n — مُفعَّل                                                                    ║
║   🔗 جسر n8n: /api/automation/n8n/webhook                                                                         ║
║   شريكك الموثوق في عالم المعادن والسكراب                                                                           ║
╚═══════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝
`);
    });

    // ═══ معالج أخطاء الخادم ═══
    server.on('error', (err) => {
        if (err.code === 'EADDRINUSE') {
            console.error(`
╔══════════════════════════════════════════════════════════════╗
║  ⛔ المنفذ ${actualPort} مشغول                                   ║
║  🧠 الشبكة العصبية ستنتقل تلقائياً للمرة القادمة             ║
╠══════════════════════════════════════════════════════════════╣
║  الحل السريع:   fuser -k ${actualPort}/tcp                        ║
║  أو pm2:        pm2 restart sheikha                          ║
╚══════════════════════════════════════════════════════════════╝`);
        } else {
            console.error('🔴 خطأ في الخادم:', err.message);
        }
        process.exit(1);
    });

    return server;
}

const _serverPromise = _startServer();

// ── استخراج كائن server لباقي الكود ─────────────────────────────────────────
let server;
_serverPromise.then((s) => {
    server = s;

    // WebSocket
    const wss = new WebSocket.Server({ server });
    let clients = [];

    wss.on('connection', ws => {
        clients.push(ws);
        ws.send(JSON.stringify({ type: 'connected', prices: LIVE_PRICES }));
        ws.on('close', () => {
            clients = clients.filter(c => c !== ws);
        });
    });

    // Wire WS clients into social connect engine after clients array is ready
    if (socialConnectEngine) { socialConnectEngine.wsClients = { forEach: (fn) => clients.forEach(fn) }; }
    // Wire WS clients into currency engine
    if (currencyEngine) { currencyEngine.wsClients = { forEach: (fn) => clients.forEach(fn) }; }
    // Wire WS clients into grand empire engine
    if (empireGrandEngine) { empireGrandEngine.wsClients = { forEach: (fn) => clients.forEach(fn) }; }
    // Wire WS clients into meta engine
    if (metaEngine) { metaEngine.wsClients = { forEach: (fn) => clients.forEach(fn) }; }

    function broadcastPrices() {
        const data = JSON.stringify({
            type: 'priceUpdate',
            prices: LIVE_PRICES,
            timestamp: new Date().toISOString()
        });
        clients.forEach(client => {
            if (client.readyState === WebSocket.OPEN) client.send(data);
        });
    }

}).catch((err) => console.error('❌ فشل بدء الخادم:', err.message));
